  function normalizeModalItems(items) {
    return (items || [])
      .map(item =>
        String(item || '')
          .replace(/activeChar\.[^,，\s]+/g, '当前角色信息')
          .replace(/sd\.[^,，\s]+/g, '世界状态')
          .replace(/WORLD_MAP_TREE/g, '地图节点')
          .replace(/travel[\s_]?request/gi, '出行安排')
          .replace(/player_action/gi, '玩家行动')
          .replace(/settle_result/gi, '结算结果')

          .replace(/request 变量/gi, '当前安排')
          .replace(/展示/g, '查看')
          .replace(/显示/g, '查看')
          .replace(/整理/g, '收纳')
          .replace(/统一管理/g, '集中查看')
          .replace(/写入/g, '生成')
          .replace(/跳转/g, '前往')
          .replace(/承接/g, '查看')
          .replace(/字段/g, '信息')
          .replace(/变量/g, '内容')
          .replace(/用于显示/g, '展示')
          .replace(/进入这里/g, '收纳于此')
          .replace(/可作为/g, '可视作')
          .replace(/预留/g, '')
          .replace(/后续/g, '')
          .replace(/运行时/g, '')
          .replace(/\(\)/g, '')
          .replace(/\s{2,}/g, ' ')
          .trim(),
      )
      .filter(Boolean);
  }

  function renderGenericModalBody(config) {
    const focusItems = normalizeModalItems(
      config.highlights && config.highlights.length ? config.highlights : config.duties,
    ).slice(0, 6);
    const actionItems = normalizeModalItems(config.actions).slice(0, 6);
    const renderPills = (items, fallback, mode = '') => {
      const source = items.length ? items : [fallback];
      return `<div class="status-tag-rack">${source.map(item => `<span class="status-pill ${mode}">${item}</span>`).join('')}</div>`;
    };
    return `
        <div class="modal-block">
          <div class="modal-block-title">当前要点</div>
          ${renderPills(focusItems, '当前暂无额外要点。')}
        </div>
        <div class="modal-block">
          <div class="modal-block-title">可做事项</div>
          ${renderPills(actionItems, '暂时没有额外操作。', 'live')}
        </div>
      `;
  }

  function makeRadarSvg(labels, values, realValues = null, accent = 'cyan') {
    const size = 220;
    const cx = 110;
    const cy = 110;
    const radius = 70;
    const levels = 4;
    const angleStep = (Math.PI * 2) / labels.length;

    const point = (index, ratio) => {
      const angle = -Math.PI / 2 + angleStep * index;
      return {
        x: cx + Math.cos(angle) * radius * ratio,
        y: cy + Math.sin(angle) * radius * ratio,
      };
    };

    let grids = '';
    for (let level = 1; level <= levels; level++) {
      const ratio = level / levels;
      const pts = labels
        .map((_, idx) => {
          const p = point(idx, ratio);
          return `${p.x},${p.y}`;
        })
        .join(' ');
      grids += `<polygon class="radar-grid-line" points="${pts}"></polygon>`;
    }

    const axes = labels
      .map((_, idx) => {
        const p = point(idx, 1);
        return `<line class="radar-axis-line" x1="${cx}" y1="${cy}" x2="${p.x}" y2="${p.y}"></line>`;
      })
      .join('');

    const shapePoints = values
      .map((value, idx) => {
        const p = point(idx, Math.max(0.08, Math.min(1, value / 100)));
        return `${p.x},${p.y}`;
      })
      .join(' ');

    const labelTexts = labels
      .map((label, idx) => {
        const p = point(idx, 1.22);
        let anchor = 'middle';
        if (p.x < cx - 10) anchor = 'end';
        else if (p.x > cx + 10) anchor = 'start';
        return `<text x="${p.x}" y="${p.y}" text-anchor="${anchor}" dominant-baseline="middle" class="radar-label">${label}</text>`;
      })
      .join('');

    const legend = labels
      .map(
        (label, idx) => `
        <div class="legend-chip">
          <b>${label}</b>
          <span>${realValues ? realValues[idx] : values[idx]}</span>
        </div>
      `,
      )
      .join('');

    return `
        <div class="radar-shell">
          <div class="radar-visual">
            <svg class="radar-svg" viewBox="0 0 ${size} ${size}">
              ${grids}
              ${axes}
              <polygon class="radar-data-shape ${accent === 'gold' ? 'gold' : ''}" points="${shapePoints}"></polygon>
              ${labelTexts}
            </svg>
          </div>
          <div class="radar-legend">${legend}</div>
        </div>
      `;
  }

  function makeTileGrid(items, className = '') {
    const tileItems = Array.isArray(items) ? items : [];
    const compactIntelGrid =
      tileItems.length === 2 && tileItems.every(item => ['线索', '影响'].includes(toText(item && item.label, '')));
    const 紧凑情报网格类 = compactIntelGrid ? ' archive-tile-grid--compact-intel' : '';
    const 紧凑情报格类 = compactIntelGrid ? ' archive-tile--compact-intel' : '';
    const 紧凑情报值类 = compactIntelGrid ? ' class="archive-tile-value--compact-intel"' : '';
    return `
      <div class="archive-tile-grid ${className}${紧凑情报网格类}">
          ${tileItems
            .map(
              item => {
                const 悬浮Html = item && item.悬浮Html ? toText(item.悬浮Html, '') : '';
                const 悬浮类 = 悬浮Html ? ' archive-tile--has-hover' : '';
                const 标题属性 = !悬浮Html && item && item.提示文本 ? ` title="${escapeHtmlAttr(item.提示文本)}"` : '';
                const 聚焦属性 = 悬浮Html ? ' tabindex="0"' : '';
                return `
            <div class="archive-tile${紧凑情报格类}${悬浮类}"${标题属性}${聚焦属性}>
              <b>${item.label}</b>
              <span${紧凑情报值类}>${item && item.值Html ? item.值Html : item.value}</span>
              ${悬浮Html}
            </div>
          `;
              },
            )
            .join('')}
        </div>
      `;
  }

  function escapeHtmlAttr(value) {
    return String(value ?? '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function makeInteractiveTileGrid(items, className = '') {
    return `
        <div class="archive-tile-grid ${className}">
          ${(items || [])
            .map(
              item => {
                const 悬浮Html = item && item.悬浮Html ? toText(item.悬浮Html, '') : '';
                const 悬浮类 = 悬浮Html ? ' archive-tile--has-hover' : '';
                const 标题属性 = !悬浮Html && item && item.提示文本 ? ` title="${escapeHtmlAttr(item.提示文本)}"` : '';
                const 聚焦属性 = 悬浮Html ? ' tabindex="0"' : '';
                return `
            <div class="archive-tile ${item.className || ''}${悬浮类} ${item.preview ? 'clickable' : ''}"${item.preview ? ` data-preview="${escapeHtmlAttr(item.preview)}"` : ''}${标题属性}${聚焦属性}>
              <b>${item.label}</b>
              <span>${item && item.值Html ? item.值Html : item.value}</span>
              ${悬浮Html}
            </div>
          `;
              },
            )
            .join('')}
        </div>
      `;
  }

