  function summarizeArmoryValue(value) {
    if (value === undefined || value === null || value === '') return '无';
    if (Array.isArray(value))
      return (
        value
          .map(item => summarizeArmoryValue(item))
          .filter(Boolean)
          .slice(0, 4)
          .join(' / ') || '无'
      );
    if (typeof value === 'object') {
      const named = value.name || value['名称'] || value.title || value['标题'];
      if (named) return String(named);
      return (
        Object.entries(value)
          .filter(([, v]) => v !== undefined && v !== null && v !== '' && typeof v !== 'object')
          .slice(0, 4)
          .map(([k, v]) => `${k}:${v}`)
          .join(' / ') || '无'
      );
    }
    return String(value);
  }

  function buildStatsBonusItems(statsBonus, options = {}) {
    const bonus = statsBonus && typeof statsBonus === 'object' ? statsBonus : {};
    const normalizeBonusValue = value => {
      const text = String(value ?? '').trim();
      const 百分比匹配 = text.match(/^([+-]?\d+(?:\.\d+)?)%$/);
      if (百分比匹配) {
        if (options.percentAsLevel) {
          const 等级 = Number(百分比匹配[1]) / 10;
          const 文本 = Number.isInteger(等级) ? String(等级) : String(Number(等级.toFixed(2)));
          return `${等级 >= 0 ? '+' : ''}${文本}级`;
        }
        return /^[+-]/.test(text) ? text : `+${text}`;
      }
      const numeric = toNumber(value, 0);
      if (numeric > 0) return Math.floor(numeric);
      if (numeric < 0) return Math.ceil(numeric);
      return 0;
    };
    const 格式化加成值 = (原始加成值, 标签) => {
      const 规范值 = normalizeBonusValue(原始加成值);
      if (typeof 规范值 === 'string') return { value: 规范值 };
      return {
        value: 格式化属性短数字(规范值),
        值Html: 构建属性数值Html(标签, 规范值),
        提示文本: `${标签}：${格式化属性完整数字(规范值)}`,
      };
    };
    const items = [];
    if (options.includeLvEquiv && toNumber(bonus.等效等级, 0) > 0)
      items.push({ label: '等效等级', value: String(toNumber(bonus.等效等级, 0)) });
    items.push(
      { label: '体力加成', ...格式化加成值(bonus.体力上限, '体力加成') },
      { label: '魂力加成', ...格式化加成值(bonus.魂力上限, '魂力加成') },
      { label: '精神加成', ...格式化加成值(bonus.精神力上限, '精神加成') },
      { label: '力量加成', ...格式化加成值(bonus.力量, '力量加成') },
      { label: '防御加成', ...格式化加成值(bonus.防御, '防御加成') },
      { label: '敏捷加成', ...格式化加成值(bonus.敏捷, '敏捷加成') },
    );
    return items;
  }

  function buildEditableStatBonusItems(basePath = [], statsBonus = {}, options = {}) {
    const path = Array.isArray(basePath) ? basePath : [];
    const bonus = statsBonus && typeof statsBonus === 'object' ? statsBonus : {};
    const includeSoulPower = options.includeSoulPower !== false;
    const makeBonusValue = field => {
      const 原始值 = bonus[field];
      const 百分比文本 = /^[+-]?\d+(?:\.\d+)?%$/.test(String(原始值 ?? '').trim()) ? String(原始值 ?? '').trim() : '';
      const 数值 = toNumber(原始值, 0);
      const 写入值 = 百分比文本 || (数值 > 0 ? Math.floor(数值) : 数值 < 0 ? Math.ceil(数值) : 0);
      const 显示文本 = 百分比文本 || 格式化属性短数字(写入值);
      return path.length
        ? makeInlineEditableValue(显示文本, {
            path: [...path, field],
            kind: 百分比文本 ? 'string' : 'number',
            rawValue: 写入值,
            提示文本: 百分比文本 || `${field}：${格式化属性完整数字(写入值)}`,
            editorMeta: 百分比文本 ? undefined : { min: 0, integer: true, hint: '最小 0 · 整数' },
          })
        : 百分比文本
          ? htmlEscape(百分比文本)
          : 构建属性数值Html(field, 写入值);
    };
    return [
      { label: '体力加成', value: makeBonusValue('体力上限') },
      ...(includeSoulPower ? [{ label: '魂力加成', value: makeBonusValue('魂力上限') }] : []),
      { label: '精神加成', value: makeBonusValue('精神力上限') },
      { label: '力量加成', value: makeBonusValue('力量') },
      { label: '防御加成', value: makeBonusValue('防御') },
      { label: '敏捷加成', value: makeBonusValue('敏捷') },
    ];
  }

