    const path = Array.isArray(previewMeta && previewMeta.path) ? previewMeta.path : [];
    const charKey = path[0] === 'char' ? toText(path[1], '').trim() : '';
    return {
      charKey,
      charData: charKey ? deepGet(rootData, ['char', charKey], {}) : {},
    };
