    if (['伤害结算', '资源转移'].includes(原型名) && !['单体', '群体', '全场'].includes(当前目标)) return '单体';
    if (原型名 === '修炼增益' && 当前目标 === '召唤物') return 默认目标 === '自身' ? '自身' : '单体';
    if (当前目标 === '全场' && 技能设计台效果是正向辅助(原型名, 效果 || {})) return '群体';
