    if (!prototype) return false;
    const meta = 读取技能设计台原型摘要(prototype);
    if (meta.类别 !== '战斗外') return true;
    if (['修炼增益', '战斗外复活', '召唤生成'].includes(prototype)) return true;
    return false;
