  function normalizeSkillDesignerPassiveEffects(effectArray = [], draft = {}, previewMeta = {}) {
    const isPassive =
      /被动/.test(normalizeSkillUiText(draft && draft.type, '')) ||
      toText(previewMeta && previewMeta.scope, '') === 'blood_passive';
    if (!isPassive) return Array.isArray(effectArray) ? effectArray : [];
    return (Array.isArray(effectArray) ? effectArray : []).map(effect => {
      if (!effect || typeof effect !== 'object') return effect;
      const cloned = cloneJsonValue(effect);
      const 原型 = toText(cloned && cloned['原型'], '').trim();
      if (['属性修正', '资源变化', '状态施加', '结算修正'].includes(原型)) {
        cloned['目标'] = cloned['目标'] || '自身';
        delete cloned['对象'];
        if (Number(cloned['持续回合'] || 0) > 10) delete cloned['持续回合'];
      }
      if (['护盾变化', '规则防御', '机制授予', '召唤生成', '复制执行'].includes(原型)) {
        cloned['目标'] = cloned['目标'] || '自身';
        if (Number(cloned['持续回合'] || 0) > 10) delete cloned['持续回合'];
      }
      return cloned;
    });
  }

  function 套用技能设计台被动触发(effectArray = [], draft = {}) {
    if (!技能设计台启用被动({}, draft)) return Array.isArray(effectArray) ? effectArray : [];
    return (Array.isArray(effectArray) ? effectArray : []).map(effect => {
      if (!effect || typeof effect !== 'object') return effect;
      const cloned = cloneJsonValue(effect);
      const 原型 = normalizeSkillUiText(cloned['原型'], '');
      cloned['目标'] = '自身';
      delete cloned['对象'];
      if (原型 !== '伤害结算' && Number(cloned['持续回合'] || 0) > 10) delete cloned['持续回合'];
      delete cloned['触发限制'];
      return cloned;
    });
  }

  function buildSkillDesignerConstructEffect(draft = {}, runtimeEffects = []) {
    const 造物默认驱动属性 =
      cloneJsonValue(Array.isArray(runtimeEffects) ? runtimeEffects : []).find(effect =>
        effect &&
        typeof effect === 'object' &&
        normalizeSkillUiText(effect['原型'], '') !== '伤害结算' &&
        normalizeSkillUiText(effect['驱动属性'], '无') !== '无',
      )?.['驱动属性'] || '魂力上限';
    const usageEffects = cloneJsonValue(Array.isArray(runtimeEffects) ? runtimeEffects : []).map(effect => {
      if (!effect || typeof effect !== 'object') return effect;
      const cloned = cloneJsonValue(effect);
      const 原型 = normalizeSkillUiText(cloned['原型'], '');
      const 字段列表 = 读取技能设计台原型字段列表(原型, cloned);
      const 支持驱动 = 字段列表.includes('驱动属性');
      const 支持影响方向 = 字段列表.includes('影响方向');
      if (原型 !== '伤害结算' && 原型 && 支持驱动 && 支持影响方向) {
        if (String(cloned['驱动属性'] ?? '').trim() === '无') {
          delete cloned['驱动属性'];
          delete cloned['影响方向'];
        } else {
          if (!normalizeSkillUiText(cloned['驱动属性'], '')) {
            cloned['驱动属性'] = 造物默认驱动属性;
          }
        }
      }
      应用技能设计台目标驱动契约(原型, cloned);
      return cloned;
    });
    const result = buildSkillDesignerRuntimeObject({
      数量: Math.max(1, parseSkillDesignerIntegerInputValue(draft && draft.constructItemCount, 1, 1)),
      描述: normalizeSkillUiText(
        draft && draft.constructDescription,
        buildSkillDesignerCompactSummary(draft) || '使用后触发对应魂技效果',
      ),
      使用效果: usageEffects,
    });
    const 使用副作用列表 = 规范化技能设计台副作用列表(draft && draft.使用副作用列表);
    if (使用副作用列表.length) result['副作用列表'] = 使用副作用列表;
    const durationTick = Math.max(0, parseSkillDesignerIntegerInputValue(draft && draft.constructDurationTick, 0, 0));
    if (durationTick > 0) result['有效期tick'] = durationTick;
    return result;
  }

  function buildSkillDesignerRuntimeEffects(draft = {}, skillSource = {}, previewMeta = {}) {
    const prototypeEffects = 筛选技能设计台显式原型效果列表(
      draft && draft.prototypeEffects,
      draft && draft.target,
    ).filter(effect => 技能设计台原型需要落盘(effect));
    void skillSource;
    void previewMeta;
    return 规范化技能设计台运行效果生效方式(prototypeEffects);
  }

  function buildSkillDesignerUpdatedSkill(skillSource = {}, formState = {}, previewMeta = {}, 根数据 = {}) {
    const safeSkill = {};
    const 原始副作用违规列表 = [];
    const 记录原始副作用违规 = (列表, 前缀) => {
      if (!Array.isArray(列表)) return;
      规范化技能设计台副作用列表(列表, path => {
        if (path) 原始副作用违规列表.push(path.replace(/^副作用列表/, 前缀));
      });
    };
    记录原始副作用违规(formState && formState['副作用列表'], '副作用列表');
    记录原始副作用违规(formState && formState['使用副作用列表'], '使用副作用列表');
    if (原始副作用违规列表.length) throw new Error(`副作用结构错误：${Array.from(new Set(原始副作用违规列表)).join('、')}`);
    const 原始范围 = normalizeSkillUiText(previewMeta && previewMeta.scope, '');
    if (原始范围 !== 'art') {
      const 原始战斗外原型 = [];
      const 战斗外原型集合 = new Set(['修炼增益', '战斗外复活']);
      const 扫描原始战斗外原型 = effect => {
        if (!effect || typeof effect !== 'object' || Array.isArray(effect)) return;
        const 原型 = normalizeSkillUiText(effect['原型'], '');
        if (战斗外原型集合.has(原型)) 原始战斗外原型.push(原型);
        技能设计台嵌套效果数组字段表.forEach(key => {
          (Array.isArray(effect[key]) ? effect[key] : []).forEach(扫描原始战斗外原型);
        });
      };
      (Array.isArray(formState && formState.prototypeEffects) ? formState.prototypeEffects : []).forEach(扫描原始战斗外原型);
      if (原始战斗外原型.length)
        throw new Error(`战斗外原型不可保存为主动战斗技能：${Array.from(new Set(原始战斗外原型)).join('、')}`);
    }
    const normalized = buildSkillDesignerFormStateFromDraft(formState, previewMeta);
    const normalizedFusionFields =
      previewMeta && previewMeta.scope === '武魂融合技' ? assertSkillDesignerFusionState(normalized) : null;
    if (!normalizeSkillUiText(normalized.name, ''))
      throw new Error(`请填写${getSkillDesignerScopeLabels(previewMeta).nameFieldLabel || '技能名'}。`);
    const designSummary = buildSkillDesignerCompactSummary(normalized);
    const 启用被动 = 技能设计台启用被动(previewMeta, normalized);
    const 有效触发限制 = 读取技能设计台有效触发限制(normalized, previewMeta);
    safeSkill['魂技名'] = 规范第七魂环真身名称_桥接(normalized.name, previewMeta);
    safeSkill['承载方式'] = 启用被动 ? '直接生效' : normalized.deliveryForm || '直接生效';
    safeSkill['消耗'] = formatSkillDesignerFullCostText(normalized.costType, normalized.costValues, normalized.sustainCostText);
    safeSkill['前摇'] = Math.max(0, toNumber(normalized['前摇'], 0));
    if (有效触发限制) safeSkill['触发限制'] = cloneJsonValue(有效触发限制);
    else delete safeSkill['触发限制'];
    if (normalized['技能掌控度']) safeSkill['技能掌控度'] = cloneJsonValue(normalized['技能掌控度']);
    else delete safeSkill['技能掌控度'];
    safeSkill['画面描述'] = normalized.visualDesc;
    safeSkill['效果描述'] = normalized.effectDesc;
    const 技能设计台写回元数据 = {};
    if (previewMeta && previewMeta.scope === 'art') {
      技能设计台写回元数据['功法境界'] = normalizeSkillUiText(normalized.artStage, '未入门');
      技能设计台写回元数据['功法等级'] = Math.max(0, toNumber(normalized.artLevel, 0));
      技能设计台写回元数据['功法经验'] = Math.max(0, toNumber(normalized.artExp, 0));
    }
    if (previewMeta && previewMeta.scope === '武魂融合技') {
      技能设计台写回元数据['融合模式'] = normalizedFusionFields.fusionMode;
      技能设计台写回元数据['融合用法模式'] = normalized['用法模式'];
      技能设计台写回元数据['融合对象'] = normalizedFusionFields.fusionPartner;
      技能设计台写回元数据['融合来源武魂'] = [...normalizedFusionFields.fusionSourceSpirits];
      技能设计台写回元数据['融合参与者'] = cloneJsonValue(normalizedFusionFields.fusionParticipants);
    }
    if (Object.keys(技能设计台写回元数据).length) {
      Object.defineProperty(safeSkill, '技能设计台写回元数据', {
        value: 技能设计台写回元数据,
        enumerable: false,
        configurable: true,
      });
    }
    const 武魂元素上下文 = 读取技能设计台武魂上下文(根数据, previewMeta);
    let 正式附带属性 = 规范化技能元素列表_桥接(normalized.attachedAttributes);
    if (!正式附带属性.length && 技能设计台是元素系上下文(根数据, previewMeta, normalized)) {
      if (!武魂元素上下文.可调用元素.length) throw new Error('元素系技能需要先补全武魂可调用元素。');
      正式附带属性 = [...武魂元素上下文.可调用元素];
    }
    safeSkill['附带属性'] = 正式附带属性;
    const 副作用违规列表 = [];
    const 副作用列表 = 规范化技能设计台副作用列表(normalized['副作用列表'], path => {
      if (path) 副作用违规列表.push(path);
    });
    规范化技能设计台副作用列表(normalized['使用副作用列表'], path => {
      if (path) 副作用违规列表.push(path.replace(/^副作用列表/, '使用副作用列表'));
    });
    if (副作用违规列表.length) throw new Error(`副作用结构错误：${Array.from(new Set(副作用违规列表)).join('、')}`);
    if (副作用列表.length) safeSkill['副作用列表'] = 副作用列表;
    else delete safeSkill['副作用列表'];
    void designSummary;
    const 当前范围 = normalizeSkillUiText(previewMeta && previewMeta.scope, '');
    if (当前范围 !== 'art') {
      const 战斗外主动原型 = [];
      const 战斗外原型集合 = new Set(['修炼增益', '战斗外复活']);
      const 记录战斗外主动原型 = effect => {
        if (!effect || typeof effect !== 'object' || Array.isArray(effect)) return;
        const 原型 = normalizeSkillUiText(effect['原型'], '');
        if (战斗外原型集合.has(原型)) 战斗外主动原型.push(原型);
        技能设计台嵌套效果数组字段表.forEach(key => {
          (Array.isArray(effect[key]) ? effect[key] : []).forEach(记录战斗外主动原型);
        });
      };
      (Array.isArray(normalized.prototypeEffects) ? normalized.prototypeEffects : []).forEach(记录战斗外主动原型);
      if (战斗外主动原型.length)
        throw new Error(`战斗外原型不可保存为主动战斗技能：${Array.from(new Set(战斗外主动原型)).join('、')}`);
    }
    let runtimeEffects = buildSkillDesignerRuntimeEffects(normalized, skillSource, previewMeta);
    runtimeEffects = 套用技能设计台被动触发(
      normalizeSkillDesignerPassiveEffects(runtimeEffects, normalized, previewMeta),
      normalized,
    );
    const normalizedRuntimeEffects = normalizeSkillDesignerExecutionEffectArray(
      cloneJsonValue(runtimeEffects),
      normalizeSkillDesignerTargetForForm(normalized.target, '单体'),
      { draft: normalized, 技能: safeSkill, passiveMode: 技能设计台启用被动(previewMeta, normalized) },
    );
    safeSkill['_效果数组'] =
      normalized.deliveryForm === '造物承载'
        ? [buildSkillDesignerConstructEffect(normalized, normalizedRuntimeEffects)].filter(
            effect => Array.isArray(effect['使用效果']) && effect['使用效果'].length,
          )
        : normalizedRuntimeEffects;
    收口技能设计台元素字段(safeSkill['_效果数组'], safeSkill['附带属性']);
    if (!safeSkill['_效果数组'].length && !技能设计台允许纯描述技能(normalized))
      throw new Error('至少需要一个可执行原型。');
    if (normalized.deliveryForm === '造物承载') {
      safeSkill['_效果数组'].forEach((effect, index) =>
        断言技能设计台效果数组契约(effect['使用效果'] || [], `_效果数组[${index}].使用效果`),
      );
    } else {
      断言技能设计台效果数组契约(safeSkill['_效果数组']);
    }
    断言技能设计台维持契约(safeSkill);
    const 断言预算 = 读取窗口函数('__LWCS_ASSERT_DIRECT_SETTLE_BUDGET__');
    if (typeof 断言预算 === 'function') {
      断言预算(safeSkill, '技能', 构建技能设计台预算上下文(previewMeta, 根数据, normalized));
    }
    return safeSkill;
  }

  function buildSkillDesignerWriteUpdates(previewMeta = {}, nextSkill = {}, rootData = {}) {
    const path = Array.isArray(previewMeta && previewMeta.path) ? previewMeta.path : [];
    if (!path.length) return [];
    断言技能设计台本命召唤唯一(previewMeta, nextSkill, rootData);
    const 技能设计台写回元数据 = nextSkill && typeof nextSkill === 'object' ? (nextSkill.技能设计台写回元数据 || {}) : {};
    const 功法境界 = normalizeSkillUiText(技能设计台写回元数据['功法境界'], '未入门');
    const 功法等级 = Math.max(0, toNumber(技能设计台写回元数据['功法等级'], 0));
    const 功法经验 = Math.max(0, toNumber(技能设计台写回元数据['功法经验'], 0));
    const 融合模式草稿 = 技能设计台写回元数据['融合模式'];
    const 融合用法模式草稿 = 技能设计台写回元数据['融合用法模式'];
    const 融合对象草稿 = 技能设计台写回元数据['融合对象'];
    const 融合来源武魂草稿 = 技能设计台写回元数据['融合来源武魂'];
    const 融合参与者草稿 = 技能设计台写回元数据['融合参与者'];
    const updates = [{ path, value: nextSkill }];
    if (toText(previewMeta && previewMeta.scope, '') === 'art') {
      const charKey = path[0] === 'char' ? toText(path[1], '') : '';
      const 功法名 = normalizeSkillUiText(nextSkill?.魂技名 || path[path.length - 1], path[path.length - 1] || '未命名功法');
      if (charKey && 功法名) {
        const 功法路径 = ['char', charKey, '功法', 功法名];
        updates.push({ path: [...功法路径, '境界'], value: 功法境界 });
        updates.push({ path: [...功法路径, 'lv'], value: 功法等级 });
        updates.push({ path: [...功法路径, 'exp'], value: 功法经验 });
        updates.push({ path: [...功法路径, '描述'], value: normalizeSkillUiText(nextSkill?.效果描述, '无') });
      }
    }
    if (
      toText(previewMeta && previewMeta.scope, '') === '武魂融合技' &&
      toText(path[path.length - 1], '') === '技能数据'
    ) {
      const fusionRecordPath = path.slice(0, -1);
      const existingFusion = deepGet(rootData, fusionRecordPath, {});
      const fusionName = normalizeSkillUiText(
        nextSkill && (nextSkill['魂技名'] || nextSkill.name),
        toText(previewMeta && previewMeta.label, '未命名融合技'),
      );
      const charKey = path[0] === 'char' ? toText(path[1], '') : '';
      const spiritOptions = getSkillDesignerSpiritNameOptions(charKey ? deepGet(rootData, ['char', charKey], {}) : {});
      const canUseSelfFusion = spiritOptions.length >= 2;
      let fusionMode = normalizeSkillDesignerFusionMode(
        融合模式草稿 || existingFusion.融合模式 || 'partner',
      );
      if (fusionMode === 'self' && !canUseSelfFusion) fusionMode = 'partner';
      const 用法模式 = 规范化技能设计台融合用法模式(
        融合用法模式草稿 || existingFusion['用法模式'],
      );
      const 临时融合数据 = {
        融合参与者: 融合参与者草稿,
        来源武魂: 融合来源武魂草稿,
        融合对象: 融合对象草稿,
      };
      const rawParticipants = getSkillDesignerRawFusionParticipants(临时融合数据, {}).length
        ? getSkillDesignerRawFusionParticipants(临时融合数据, {})
        : getSkillDesignerRawFusionParticipants({}, existingFusion);
      const fusionParticipants = normalizeSkillDesignerFusionParticipantList(rawParticipants, rootData);
      const fusionFields = deriveSkillDesignerFusionFields(
        fusionMode,
        fusionParticipants,
        normalizeSkillUiText(
          融合对象草稿 || existingFusion['融合对象'],
          '未知搭档',
        ),
      );
      const partnerValue = fusionFields.fusionPartner;
      let sourceSpirits = fusionFields.fusionSourceSpirits.length
        ? fusionFields.fusionSourceSpirits
        : normalizeSkillDesignerArray(融合来源武魂草稿 || existingFusion.来源武魂);
      if (fusionMode === 'self' && !sourceSpirits.length) sourceSpirits = spiritOptions.slice(0, 2);
      updates.push({ path: [...fusionRecordPath, '名称'], value: fusionName });
      updates.push({ path: [...fusionRecordPath, '融合模式'], value: fusionMode });
      updates.push({ path: [...fusionRecordPath, '用法模式'], value: 用法模式 });
      updates.push({ path: [...fusionRecordPath, '融合对象'], value: partnerValue });
      updates.push({ path: [...fusionRecordPath, '来源武魂'], value: sourceSpirits });
      updates.push({
        path: [...fusionRecordPath, '融合参与者'],
        value: cloneJsonValue(fusionFields.fusionParticipants),
      });
    }
    return updates;
  }

  function summarizeSkillEffectArray(effectArray, skill = null, cachedDraft = null) {
    const effectNames = (Array.isArray(effectArray) ? effectArray : [])
      .map(effect => {
        const name = toText(effect && effect['原型'], '').trim();
        if (!name && Array.isArray(effect && effect['使用效果'])) return summarizeConstructEffectUi(effect);
        if (!name || isSkillSummaryEffect(effect)) return '';
        if (name === '召唤生成') return summarizeSummonEffectUi(effect);
        if (name === '状态施加') return normalizeSkillUiText(effect && effect['状态'], '状态施加');
        return name;
      })
      .filter(Boolean);
    if (effectNames.length) return effectNames.join(' / ');
    const draft = cachedDraft || (skill ? readSkillDesignerDraft(skill) : null);
    const designSummary = buildSkillDesignerMechanicSummary(draft || {});
    return designSummary || '未知';
  }

  function resolveExpiryUiText(item, fallback = '') {
    const expiryTick = toNumber(item && item['有效期至tick'], 0);
    if (expiryTick > 0) return formatTickToCalendarDateText(expiryTick);
    const explicitText = normalizeSkillUiText(item && item['有效期至'], '');
    if (explicitText) return explicitText;
    return fallback;
  }

  function 读取场外魂技冷却档(skill = {}) {
    const 前摇 = Math.max(0, toNumber(skill && skill['前摇'], 0));
    if (前摇 < 30) return { 标签: '随时', 冷却tick: 0 };
    if (前摇 < 60) return { 标签: '每小时', 冷却tick: 6 };
    if (前摇 < 90) return { 标签: '每日', 冷却tick: 144 };
    return { 标签: '每周', 冷却tick: 1008 };
  }

  function 读取场外魂技冷却状态(skill = {}, 当前tick = 0) {
    const 冷却档 = 读取场外魂技冷却档(skill);
    const 当前 = Math.max(0, toNumber(当前tick, 0));
    const 冷却至tick = Math.max(0, toNumber(skill && skill['场外冷却至tick'], 0));
    const 冷却中 = 冷却至tick > 当前;
    return {
      ...冷却档,
      冷却至tick,
      冷却中,
      冷却文本: 冷却中 ? `冷却至${formatTickToCalendarDateText(冷却至tick)}` : '',
    };
  }

  function 校验场外魂技冷却(skill = {}, 当前tick = 0, 技能名 = '技能') {
    const 冷却状态 = 读取场外魂技冷却状态(skill, 当前tick);
    if (冷却状态.冷却中) throw new Error(`【${技能名}】场外冷却中，${冷却状态.冷却文本}。`);
    return 冷却状态;
  }

  function 写入场外魂技冷却(skill = {}, 当前tick = 0) {
    if (!skill || typeof skill !== 'object' || Array.isArray(skill)) return null;
    const 冷却状态 = 读取场外魂技冷却状态(skill, 当前tick);
    if (冷却状态.冷却tick > 0) skill['场外冷却至tick'] = Math.max(0, toNumber(当前tick, 0)) + 冷却状态.冷却tick;
    else delete skill['场外冷却至tick'];
    return 读取场外魂技冷却状态(skill, 当前tick);
  }

  function extractConstructCreateEffects(effectArray = []) {
    return (Array.isArray(effectArray) ? effectArray : []).filter(
      effect =>
        effect &&
        typeof effect === 'object' &&
        !toText(effect['原型'], '').trim() &&
        Array.isArray(effect['使用效果']),
    );
  }

  function buildConstructSkillActionHtml(skillPath = [], skill = {}, 当前tick = 0) {
    if (!Array.isArray(skillPath) || !skillPath.length) return '';
    const 冷却状态 = 读取场外魂技冷却状态(skill, 当前tick);
    const 禁用 = 冷却状态.冷却中;
    const 提示 = 禁用 ? ` title="${escapeHtmlAttr(冷却状态.冷却文本)}"` : '';
    return `
        <div class="tag-cloud armory-quick-actions mvu-detail-toolbar mvu-detail-toolbar--tight">
          <button type="button" class="tag-chip live skill-inline-action-btn" data-skill-action="cast-construct" data-skill-path="${escapeHtmlAttr(JSON.stringify(skillPath))}"${禁用 ? ' disabled aria-disabled="true"' : ''}${提示}>${禁用 ? '冷却中' : '日常施展'}</button>
        </div>
      `;
  }

  function skillHasDailyMvuWritebackEffect(skill = {}) {
    const 可写回原型 = new Set(['资源变化', '属性修正', '状态施加', '状态移除', '修炼增益', '战斗外复活', '灵物吸收', '护盾变化', '机制授予', '复制执行']);
    const visit = effects =>
      (Array.isArray(effects) ? effects : []).some(effect => {
        if (!effect || typeof effect !== 'object') return false;
        if (!toText(effect['原型'], '').trim() && Array.isArray(effect['使用效果'])) return false;
        const 原型 = toText(effect['原型'], '').trim();
        if (可写回原型.has(原型)) return true;
        if (技能设计台嵌套效果数组字段表.some(字段名 => visit(effect[字段名]))) return true;
        return (Array.isArray(effect['条件分支']) ? effect['条件分支'] : []).some(branch =>
          技能设计台条件分支效果数组字段表.some(字段名 => visit(branch && branch[字段名])),
        );
      });
    return visit(skill && skill['_效果数组']);
  }

  function buildDailyWritebackSkillActionHtml(skillPath = [], skill = {}, 当前tick = 0) {
    if (!Array.isArray(skillPath) || !skillPath.length) return '';
    const 冷却状态 = 读取场外魂技冷却状态(skill, 当前tick);
    const 禁用 = 冷却状态.冷却中;
    const 提示 = 禁用 ? ` title="${escapeHtmlAttr(冷却状态.冷却文本)}"` : '';
    return `
        <div class="tag-cloud armory-quick-actions mvu-detail-toolbar mvu-detail-toolbar--tight">
          <button type="button" class="tag-chip live skill-inline-action-btn" data-skill-action="daily-writeback" data-skill-path="${escapeHtmlAttr(JSON.stringify(skillPath))}"${禁用 ? ' disabled aria-disabled="true"' : ''}${提示}>${禁用 ? '冷却中' : '使用'}</button>
        </div>
      `;
  }

  function buildSkillList(skillObj, options = {}) {
    const basePath = Array.isArray(options && options.basePath) ? options.basePath : [];
    const category = normalizeSkillUiText(options && options.category, '技能');
    const scope = normalizeSkillUiText(options && options.scope, 'skill');
    const 渲染快照 = options && options.渲染快照 && typeof options.渲染快照 === 'object' ? options.渲染快照 : { rootData: {} };
    const 渲染根数据 = 渲染快照.rootData && typeof 渲染快照.rootData === 'object' ? 渲染快照.rootData : {};
    const 当前tick = Math.max(0, toNumber(deepGet(渲染根数据, 'world.时间.tick', 0), 0));
    const skills = safeEntries(skillObj).map(([rawName, skill]) => {
      const effectArray = Array.isArray(skill && skill['_效果数组']) ? skill['_效果数组'] : [];
      const draft = readSkillDesignerDraft(skill, rawName);
      const effectCount = effectArray.filter(effect => {
        const name = toText(effect && effect['原型'], '').trim();
        return name && !isSkillSummaryEffect(effect);
      }).length;
      const cleanSkillName = draft.name;
      const skillPath = basePath.length ? [...basePath, rawName] : [];
      const 技能预览元数据 = {
        path: skillPath,
        label: cleanSkillName,
        category,
        scope,
      };
      const 技能翻译输入 = {
        ...skill,
        __魂环位: 推断技能设计台魂环位(技能预览元数据),
        __战斗来源类别: ['魂技', 'independent_ring_skill'].includes(scope) ? '魂技' : scope,
      };
      const visualDesc = normalizeSkillUiText(skill && skill['画面描述'], '未知');
      const effectDesc = normalizeSkillUiText(skill && skill['效果描述'], '未知');
      const 正式翻译器 = 读取正式技能结构翻译器();
      const effectSummaryCore =
        typeof 正式翻译器 === 'function'
          ? normalizeSkillUiText(正式翻译器(技能翻译输入, { 当前tick }), '') || summarizeSkillEffectArray(effectArray, skill, draft)
          : summarizeSkillEffectArray(effectArray, skill, draft);
      const constructMeta = extractConstructEffectMeta(effectArray);
      const attributeSummary = buildSkillDesignerAttributeSummary(draft);
      const effectSummary =
        effectSummaryCore === '未知'
          ? '未知'
          : effectCount > 0
            ? `${effectSummaryCore} (${effectCount}项)`
            : effectSummaryCore;
      const type = normalizeSkillUiText(draft && draft.type, 推断技能设计台技能分类(effectArray, '输出'));
      const target = normalizeSkillUiText(draft && draft.target, '未知');
      const cost = 构建技能设计台运行态消耗展示(skill && skill['消耗'], effectArray, 技能预览元数据, skill);
      const 前摇 = Math.max(0, toNumber(skill && skill['前摇'], 0));
      const 机制推断 = inferSkillDesignerMechanicsFromEffectArray(effectArray, type, target);
      const mainRole = normalizeSkillUiText(
        (draft && draft.mainRole) ||
          inferSkillDesignerMainRole(type, target, 机制推断.primaryMain, 机制推断.primarySub),
        '未知',
      );
      const descSegments = [];
      const pushDesc = text => {
        const safeText = toText(text, '').trim();
        if (!safeText || descSegments.includes(safeText)) return;
        descSegments.push(safeText);
      };
      pushDesc(constructMeta ? `造物：${constructMeta.summary}` : '');
      pushDesc(attributeSummary ? `属性：${attributeSummary}` : '');
      pushDesc(visualDesc !== '未知' ? `画面：${visualDesc}` : '');
      pushDesc(effectDesc !== '未知' ? `效果：${effectDesc}` : '');
      if (effectSummary !== '未知') pushDesc(`_简易效果：${effectSummary}`);
      // v4 阶段 6：COST 预算评估卡片（对等基线 / 允许上限 / 位级硬上限 三段对照）
      try {
        const COST助手 = (typeof globalThis !== 'undefined' && globalThis.__LWCS_SKILL_COST_HELPERS_V1__)
          || (typeof window !== 'undefined' && window.__LWCS_SKILL_COST_HELPERS_V1__)
          || null;
        if (COST助手 && typeof COST助手.评估技能预算_V1 === 'function') {
          const 预算上下文 = 构建技能设计台预算上下文(技能预览元数据, 渲染根数据, draft || {});
          const 评估 = COST助手.评估技能预算_V1(skill || {}, {
            ...预算上下文,
            path: skillPath,
            来源: 预算上下文.来源类别,
          });
          if (评估 && Number.isFinite(评估.允许上限)) {
            const 消耗倍数 = 评估.消耗倍数;
            const 前摇倍数 = 评估.前摇倍数;
            const 状态标签 = 评估.是否超预算 ? '⚠超预算' : '达标';
            const 倍数提示 = (消耗倍数 !== 1 || 前摇倍数 !== 1)
              ? ` (消耗 ${消耗倍数.toFixed(2)}× × 前摇 ${前摇倍数.toFixed(2)}×)`
              : '';
            const 来源标签 = 评估.来源 && 评估.来源 !== '魂技' ? `[${评估.来源}]` : '';
            pushDesc(`COST预算${来源标签}: 实际${评估.实际COST.toFixed(1)} / 上限${评估.实际门禁.toFixed(1)} [${状态标签}]${倍数提示}`);
          }
        }
      } catch (e) { /* 评估失败不影响渲染 */ }
      let desc = descSegments.join('<br/>');
      const tags = Array.from(
        new Set(
          effectArray
            .map(effect => normalizeSkillUiText(effect && effect['原型'], ''))
            .filter(name => name && !SKILL_SUMMARY_EFFECT_MECHANISM_SET.has(name))
            .concat(type && type !== '未知' ? [type] : [])
            .concat(mainRole && mainRole !== '未知' ? [mainRole] : [])
            .concat(Array.isArray(draft.attachedAttributes) ? draft.attachedAttributes : []),
        ),
      )
        .filter(Boolean)
        .slice(0, 8);

      const preview = buildSkillDesignerPreviewKey({
        path: skillPath,
        label: cleanSkillName,
        category,
        scope,
      });
      const constructCreateEffects = extractConstructCreateEffects(effectArray);
      const canDailyCastConstruct =
        skillPath.length > 0 && skillPath[0] === 'char' && constructCreateEffects.length > 0;
      const canDailyUseWriteback =
        skillPath.length > 0 &&
        skillPath[0] === 'char' &&
        constructCreateEffects.length <= 0 &&
        skillHasDailyMvuWritebackEffect(skill);
      const constructActionHtml = canDailyCastConstruct
        ? buildConstructSkillActionHtml(skillPath, skill, 当前tick)
        : canDailyUseWriteback
          ? buildDailyWritebackSkillActionHtml(skillPath, skill, 当前tick)
        : '';
      if (constructActionHtml) desc += constructActionHtml;

      return {
        name: cleanSkillName,
        type,
        target,
        cost,
        前摇,
        desc: desc || '未知',
        visualDesc,
        effectDesc,
        effectSummary,
        status: effectCount > 0 ? '已觉醒' : '未生成',
        mainRole,
        tags,
        preview,
        path: skillPath,
        category,
        scope,
        designDraft: draft,
        constructActionHtml,
      };
    });

    if (skills.length) return skills;
    if (options && options.空表不造占位 === true) return [];

    return [
      {
        name: '魂技未显现',
        type: '未觉醒',
        target: '未知',
        bonus: '未知',
        cost: '未知',
        desc: '魂技信息尚未明晰。',
        visualDesc: '未知',
        effectDesc: '未知',
        effectSummary: '未知',
        status: '未觉醒',
        mainRole: '未知',
        tags: [],
        preview: '',
        path: [],
        category,
        scope,
        designDraft: null,
      },
    ];
  }

  function buildSpiritRingInfo(ringIndex, ring, skills, options = {}) {
    const ringPath = Array.isArray(options.path) ? options.path : [];
    const forceGold = !!(options && options.forceGold);
    const colorText = getRingDisplayColorLabel(ring && ring['颜色'], ring && ring['年限'], { forceGold });
    const ageText = formatAge(ring && ring['年限']);
    return {
      glyph: ringGlyph(ring && ring['颜色'], ringIndex, ring && ring['年限'], { forceGold }),
      ringClass: mapRingClass(ring && ring['颜色'], ring && ring['年限'], { forceGold }),
      title: toText(options && options.title, `第${ringIndex}魂环`),
      desc: [colorText, ageText].filter(Boolean).join(' / '),
      skills,
      path: ringPath,
      colorText,
      colorValue: colorText,
      ageText,
      sourceText: normalizeSkillUiText(options && options.sourceText, ''),
      sourceValue: toText(options && options.sourceValue, ''),
      sourcePath: Array.isArray(options && options.sourcePath) ? options.sourcePath : [],
    };
  }

  function buildRingHoverMetaMarkup(ring) {
    const colorMarkup =
      ring && Array.isArray(ring.path) && ring.path.length
        ? makeInlineEditableValue(toText(ring.colorText, '未定'), {
            path: [...ring.path, '颜色'],
            kind: 'enum_select',
            rawValue: toText(ring.colorValue, toText(ring.colorText, '未定')),
            editorMeta: { options: RING_COLOR_OPTIONS },
          })
        : htmlEscape(toText(ring && ring.colorText, '未定'));
    const 年限文本 = toText(ring && ring.ageText, '').trim();
    const 来源文本 = toText(ring && ring.sourceText, '').trim();
    const 来源存在 = !!来源文本;
    let 来源Markup = '';
    if (来源存在) {
      来源Markup =
        ring && ring.sourcePath && ring.sourcePath.length
          ? makeInlineEditableValue(来源文本, {
              path: ring.sourcePath,
              kind: 'string',
              rawValue: toText(ring.sourceValue, 来源文本),
            })
          : htmlEscape(来源文本);
    }
    const 片段 = [colorMarkup, 年限文本 ? htmlEscape(年限文本) : '', 来源存在 ? 来源Markup : ''].filter(Boolean);
    return 片段.length ? `<div class="ring-hover-desc">${片段.join(' / ')}</div>` : '';
  }

  function 构建技能悬浮详情内容(技能, 选项 = {}) {
    const 安全技能 = 技能 && typeof 技能 === 'object' ? 技能 : {};
    const 显示标题 = 选项 && 选项.显示标题 !== false;
    const 元信息行 = [];
    const 添加元信息 = (label, value) => {
      const 文本 = toText(value, '').trim();
      if (!文本 || 文本 === '未知') return;
      元信息行.push(
        `<div class="ring-hover-meta-row"><em>${htmlEscape(label)}</em><strong>${htmlEscape(文本)}</strong></div>`,
      );
    };
    添加元信息('类别', [安全技能.category || 安全技能.type, 安全技能.mainRole].map(item => toText(item, '').trim()).filter(Boolean).join(' · '));
    添加元信息('目标', 安全技能.target);
    添加元信息('消耗', 安全技能.cost);
    const 前摇 = Math.max(0, toNumber(安全技能.前摇, 0));
    if (前摇 > 0) 添加元信息('前摇', `${formatNumber(前摇)} tick`);
    const 元信息Html = 元信息行.length ? `<div class="ring-hover-meta">${元信息行.join('')}</div>` : '';
    const 文案行Html = [
      ['画面描述', 安全技能.visualDesc],
      ['效果描述', 安全技能.effectDesc],
    ]
      .map(([label, value]) => {
        const 文本 = toText(value, '').trim();
        if (!文本 || 文本 === '未知') return '';
        return `<div class="ring-hover-copy"><em>${htmlEscape(label)}</em><span>${htmlEscape(文本)}</span></div>`;
      })
      .filter(Boolean)
      .join('');
    const 标签列表 = Array.isArray(安全技能.tags)
      ? 安全技能.tags
          .map(item => toText(item, '').trim())
          .filter(Boolean)
          .slice(0, 6)
      : [];
    const 标签Html = 标签列表.length
      ? `<div class="ring-hover-tags">${标签列表.map(item => `<span class="ring-hover-chip">${htmlEscape(item)}</span>`).join('')}</div>`
      : '';
    const 预览属性 = 安全技能.preview
      ? ` data-preview="${escapeHtmlAttr(安全技能.preview)}" data-detail-mode="embed"`
      : '';
    return `
        <div class="ring-hover-skill skill-hover-detail${安全技能.preview ? ' clickable' : ''}"${预览属性}>
          ${显示标题 ? `<b>${htmlEscape(安全技能.name || '未命名技能')}</b>` : ''}
          ${元信息Html}
          ${文案行Html || '<div class="ring-hover-copy"><em>效果描述</em><span>未知</span></div>'}
          ${标签Html}
          ${安全技能.constructActionHtml || ''}
        </div>
      `;
  }

  function 构建技能悬浮卡片(技能, 副标题输入 = '') {
    const 标题 = toText(技能 && 技能.name, '未命名技能');
    const 副标题 = toText(副标题输入, '').trim();
    return `<div class="ring-hover-card skill-hover-card"><div class="ring-hover-title">${htmlEscape(标题)}</div>${副标题 ? `<div class="ring-hover-desc">${htmlEscape(副标题)}</div>` : ''}${构建技能悬浮详情内容(技能, { 显示标题: false })}</div>`;
  }

  function buildRingHoverCardMarkup(ring) {
    const skills = (ring && Array.isArray(ring.skills) ? ring.skills : [])
      .map(技能 => 构建技能悬浮详情内容(技能, { 显示标题: true }))
      .join('');
    return `<div class=\"ring-hover-card\"><div class=\"ring-hover-title\">${htmlEscape(toText(ring && ring.title, '魂环技能'))}</div>${buildRingHoverMetaMarkup(ring)}${skills}</div>`;
  }

  function buildSpiritConfig(slotName, spiritData, previewKey, badgeText, badgeClass, spiritBasePath = [], 渲染快照 = null) {
    const spiritPath = Array.isArray(spiritBasePath) ? spiritBasePath : [];
    const soulEntries = 取武魂魂灵条目_桥接(spiritData);
    const summaryRings = [];
    const souls = soulEntries.map(([soulName, soulData]) => {
      const soulPath = [...spiritPath, soulName];
      const soulDisplayName = normalizeSkillUiText(soulData && soulData['表象名称'], soulName);
      const ringEntries = 取魂灵魂环条目_桥接(soulData)
        .sort((a, b) => 读取槽位序号_桥接(a[0], 1) - 读取槽位序号_桥接(b[0], 1))
        .map(([ringIndex, ring]) => {
          const skills = buildSkillList(Object.fromEntries(取魂环魂技条目_桥接(ring)), {
            basePath: [...soulPath, ringIndex],
            category: '魂环魂技',
            scope: '魂技',
            渲染快照,
          });
          const ringInfo = buildSpiritRingInfo(ringIndex, ring, skills, {
            path: [...soulPath, ringIndex],
            title: `${ringIndex} · ${skills[0] ? skills[0].name : soulDisplayName}`,
            sourceText: soulDisplayName,
          });
          summaryRings.push(ringInfo);
          return ringInfo;
        });

      const spiritName = soulDisplayName;
      const description = normalizeSkillUiText(soulData && soulData['描述'], '未设置');
      const quality = normalizeSkillUiText(soulData && soulData['品质'], '未设置');
      const state = normalizeSkillUiText(soulData && soulData['状态'], '未知');
      const ageValue = toNumber(soulData && soulData['年限'], 0);
      const compValue = toNumber(soulData && soulData['契合度'], 100);
      return {
        name: soulName,
        desc: spiritName,
        spiritName,
        description,
        quality,
        state,
        age: formatAge(ageValue),
        ageValue,
        comp: `${compValue}%`,
        compValue,
        path: soulPath,
        魂环: ringEntries,
      };
    });
    const independentRings = 取武魂直接魂环条目_桥接(spiritData)
      .sort((a, b) => 读取槽位序号_桥接(a[0], 1) - 读取槽位序号_桥接(b[0], 1))
      .map(([ringIndex, ring]) => {
        const 魂环位 = 读取槽位序号_桥接(ringIndex, 1);
        const ringPath = [...spiritPath, ringIndex];
        const skills = buildSkillList(Object.fromEntries(取魂环魂技条目_桥接(ring)), {
          basePath: ringPath,
          category: '独立魂环魂技',
          scope: 'independent_ring_skill',
          渲染快照,
        });
        const ringInfo = buildSpiritRingInfo(ringIndex, ring, skills, {
          path: ringPath,
          title: `第${魂环位}魂环`,
          sourceText: normalizeSkillUiText(ring && ring['来源'], ''),
          sourceValue: toText(ring && ring['来源'], ''),
          sourcePath: [...ringPath, '来源'],
        });
        summaryRings.push(ringInfo);
        return ringInfo;
      });

    if (!souls.length) {
      souls.push({
        name: '魂灵槽位',
        desc: '尚未接入魂灵。',
        spiritName: '未设置',
        description: '尚未接入魂灵。',
        quality: '未设置',
        state: '未激活',
        age: '--',
        ageValue: 0,
        comp: '--',
        compValue: 0,
        path: [],
        魂环: [],
      });
    }

    const soulCount = soulEntries.length;
    const independentRingCount = independentRings.length;
    const displayName = normalizeSkillUiText(spiritData && spiritData['表象名称'], slotName);
    const spiritType = normalizeSkillUiText(spiritData && spiritData['系别'], '未知系');
    const spiritDesc = normalizeSkillUiText(spiritData && spiritData['描述'], '未设置');
    const attributeState = resolveSpiritAttributeUiState(spiritData);

    return {
      preview: previewKey,
      badge: badgeText,
      badgeClass,
      name: `${displayName}（${spiritType}）`,
      desc: `属性体系：${attributeState.attributeSystem} / 魂灵：${soulCount} / 独立环：${independentRingCount}`,
      魂环: summaryRings.slice(0, 10),
      souls,
      independentRings,
      soulCount,
      independentRingCount,
      slotName,
      spiritPath,
      spiritName: displayName,
      spiritDesc,
      spiritType,
      spiritElement: attributeState.attributeSystem,
      spiritCallableElements: attributeState.callableElements,
    };
  }

  function createDefaultRingSkillShellForUi() {
    return {
      魂技名: '待补全',
      画面描述: '未知',
      效果描述: '未知',
      _效果数组: [],
    };
  }

  function buildDefaultRingSkillMapForUi(ringIndex = 1, ringAge = 0) {
    const 技能序号 = Math.max(1, Math.floor(Number(ringIndex) || 1));
    const baseSkillKey = `第${技能序号}魂技`;
    if (技能序号 === 7) {
      return {
        [baseSkillKey]: { ...createDefaultRingSkillShellForUi(), 魂技名: '武魂真身' },
      };
    }
    const skillMap = {
      [baseSkillKey]: createDefaultRingSkillShellForUi(),
    };
    if (Math.floor(Number(ringAge) || 0) >= 100000) {
      skillMap[`${baseSkillKey}_2`] = createDefaultRingSkillShellForUi();
    }
    return skillMap;
  }

  function buildDefaultBloodlineRingSkillMapForUi(ringIndex = 1, ringAge = 0) {
    const 技能序号 = Math.max(1, Math.floor(Number(ringIndex) || 1));
    const baseSkillKey = `第${技能序号}血脉魂技`;
    const skillMap = { [baseSkillKey]: createDefaultRingSkillShellForUi() };
    if (Math.floor(Number(ringAge) || 0) >= 100000)
      skillMap[`${baseSkillKey}_2`] = createDefaultRingSkillShellForUi();
    return skillMap;
  }

  function getSoulSpiritRingCapacityForUi(ageValue = 0) {
    const years = Math.max(0, toNumber(ageValue, 0));
    if (years >= 10000) return 4;
    if (years >= 1000) return 3;
    if (years >= 100) return 2;
    return 1;
  }

  function buildPendingSoulRingState(snapshot) {
    const safeSnapshot = snapshot && typeof snapshot === 'object' ? snapshot : null;
    if (!safeSnapshot || !safeSnapshot.rootData) return null;
    const activeChar =
      safeSnapshot.activeChar && typeof safeSnapshot.activeChar === 'object' ? safeSnapshot.activeChar : null;
    const pending =
      activeChar && activeChar.状态 && typeof activeChar.状态.待选魂环 === 'object' ? activeChar.状态.待选魂环 : null;
    if (!pending) return null;
    const status = toText(pending.状态, '').trim();
    const spiritSlot = toText(pending.武魂槽位, '').trim();
    const ringIndex = Math.max(1, toNumber(pending.待生成魂环位, 1));
    if (!status || !spiritSlot || !ringIndex) return null;
    const charKey =
      resolveSnapshotCharKey(safeSnapshot, toText(safeSnapshot.activeName, '')) || toText(safeSnapshot.activeName, '');
    if (!charKey) return null;
    const spiritData = deepGet(safeSnapshot, ['rootData', 'char', charKey, spiritSlot], {});
    const spiritPreviewKey =
      spiritSlot === '第1武魂' ? '第1武魂详细页' : spiritSlot === '第2武魂' ? '第2武魂详细页' : '第1武魂详细页';
    const candidateNames = Array.isArray(pending.候选魂灵)
      ? pending.候选魂灵.map(name => toText(name, '').trim()).filter(Boolean)
      : [];
    const candidates = candidateNames.map(name => {
      const soulData = deepGet(spiritData, [name], {});
      const ageValue = toNumber(soulData && soulData.年限, 0);
      const displayName = normalizeSkillUiText(soulData && soulData.表象名称, name || '候选魂灵');
      const ringCount = 取魂灵魂环条目_桥接(soulData).length;
      const ringCapacity = getSoulSpiritRingCapacityForUi(ageValue);
      const nextRingColorLabel = getRingDisplayColorLabel('', ageValue);
      return {
        soulName: name,
        displayName,
        ageValue,
        ageText: formatAge(ageValue),
        quality: normalizeSkillUiText(soulData && soulData.品质, '未设置'),
        state: normalizeSkillUiText(soulData && soulData.状态, '未知'),
        compValue: toNumber(soulData && soulData.契合度, 100),
        description: normalizeSkillUiText(soulData && soulData.描述, '暂无描述'),
        ringCount,
        ringCapacity,
        remainingSlots: Math.max(0, ringCapacity - ringCount),
        remainingAfterGenerate: Math.max(0, ringCapacity - ringCount - 1),
        nextRingColorLabel,
        nextRingClass: mapRingClass('', ageValue),
        sourcePath: ['char', charKey, spiritSlot, name],
      };
    });
    const signature = [charKey, spiritSlot, ringIndex, status, candidates.map(item => item.soulName).join('|')].join(
      '::',
    );
    return {
      charKey,
      charName: toText(safeSnapshot.activeName, charKey),
      spiritSlot,
      spiritName: normalizeSkillUiText(spiritData && spiritData.表象名称, spiritSlot),
      spiritPreviewKey,
      ringIndex,
      status,
      source: toText(pending.来源, ''),
      candidates,
      signature,
    };
  }

  function shouldRenderBloodline(activeChar) {
    const 血脉资料 = deepGet(activeChar, '血脉之力', {});
    if (!血脉资料 || typeof 血脉资料 !== 'object') return false;
    const 血脉名 = normalizeSkillUiText(血脉资料['血脉'], '无');
    const 有血脉名 = !!血脉名 && !['无', '未觉醒', '未觉醒血脉'].includes(血脉名);
    return (
      有血脉名 ||
      safeEntries(deepGet(血脉资料, '技能', {})).length > 0 ||
      safeEntries(deepGet(血脉资料, '被动', {})).length > 0 ||
      取血脉气血魂环条目_桥接(血脉资料).length > 0
    );
  }

  function buildBloodlineConfig(activeChar, activeName = '', bloodlineBasePath = [], 渲染快照 = null) {
    const bloodlineData = deepGet(activeChar, '血脉之力', {});
    if (!shouldRenderBloodline(activeChar)) {
      return {
        kind: 'bloodline',
        valid: false,
        preview: '血脉封印详细页',
        badge: '血脉',
        badgeClass: 'gold',
        name: '',
        desc: '',
        魂环: [],
        bloodSkills: [],
        bloodPassives: [],
        sealLv: 0,
        core: '未凝聚',
        lifeFire: false,
        bloodline: '无',
        使用封印界面: false,
      };
    }
    const bloodline = normalizeSkillUiText(deepGet(activeChar, '血脉之力.血脉', '无'), '无');
    const sealLv = toNumber(deepGet(activeChar, '血脉之力.解封层数', 0), 0);
    const core = normalizeSkillUiText(deepGet(activeChar, '血脉之力.核心', '未凝聚'), '未凝聚');
    const rawSkills = deepGet(activeChar, '血脉之力.技能', {});
    const rawRings = Object.fromEntries(取血脉气血魂环条目_桥接(bloodlineData));
    const rawPassives = deepGet(activeChar, '血脉之力.被动', {});
    const hasBloodlineData =
      !['无', '未觉醒', '未觉醒血脉'].includes(toText(bloodline, '无')) ||
      safeEntries(rawRings).length > 0 ||
      safeEntries(rawSkills).length > 0 ||
      safeEntries(rawPassives).length > 0;
    const 是金龙王 = bloodline === '金龙王';
    const 是银龙王 = bloodline === '银龙王';
    const 使用封印界面 = 是金龙王;
    const ringEntries = 取血脉气血魂环条目_桥接(bloodlineData)
      .sort((a, b) => 读取槽位序号_桥接(a[0], 1) - 读取槽位序号_桥接(b[0], 1))
      .map(([index, ring]) =>
        buildSpiritRingInfo(
          index,
          ring,
          buildSkillList(Object.fromEntries(取气血魂环魂技条目_桥接(ring)), {
            basePath: [...bloodlineBasePath, index],
            category: '血脉魂环',
            scope: 'blood_ring_skill',
            渲染快照,
          }),
          {
            path: [...bloodlineBasePath, index],
            title: `血脉环位 · ${index}`,
            sourceText: toText(activeChar && activeChar['血脉之力'] && activeChar['血脉之力']['血脉'], '血脉本体'),
          },
        ),
      );
    const normalizedRingEntries = ringEntries.slice(0, 10);

    return {
      kind: 'bloodline',
      valid: hasBloodlineData,
      preview: '血脉封印详细页',
      badge: 使用封印界面 ? '血脉封印' : '血脉能力',
      badgeClass: 'gold',
      name: `${bloodline === '无' ? '未觉醒血脉' : bloodline}`,
      desc: 使用封印界面
        ? `解封层数：${sealLv} / 体力魂核：${core}`
        : `主动能力：${safeEntries(rawSkills).length} / 被动特性：${safeEntries(rawPassives).length}`,
      魂环: 使用封印界面 || (!是银龙王 && normalizedRingEntries.length) ? normalizedRingEntries : [],
      bloodSkills: buildSkillList(rawSkills, {
        basePath: [...bloodlineBasePath, '技能'],
        category: '血脉散技',
        scope: 'blood_skill',
        渲染快照,
        空表不造占位: true,
      }),
      bloodPassives: buildSkillList(rawPassives, {
        basePath: [...bloodlineBasePath, '被动'],
        category: '血脉特性',
        scope: 'blood_passive',
        渲染快照,
        空表不造占位: true,
      }),
      sealLv,
      core,
      lifeFire: !!deepGet(activeChar, '血脉之力.生命之火', false),
      bloodline: bloodline === '无' ? '未觉醒血脉' : bloodline,
      是金龙王,
      是银龙王,
      使用封印界面,
    };
  }

  function 构建血脉状态文本_桥接(血脉配置 = {}) {
    const 血脉名 = toText((血脉配置 && (血脉配置.bloodline || 血脉配置.name)) || '', '血脉');
    if (血脉配置 && 血脉配置.使用封印界面) return `${血脉名} / ${toText(血脉配置.sealLv, '0')}层`;
    const 主动数量 = Array.isArray(血脉配置 && 血脉配置.bloodSkills) ? 血脉配置.bloodSkills.length : 0;
    const 被动数量 = Array.isArray(血脉配置 && 血脉配置.bloodPassives) ? 血脉配置.bloodPassives.length : 0;
    const 气血魂环数量 = Array.isArray(血脉配置 && 血脉配置.魂环) ? 血脉配置.魂环.length : 0;
    return [血脉名, `主动${主动数量}`, `被动${被动数量}`, 气血魂环数量 ? `血环${气血魂环数量}` : '']
      .filter(Boolean)
      .join(' / ');
  }

  function getPrimaryFactionEntry(snapshot) {
    const preferredName = toText(
      deepGet(
        snapshot,
        'locationData.掌控势力',
        snapshot && snapshot.势力 && snapshot.势力[0] ? snapshot.势力[0][0] : '',
      ),
      snapshot && snapshot.势力 && snapshot.势力[0] ? snapshot.势力[0][0] : '',
    );
    const fallbackEntry =
      snapshot && Array.isArray(snapshot.orgEntries) && snapshot.orgEntries.length ? snapshot.orgEntries[0] : ['', {}];
    const matchedEntry =
      snapshot && Array.isArray(snapshot.orgEntries)
        ? snapshot.orgEntries.find(([name]) => name === preferredName) || fallbackEntry
        : fallbackEntry;
    return {
      name: toText(matchedEntry && matchedEntry[0], preferredName || '未知'),
      data: matchedEntry && matchedEntry[1] ? matchedEntry[1] : {},
    };
  }

  function buildFactionRelationMeta(relName, relData) {
    const safeName = toText(relName, '未知势力');
    const safeRelData = relData && typeof relData === 'object' ? relData : {};
    const attitude = toText(deepGet(safeRelData, '态度', deepGet(safeRelData, '关系', '未知')), '未知');
    const detailParts = safeEntries(safeRelData)
      .filter(([key]) => !['态度', '关系'].includes(toText(key, '')))
      .map(([key, value]) => {
        if (value && typeof value === 'object') {
          const detailCount = safeEntries(value).length;
          return `${toText(key, '关系项')} ${detailCount}项`;
        }
        const textValue = toText(value, '');
        return textValue ? `${toText(key, '关系项')} ${textValue}` : toText(key, '关系项');
      })
      .filter(Boolean);
    return {
      name: safeName,
      attitude,
      desc: detailParts.length ? `${attitude} ｜ ${detailParts.join(' / ')}` : attitude,
      className: /敌对|死敌|仇视|战争/.test(attitude)
        ? 'warn'
        : /同盟|盟友|友好|合作|生死同盟/.test(attitude)
          ? 'highlight'
          : '',
    };
  }

  function buildFactionRelationEditorGrid(orgName, orgData, options = {}) {
    const { max = 6, emptyTitle = '暂无势力关系', emptyDesc = '当前未记录对外关系。' } = options || {};
    const safeOrgName = toText(orgName, '').trim();
    const relationEntries = safeEntries(deepGet(orgData, '关系', {})).slice(0, Math.max(1, max));
    if (!relationEntries.length) {
      return `<div class="relation-card"><b>${htmlEscape(emptyTitle)}</b><span>${htmlEscape(emptyDesc)}</span></div>`;
    }
    return `
        <div class="mvu-detail-card-grid mvu-detail-card-grid--two">
          ${relationEntries
            .map(([relationName, relationData]) => {
              const safeRelData = relationData && typeof relationData === 'object' ? relationData : {};
              const relationMeta = buildFactionRelationMeta(relationName, safeRelData);
              const relationField = Object.prototype.hasOwnProperty.call(safeRelData, '态度')
                ? '态度'
                : Object.prototype.hasOwnProperty.call(safeRelData, '关系')
                  ? '关系'
                  : '态度';
              const relationValue = toText(
                deepGet(safeRelData, relationField, relationMeta.attitude),
                relationMeta.attitude,
              );
              const detailText = safeEntries(safeRelData)
                .filter(([key]) => !['态度', '关系'].includes(toText(key, '')))
                .map(([key, value]) => {
                  if (value && typeof value === 'object')
                    return `${toText(key, '关系项')} ${safeEntries(value).length}项`;
                  const textValue = toText(value, '');
                  return textValue ? `${toText(key, '关系项')} ${textValue}` : '';
                })
                .filter(Boolean)
                .join(' / ');
              const editableValue = safeOrgName
                ? makeInlineEditableValue(relationValue, {
                    path: ['org', safeOrgName, '关系', relationName, relationField],
                    kind: 'string',
                    rawValue: relationValue,
                  })
                : htmlEscape(relationValue);
              return `
              <div class="archive-tile mvu-detail-relation-tile">
                <b>${htmlEscape(relationMeta.name)}</b>
                <span class="mvu-detail-relation-value">${editableValue}</span>
                ${detailText ? `<div class="mvu-detail-relation-note">${htmlEscape(detailText)}</div>` : ''}
              </div>
            `;
            })
            .join('')}
        </div>
      `;
  }

  function buildFactionRelationSummary(orgData, max = 3) {
    return safeEntries(deepGet(orgData, '关系', {}))
      .slice(0, Math.max(1, max))
      .map(([name, relData]) => {
        const meta = buildFactionRelationMeta(name, relData);
        return `${meta.name}:${meta.attitude}`;
      })
      .join(' / ');
  }

  function getPrimaryFactionPowerStats(snapshot) {
    const preferredName = toText(
      deepGet(
        snapshot,
        'locationData.掌控势力',
        snapshot && snapshot.势力 && snapshot.势力[0] ? snapshot.势力[0][0] : '',
      ),
      snapshot && snapshot.势力 && snapshot.势力[0] ? snapshot.势力[0][0] : '',
    );
    const fallbackEntry =
      snapshot && Array.isArray(snapshot.orgEntries) && snapshot.orgEntries.length ? snapshot.orgEntries[0] : ['', {}];
    const matchedEntry =
      snapshot && Array.isArray(snapshot.orgEntries)
        ? snapshot.orgEntries.find(([name]) => name === preferredName) || fallbackEntry
        : fallbackEntry;
    const matchedName = toText(matchedEntry && matchedEntry[0], preferredName || '未知');
    const matchedData = matchedEntry && matchedEntry[1] ? matchedEntry[1] : {};
    return {
      name: matchedName,
      limit: toNumber(deepGet(matchedData, '战力统计.极限斗罗', 0), 0),
      super: toNumber(deepGet(matchedData, '战力统计.超级斗罗', 0), 0),
      title: toNumber(deepGet(matchedData, '战力统计.封号斗罗', 0), 0),
    };
  }

  function collectPendingRequests(activeChar, sd) {
    const result = [];
    const push = text => {
      if (text) result.push(text);
    };

    const interact = activeChar && activeChar.互动请求;
    if (interact && toText(interact.动作, '无') !== '无') {
      push(`互动：${toText(interact.目标人物, '未知对象')} / ${toText(interact.动作, '互动')}`);
    }

    return result;
  }

  function 提取叙事句段(source = '') {
    const 原文 = String(source || '')
      .replace(/\s+/g, ' ')
      .trim();
    if (!原文) return [];
    return 原文
      .split(/[。！？!?；;\n]+/)
      .map(segment => String(segment || '').trim())
      .filter(Boolean);
  }

  function 构建叙事三段文案({ 现象 = '', 结果 = '', 钩子 = '', 回退 = '暂无记录' } = {}) {
    const 现象文本 = toText(现象, '').trim() || 回退;
    const 片段 = [];
    const 结果文本 = toText(结果, '').trim();
    const 线索文本 = toText(钩子, '').trim();
    if (结果文本) 片段.push(`影响：${结果文本}`);
    if (线索文本) 片段.push(`线索：${线索文本}`);
    return 片段.length ? `${现象文本} ｜ ${片段.join(' ｜ ')}` : 现象文本;
  }

  function 构建安排文案({ 内容 = '', 时间 = '', 状态 = '', 线索 = '', 回退 = '暂无安排' } = {}) {
    const 内容文本 = toText(内容, '').trim() || 回退;
    const 片段 = [];
    const 时间文本 = toText(时间, '').trim();
    const 状态文本 = toText(状态, '').trim();
    const 线索文本 = toText(线索, '').trim();
    if (时间文本) 片段.push(`时间：${时间文本}`);
    if (状态文本) 片段.push(`状态：${状态文本}`);
    if (线索文本) 片段.push(`线索：${线索文本}`);
    return 片段.length ? `${内容文本} ｜ ${片段.join(' ｜ ')}` : 内容文本;
  }

  function 归一化情报叙事文案(source = '') {
    const 展示文本 = 格式化情报展示文本(source, '暂无记录');
    const 句段 = 提取叙事句段(展示文本);
    return 构建叙事三段文案({
      现象: 句段[0] || 展示文本,
      结果: 句段[1] || '情报已入档',
      钩子: 句段[2] || '建议继续核实线索来源',
      回退: '暂无记录',
    });
  }

  function buildRecentNewsSummary(snapshot, options = {}) {
    const { seqLimit = 2, intelLimit = 2 } = options || {};
    const globalNews = (snapshot.timelineEntries || [])
      .filter(([, item]) => /done|handled|完成|已处理/.test(toText(deepGet(item, '状态', ''), '')))
      .sort((a, b) => toNumber(deepGet(b[1], '触发tick', 0), 0) - toNumber(deepGet(a[1], '触发tick', 0), 0))
      .slice(0, Math.max(1, seqLimit))
      .map(([key, item]) => ({
        title: `全局 / ${key}`,
        事件名: key,
        事件: toText(deepGet(item, '事件', ''), '暂无记录'),
        状态: toText(deepGet(item, '状态', ''), ''),
        触发tick: toNumber(deepGet(item, '触发tick', 0), 0),
        影响: toText(deepGet(item, '结果', deepGet(item, '影响', '')), ''),
        后续: toText(deepGet(item, '下一步', deepGet(item, '后续', deepGet(item, '线索', ''))), ''),
        desc: 构建叙事三段文案({
          现象: toText(deepGet(item, '事件', ''), '暂无记录'),
          结果: toText(deepGet(item, '结果', deepGet(item, '影响', '')), ''),
          钩子: toText(deepGet(item, '下一步', deepGet(item, '后续', deepGet(item, '线索', ''))), ''),
          回退: '暂无记录',
        }),
      }));
    const personalNews = (snapshot.unlockedKnowledges || [])
      .slice(-Math.max(1, intelLimit))
      .reverse()
      .map((text, index) => ({
        title: `个人 / 见闻 ${index + 1}`,
        事件名: `见闻 ${index + 1}`,
        事件: 格式化情报展示文本(text, '暂无记录'),
        状态: '已收录',
        desc: 归一化情报叙事文案(text),
      }));
    return {
      globalNews,
      personalNews,
      cards: globalNews.concat(personalNews).length
        ? globalNews.concat(personalNews)
        : [{ title: '近期见闻', desc: '暂无新的全局或个人见闻。' }],
      summary: globalNews[0]
        ? globalNews[0].desc
        : personalNews[0]
          ? personalNews[0].desc
          : '暂无近期见闻',
    };
  }

  function buildRecentPlanSummary(snapshot, options = {}) {
    const { worldLimit = 2, recordLimit = 2 } = options || {};
    const 当前tick = Math.max(0, toNumber(deepGet(snapshot, 'rootData.world.时间.tick', 0), 0));
    const worldPlans = (snapshot.timelineEntries || [])
      .filter(([, item]) => {
        const 状态文本 = toText(deepGet(item, '状态', 'pending'), 'pending');
        const 触发tick = toNumber(deepGet(item, '触发tick', 0), 0);
        return 触发tick > 当前tick && !/done|handled|完成|已处理|取消|cancel/i.test(状态文本);
      })
      .sort((a, b) => toNumber(deepGet(a[1], '触发tick', 0), 0) - toNumber(deepGet(b[1], '触发tick', 0), 0))
      .slice(0, Math.max(1, worldLimit))
      .map(([name, item]) => {
        const 触发tick = toNumber(deepGet(item, '触发tick', 0), 0);
        const 剩余tick = Math.max(0, 触发tick - 当前tick);
        const 剩余天 = Math.floor((剩余tick * 10) / (24 * 60));
        const 剩余小时 = Math.floor(((剩余tick * 10) % (24 * 60)) / 60);
        const 距离文本 =
          剩余天 > 0
            ? `约${剩余天}天${剩余小时 > 0 ? `${剩余小时}小时` : ''}后`
            : 剩余小时 > 0
              ? `约${剩余小时}小时后`
              : '即将触发';
        const 地点文本 = toText(deepGet(item, '地点', ''), '');
        const 后续文本 = toText(deepGet(item, '后续', ''), '');
        const 有效地点 = 地点文本 && !/^(无|未知|待定)$/.test(地点文本);
        const 事件文本 = toText(deepGet(item, '事件', '无'), '无');
        const 状态文本 = toText(deepGet(item, '状态', 'pending'), 'pending');
        return {
          title: `世界 / ${name}`,
          事件名: name,
          事件: 事件文本,
          触发tick,
          时间摘要: 距离文本,
          地点: 地点文本,
          状态: 状态文本,
          后续: 后续文本,
          desc: 构建安排文案({
            内容: 事件文本,
            时间: `${formatTickToCalendarDateText(触发tick)}（${距离文本}）`,
            状态: 状态文本,
            线索: [有效地点 ? `地点：${地点文本}` : '', 后续文本].filter(Boolean).join('；'),
            回退: '暂无安排',
          }),
        };
      });
    const personalPlans = (snapshot.recordEntries || [])
      .filter(
        ([, item]) =>
          toText(item && item['状态'], '进行中') !== '已完成' && toText(item && item['状态'], '进行中') !== '已放弃',
      )
      .slice(0, Math.max(1, recordLimit))
      .map(([name, item]) => ({
        title: `个人 / ${name}`,
        事件名: name,
        事件: toText(item && item['描述'], '无描述'),
        状态: toText(item && item['状态'], '进行中'),
        进度: Math.max(0, Math.min(100, toNumber(item && item['当前进度'], 0))),
        后续: toText(item && (item['下一步'] || item['后续'] || item['建议']), ''),
        desc: 构建安排文案({
          内容: toText(item && item['描述'], '无描述'),
          状态: `${toText(item && item['状态'], '进行中')} · ${Math.max(0, Math.min(100, toNumber(item && item['当前进度'], 0)))}%`,
          线索: toText(item && (item['下一步'] || item['后续'] || item['建议']), ''),
          回退: '暂无安排',
        }),
      }));
    return {
      worldPlans,
      personalPlans,
      cards: worldPlans.concat(personalPlans).length
        ? worldPlans.concat(personalPlans)
        : [{ title: '近期安排', desc: '暂无待处理的世界日程或个人任务。' }],
      summary: worldPlans[0] ? worldPlans[0].desc : personalPlans[0] ? personalPlans[0].desc : '暂无近期安排',
    };
  }

  function 推断世界核心阶段(snapshot = {}) {
    const 当前tick = toNumber(deepGet(snapshot, 'rootData.world.时间.tick', 0), 0);
    const 时间线条目 = (
      Array.isArray(snapshot.timelineEntries)
        ? snapshot.timelineEntries
        : safeEntries(deepGet(snapshot, 'rootData.world.时间线', {}))
    ).filter(([, 条目]) => 条目 && typeof 条目 === 'object' && !Array.isArray(条目));
    const 未完成条目 = 时间线条目
      .filter(([, 条目]) => {
        const 状态文本 = toText(deepGet(条目, '状态', 'pending'), 'pending');
        const 触发tick = toNumber(deepGet(条目, '触发tick', 0), 0);
        return 触发tick >= 当前tick && !/done|handled|完成|已处理|取消|cancel/i.test(状态文本);
      })
      .sort((左项, 右项) => toNumber(deepGet(左项[1], '触发tick', 0), 0) - toNumber(deepGet(右项[1], '触发tick', 0), 0))[0];
    if (未完成条目) return `待触发：${toText(未完成条目[0], '世界事件')}`;
    const 已推进条目 = 时间线条目
      .filter(([, 条目]) => {
        const 状态文本 = toText(deepGet(条目, '状态', ''), '');
        const 触发tick = toNumber(deepGet(条目, '触发tick', 0), 0);
        return /done|handled|完成|已处理/i.test(状态文本) || 触发tick <= 当前tick;
      })
      .sort((左项, 右项) => toNumber(deepGet(右项[1], '触发tick', 0), 0) - toNumber(deepGet(左项[1], '触发tick', 0), 0))[0];
    return 已推进条目 ? `已推进：${toText(已推进条目[0], '世界事件')}` : '未记录';
  }

  function 格式化安排短摘要(安排 = {}, 回退 = '暂无安排') {
    const 标题文本 = toText(安排.title, '')
      .replace(/^世界\s*\/\s*/, '')
      .replace(/^个人\s*\/\s*/, '')
      .trim();
    const 事件文本 = toText(安排.事件, toText(安排.事件名, 标题文本)).trim();
    const 地点文本 = toText(安排.地点, '').trim();
    return (
      [事件文本, toText(安排.时间摘要, '').trim(), 地点文本 && !/^(无|未知|待定)$/.test(地点文本) ? 地点文本 : '']
        .filter(Boolean)
        .join(' · ') || 回退
    );
  }

  function 收集本地商店商品样本(locationData = {}) {
    const 样本 = [];
    safeEntries(deepGet(locationData, '商店', {})).forEach(([商店名, 商店数据]) => {
      safeEntries(deepGet(商店数据, '库存', {})).forEach(([商品名, 商品数据]) => {
        if (!商品数据 || typeof 商品数据 !== 'object') return;
        样本.push({
          商店名: toText(商店名, '未知商店'),
          商品名: toText(商品名, '未知商品'),
          库存: Math.max(0, toNumber(商品数据 && 商品数据['库存'], 0)),
          价格: Math.max(0, toNumber(商品数据 && 商品数据['价格'], 0)),
        });
      });
    });
    return 样本;
  }

  function 计算本地供给指标(locationData = {}) {
    const 商品样本 = 收集本地商店商品样本(locationData);
    if (!商品样本.length) return '无供给';
    const 总库存 = 商品样本.reduce((总和, 项) => 总和 + Math.max(0, toNumber(项 && 项['库存'], 0)), 0);
    const 缺货数 = 商品样本.filter(项 => Math.max(0, toNumber(项 && 项['库存'], 0)) <= 0).length;
    const 均值库存 = 总库存 / Math.max(1, 商品样本.length);
    const 缺货占比 = 缺货数 / Math.max(1, 商品样本.length);
    if (总库存 <= 0 || 缺货占比 >= 0.55 || 均值库存 < 1.5) return '紧缺';
    if (缺货占比 >= 0.3 || 均值库存 < 3.5) return '偏紧';
    if (均值库存 >= 9) return '充裕';
    return '平衡';
  }

  function 计算本地价格带指标(locationData = {}) {
    const 商品样本 = 收集本地商店商品样本(locationData);
    const 价格样本 = 商品样本.map(项 => Math.max(0, toNumber(项 && 项['价格'], 0))).filter(价格 => 价格 > 0);
    if (!价格样本.length) return '无';
    const 均价 = 价格样本.reduce((总和, 价格) => 总和 + 价格, 0) / Math.max(1, 价格样本.length);
    if (均价 < 100000) return '低价';
    if (均价 < 2000000) return '中价';
    if (均价 < 50000000) return '高价';
    return '超高价';
  }

  function 提取最近成交影响指标(系统播报 = '') {
    const 播报文本 = toText(系统播报, '');
    const 标签匹配 = Array.from(播报文本.matchAll(/\[(买入热|卖出热|竞拍热|兑换热|市场波动)\]/g))
      .map(match => toText(match && match[1], '').trim())
      .filter(Boolean);
    if (标签匹配.length) return 标签匹配[标签匹配.length - 1];
    return '平稳';
  }

  function clampMarketMultiplier(value) {
    const 数值 = Number(value);
    if (!Number.isFinite(数值)) return 1;
    return Math.max(0.7, Math.min(1.6, 数值));
  }

  function 获取市场供给倍率(供给 = '平衡') {
    const 文本 = toText(供给, '平衡');
    if (文本 === '紧缺') return 1.25;
    if (文本 === '偏紧') return 1.12;
    if (文本 === '充裕') return 0.92;
    return 1;
  }

  function 获取市场经济倍率(经济状况 = '未知') {
    const 文本 = toText(经济状况, '未知');
    if (文本 === '繁荣') return 0.95;
    if (文本 === '萧条') return 1.12;
    return 1;
  }

  function 获取市场趋势倍率(最近成交影响 = '平稳') {
    const 文本 = toText(最近成交影响, '平稳');
    if (文本 === '买入热') return 1.08;
    if (文本 === '卖出热') return 0.92;
    if (文本 === '竞拍热') return 1.12;
    if (文本 === '市场波动') return 1.06;
    return 1;
  }

  function 构建市场倍率说明(市场派生 = {}) {
    const 标签 = [];
    const 供给 = toText(市场派生.本地供给, '平衡');
    const 经济 = toText(市场派生.经济状况, '未知');
    const 趋势 = toText(市场派生.最近成交影响, '平稳');
    if (供给 === '紧缺') 标签.push('紧缺上浮');
    else if (供给 === '偏紧') 标签.push('供给偏紧');
    else if (供给 === '充裕') 标签.push('供给充裕');
    if (经济 === '繁荣') 标签.push('繁荣回落');
    else if (经济 === '萧条') 标签.push('萧条上浮');
    if (趋势 === '买入热') 标签.push('买入热上浮');
    else if (趋势 === '卖出热') 标签.push('卖出热回落');
    else if (趋势 === '竞拍热') 标签.push('竞拍热');
    else if (趋势 === '市场波动') 标签.push('市场波动');
    return 标签.join(' / ') || '平稳';
  }

  function 构建市场派生模型(locationData = {}, rootData = null) {
    const 本地供给 = 计算本地供给指标(locationData);
    const 价格带 = 计算本地价格带指标(locationData);
    const 最近成交影响 = 提取最近成交影响指标(deepGet(rootData, 'sys.系统播报', ''));
    const 经济状况 = toText(locationData && locationData['经济状况'], '未知');
    const 供给倍率 = 获取市场供给倍率(本地供给);
    const 经济倍率 = 获取市场经济倍率(经济状况);
    const 趋势倍率 = 获取市场趋势倍率(最近成交影响);
    const 买入倍率 = clampMarketMultiplier(供给倍率 * 经济倍率 * 趋势倍率);
    const 卖出倍率 = clampMarketMultiplier(供给倍率 * 趋势倍率);
    const 成交率修正 = Math.round((1 - 买入倍率) * 35);
    const 派生 = {
      本地供给,
      价格带,
      最近成交影响,
      经济状况,
      供给倍率,
      经济倍率,
      趋势倍率,
      买入倍率,
      卖出倍率,
      成交率修正,
    };
    派生.说明 = 构建市场倍率说明(派生);
    return 派生;
  }

  function 判断角色情报可见(snapshotLike = {}, targetChar = {}) {
    if (!targetChar || typeof targetChar !== 'object') return false;
    const root = snapshotLike.rootData && typeof snapshotLike.rootData === 'object' ? snapshotLike.rootData : {};
    const activeNameText = toText(snapshotLike.activeName, '');
    const activeKey = resolveSnapshotCharKey(snapshotLike, activeNameText);
    const activeChar = snapshotLike.activeChar || (activeKey ? deepGet(root, ['char', activeKey], {}) : {});
    if (activeChar && activeChar === targetChar) return true;
    const targetName = toText(targetChar.name || targetChar.base?.name, '');
    const targetKey = resolveSnapshotCharKey(snapshotLike, targetName);
    const history = targetName
      ? deepGet(activeChar, ['战斗历史', targetName], deepGet(activeChar, ['战斗历史', targetKey], null))
      : null;
    if (history && toNumber(history.次数, 0) > 0) return true;
    const activeRep = toNumber(deepGet(activeChar, '社交.声望', 0), 0);
    const targetRep = toNumber(deepGet(targetChar, '社交.声望', 0), 0);
    if (targetRep >= 5000 && activeRep < Math.max(5000, Math.floor(targetRep * 0.35))) return false;
    if (targetRep < 5000) {
      const rel = targetKey
        ? deepGet(activeChar, ['社交', '关系', targetKey], deepGet(activeChar, ['社交', '关系', targetName], null))
        : null;
      const relation = toText(rel && rel.关系, '陌生');
      const relationRoute = toText(rel && rel.关系路线, '');
      const favor = toNumber(rel && rel.好感度, 0);
      if (/敌对|死敌|宿敌|对手|仇敌/.test(`${relation}${relationRoute}`)) return true;
      return favor >= 30 && !/陌生|普通|路人/.test(relation);
    }
    return activeRep >= Math.floor(targetRep * 0.35);
  }

  function buildSnapshot(sd) {
    const rawRootData = sd && typeof sd === 'object' ? sd : {};
    const contextMeta = getCurrentChatContextMeta();
    const runtimeReady = true;
    sd = rawRootData;
    const [activeName, activeChar] = resolveActiveCharacter(sd || {});
    const currentLoc = toText(deepGet(activeChar, '状态.位置', '未知'), '未知')
      .replace(/^斗罗大陆-/, '')
      .replace(/^斗灵大陆-/, '');
    const locationInfo = resolveLocationData(sd, currentLoc);
    const locationData = locationInfo.data || {};
    const storeNames = safeEntries(locationData && locationData.商店).map(([name]) => name);
    const dynamicLocationNames = safeEntries(deepGet(sd, 'world.动态地点', {})).map(([name]) => name);
    const 时间线条目 = safeEntries(deepGet(sd, 'world.时间线', {}))
      .filter(([, 条目]) => 条目 && typeof 条目 === 'object' && !Array.isArray(条目))
      .sort((左项, 右项) => {
        const 左tick = toNumber(deepGet(左项[1], '触发tick', 0), 0);
        const 右tick = toNumber(deepGet(右项[1], '触发tick', 0), 0);
        if (左tick !== 右tick) return 左tick - 右tick;
        return toText(左项[0], '').localeCompare(toText(右项[0], ''), 'zh-Hans-CN');
      });
    const timelineEntries = 时间线条目;
    const factions = safeEntries(deepGet(activeChar, '社交.势力', {}));
    const relations = safeEntries(deepGet(activeChar, '社交.关系', {})).sort(
      (a, b) => toNumber(deepGet(b[1], '好感度', 0), 0) - toNumber(deepGet(a[1], '好感度', 0), 0),
    );
    const unlockedKnowledges = Array.isArray(activeChar && activeChar.已掌握情报) ? activeChar.已掌握情报 : [];
    const inventoryEntries = safeEntries(activeChar && activeChar.背包).map(([name, item]) => [
      name,
      合并物品定义与状态_桥接(sd, name, item),
    ]);
    const flagEntries = [];
    if (deepGet(sd, 'world.兽潮已触发', false)) flagEntries.push(['兽潮已触发', true]);
    if (判断传灵塔万年魂灵开放_桥接(sd)) flagEntries.push(['传灵塔万年魂灵开放', true]);
    const orgEntries = safeEntries(sd && sd.org).sort((a, b) => {
      const aFav = factions.some(([name]) => name === a[0]) ? 1 : 0;
      const bFav = factions.some(([name]) => name === b[0]) ? 1 : 0;
      if (aFav !== bFav) return bFav - aFav;
      return toNumber(deepGet(b[1], '影响力', 0), 0) - toNumber(deepGet(a[1], '影响力', 0), 0);
    });

    const spiritEntries = 取角色武魂条目_桥接(activeChar);
    const 渲染快照 = { rootData: sd, activeName, activeChar };
    const primarySpirit = spiritEntries[0]
      ? buildSpiritConfig(spiritEntries[0][0], spiritEntries[0][1], '第1武魂详细页', '第1武魂', 'cyan', [
          'char',
          activeName,
          spiritEntries[0][0],
        ], 渲染快照)
      : buildSpiritConfig('第1武魂', {}, '第1武魂详细页', '第1武魂', 'cyan', [], 渲染快照);
    const secondarySpirit = spiritEntries[1]
      ? buildSpiritConfig(spiritEntries[1][0], spiritEntries[1][1], '第2武魂详细页', '第2武魂', 'gold', [
          'char',
          activeName,
          spiritEntries[1][0],
        ], 渲染快照)
      : null;
    const bloodline = buildBloodlineConfig(activeChar || {}, activeName, ['char', activeName, '血脉之力'], 渲染快照);

    // --- 收集额外能力与功法，放到外层给生命图谱使用 ---
    const safeRecords = obj => {
      return Object.entries(obj || {})
        .filter(([k, v]) => k !== '无' && typeof v === 'object' && v !== null)
        .map(([k, v]) => ({
          recordKey: k,
          name: k,
          ...v,
        }));
    };
    const extraSkills = [];
    const artSkillNameSet = new Set(
      safeEntries(deepGet(activeChar, '功法', {}))
        .map(([name]) => toText(name, '').trim())
        .filter(Boolean),
    );
    safeRecords(deepGet(activeChar, '功法', {})).forEach(art => {
      extraSkills.push({
        category: '功法绝学',
        name: art.name,
        level: `Lv.${art.lv || 1} / ${toText(art.境界, '未入门')}`,
        desc: toText(art.描述, '暂无描述'),
        preview: '',
      });
    });
    if (bloodline.valid) {
      safeRecords(deepGet(activeChar, '血脉之力.技能', {})).forEach(skill => {
        extraSkills.push({
          category: '血脉散技',
          name: skill.name,
          level: toText(skill.状态, '已掌握'),
          desc: toText(skill.描述 || skill.效果描述 || skill.effectDesc, '无说明'),
          preview: buildSkillDesignerPreviewKey({
            path: ['char', activeName, '血脉之力', '技能', skill.recordKey || skill.name],
            label: toText(skill.name, skill.recordKey || '血脉散技'),
            category: '血脉散技',
            scope: 'blood_skill',
          }),
        });
      });
      safeRecords(deepGet(activeChar, '血脉之力.被动', {})).forEach(skill => {
        extraSkills.push({
          category: '血脉特性',
          name: skill.name,
          level: toText(skill.状态, '已固化'),
          desc: toText(skill.描述 || skill.效果描述 || skill.effectDesc, '无说明'),
          preview: buildSkillDesignerPreviewKey({
            path: ['char', activeName, '血脉之力', '被动', skill.recordKey || skill.name],
            label: toText(skill.name, skill.recordKey || '血脉特性'),
            category: '血脉特性',
            scope: 'blood_passive',
          }),
        });
      });
    }
    safeRecords(deepGet(activeChar, '武魂融合技', {})).forEach(fusion => {
      const fusionName = toText(fusion['名称'], fusion.name || fusion.recordKey || '武魂融合技');
      extraSkills.push({
        category: '武魂融合技',
        name: fusionName,
        level: `搭档: ${toText(fusion['融合对象'], '未知')}`,
        desc: toText(deepGet(fusion, '技能数据.描述', '无'), '爆发技'),
        preview: buildSkillDesignerPreviewKey({
          path: ['char', activeName, '武魂融合技', fusion.recordKey || fusionName, '技能数据'],
          label: toText(fusionName, fusion.recordKey || '武魂融合技'),
          category: '武魂融合技',
          scope: '武魂融合技',
        }),
      });
    });
    safeRecords(deepGet(activeChar, '自创魂技', {})).forEach(abi => {
      if (artSkillNameSet.has(toText(abi.recordKey || abi.name, '').trim())) return;
      extraSkills.push({
        category: '自创魂技',
        name: abi.name,
        level: '自创',
        desc: toText(abi.效果描述 || abi.战斗摘要?.一句话定位, '暂无描述'),
        preview: buildSkillDesignerPreviewKey({
          path: ['char', activeName, '自创魂技', abi.recordKey || abi.name],
          label: toText(abi.name, abi.recordKey || '自创魂技'),
          category: '自创魂技',
          scope: '自创魂技',
        }),
      });
    });

    const nextNodeCandidates = [
      locationInfo.name,
      currentLoc,
      toText(deepGet(sd, 'world.拍卖.地点', ''), ''),
      ...storeNames,
      ...safeEntries(deepGet(sd, 'world.地点', {})).map(([name]) => name),
      ...dynamicLocationNames,
    ].filter(Boolean);

    const mapNodeLabels = [];
    nextNodeCandidates.forEach(name => {
      if (!mapNodeLabels.includes(name)) mapNodeLabels.push(name);
    });

    const recentTitles = safeEntries(deepGet(activeChar, '社交.称号', {})).map(([name]) => name);
    const titleEntries = safeEntries(deepGet(activeChar, '社交.称号', {}));
    const recordEntries = safeEntries(deepGet(activeChar, '我的任务', {}));
    const conditionEntries = safeEntries(deepGet(activeChar, '属性.状态效果', {}));
    const 原始魂骨表 = deepGet(activeChar, '魂骨', {});
    const soulBoneEntries = [
      ...常规魂骨槽位列表_桥接,
      ...外附魂骨槽位列表_桥接,
      ...safeEntries(原始魂骨表)
        .map(([槽位]) => 槽位)
        .filter(槽位 => ![...常规魂骨槽位列表_桥接, ...外附魂骨槽位列表_桥接].includes(槽位)),
    ].map(槽位 => [槽位, deepGet(原始魂骨表, 槽位, {})]);
    const artEntries = safeEntries(deepGet(activeChar, '功法', {})).sort(
      (a, b) => toNumber(deepGet(b[1], 'lv', 0), 0) - toNumber(deepGet(a[1], 'lv', 0), 0),
    );
    const customSkillEntries = safeEntries(deepGet(activeChar, '自创魂技', {})).filter(
      ([name]) => !artSkillNameSet.has(toText(name, '').trim()),
    );
    const combatHistoryEntries = safeEntries(deepGet(activeChar, '战斗历史', {})).sort(
      (a, b) => toNumber(deepGet(b[1], '最近tick', 0), 0) - toNumber(deepGet(a[1], '最近tick', 0), 0),
    );
    const pendingRequests = collectPendingRequests(activeChar || {}, sd || {});
    const bestiaryEntries = safeEntries(deepGet(sd, 'world.图鉴', {}));
    const forestKilledAge = toNumber(deepGet(sd, 'world.累计击杀年限', 0), 0);
    const 任务进行中列表 = recordEntries.filter(
      ([, item]) =>
        item &&
        typeof item === 'object' &&
        !['已完成', '已放弃', '失败', '已失败'].includes(toText(item && item['状态'], '进行中')),
    );
    const 当前任务聚焦条目 = 任务进行中列表[0] || recordEntries[0] || null;
    const 当前任务名称 = 当前任务聚焦条目 ? toText(当前任务聚焦条目[0], '暂无任务') : '暂无任务';
    const 当前任务数据 =
      当前任务聚焦条目 && 当前任务聚焦条目[1] && typeof 当前任务聚焦条目[1] === 'object' ? 当前任务聚焦条目[1] : {};
    const 当前任务进度 = 当前任务聚焦条目
      ? `${Math.max(0, Math.min(100, toNumber(当前任务数据 && 当前任务数据['当前进度'], 0)))}%`
      : '--';
    const 图鉴聚焦条目 =
      (bestiaryEntries || [])
        .filter(([, item]) => item && typeof item === 'object')
        .sort((a, b) => {
          const aData = a[1] || {};
          const bData = b[1] || {};
          const aLevel = toNumber(aData && aData['对标等级'], 0);
          const bLevel = toNumber(bData && bData['对标等级'], 0);
          if (aLevel !== bLevel) return bLevel - aLevel;
          return toText(a[0], '').localeCompare(toText(b[0], ''), 'zh-Hans-CN');
        })[0] || null;
    const 图鉴聚焦名称 = 图鉴聚焦条目 ? toText(图鉴聚焦条目[0], '暂无') : '暂无';
    const 图鉴聚焦类型 = 图鉴聚焦条目 ? toText(deepGet(图鉴聚焦条目, '1.类型', '怪物'), '怪物') : '无';
    const 图鉴聚焦规格 = 图鉴聚焦条目
      ? [
          toText(deepGet(图鉴聚焦条目, '1.年限档', ''), ''),
          toText(deepGet(图鉴聚焦条目, '1.物种品质', ''), ''),
          toText(deepGet(图鉴聚焦条目, '1.常见级别', ''), ''),
          toText(deepGet(图鉴聚焦条目, '1.常见系别', ''), ''),
        ].filter(Boolean).join(' / ') || '未标注'
      : '--';
    const 图鉴标准技能数 = 图鉴聚焦条目 ? safeEntries(deepGet(图鉴聚焦条目, '1.标准技能', {})).length : 0;
    const pendingSoulRing = buildPendingSoulRingState({ rootData: sd, activeChar, activeName });
    const mapData = sd && sd.map && typeof sd.map === 'object' ? sd.map : {};
    const sheepSnapshot =
      window.__sheepMapSnapshot && typeof window.__sheepMapSnapshot === 'object' ? window.__sheepMapSnapshot : null;
    const normalizeMapEntries = source => {
      if (Array.isArray(source)) {
        return source
          .map(item => {
            if (Array.isArray(item) && item.length >= 2) {
              const key = toText(item[0], '').trim();
              const value = item[1] && typeof item[1] === 'object' ? item[1] : {};
              return key ? [key, value] : null;
            }
            if (item && typeof item === 'object') {
              const key = toText(item.name || item.loc || item.id, '').trim();
              return key ? [key, item] : null;
            }
            return null;
          })
          .filter(entry => entry && entry[0]);
      }
      if (source && typeof source === 'object') {
        return safeEntries(source);
      }
      return [];
    };
    const normalizeTravelCandidates = source => {
      if (!Array.isArray(source)) return [];
      return source
        .map(item => {
          if (typeof item === 'string') return item.trim();
          if (Array.isArray(item)) return toText(item[0], '').trim();
          if (item && typeof item === 'object') return toText(item.loc || item.name || item.target, '').trim();
          return '';
        })
        .filter(Boolean);
    };
    const mapVisibleNodeEntriesCore = normalizeMapEntries(deepGet(mapData, 'visible_nodes', {}));
    const mapVisibleNodeEntriesSheep = normalizeMapEntries(sheepSnapshot && sheepSnapshot.visibleNodes);
    const mapVisibleNodeEntries = mapVisibleNodeEntriesCore.length
      ? mapVisibleNodeEntriesCore
      : mapVisibleNodeEntriesSheep;
    const mapVisibleDynamicEntriesCore = normalizeMapEntries(deepGet(mapData, 'visible_dynamic_locations', {}));
    const mapVisibleDynamicEntriesSheep = normalizeMapEntries(
      sheepSnapshot && (sheepSnapshot.visibleDynamics || sheepSnapshot.visibleDynamicLocations),
    );
    const mapVisibleDynamicEntries = mapVisibleDynamicEntriesCore.length
      ? mapVisibleDynamicEntriesCore
      : mapVisibleDynamicEntriesSheep;
    const mapAvailableChildMapsCore = deepGet(mapData, 'available_child_maps', {}) || {};
    const mapAvailableChildMapsSheep =
      sheepSnapshot && sheepSnapshot.availableChildMaps && typeof sheepSnapshot.availableChildMaps === 'object'
        ? sheepSnapshot.availableChildMaps
        : {};
    const mapAvailableChildMaps = safeEntries(mapAvailableChildMapsCore).length
      ? mapAvailableChildMapsCore
      : mapAvailableChildMapsSheep;
    const mapTravelCandidatesCore = normalizeTravelCandidates(deepGet(mapData, 'travel_candidates', []));
    const mapTravelCandidatesSheep = normalizeTravelCandidates(sheepSnapshot && sheepSnapshot.travelCandidates);
    const mapTravelCandidates = mapTravelCandidatesCore.length ? mapTravelCandidatesCore : mapTravelCandidatesSheep;
    const mapCurrentFocusCore = deepGet(mapData, 'current_focus', {});
    const mapCurrentFocus =
      mapCurrentFocusCore && typeof mapCurrentFocusCore === 'object'
        ? mapCurrentFocusCore
        : sheepSnapshot && sheepSnapshot.currentFocus && typeof sheepSnapshot.currentFocus === 'object'
          ? sheepSnapshot.currentFocus
          : {};
    const mapCurrentMapId = toText(
      deepGet(
        mapData,
        'current_map_id',
        sheepSnapshot && sheepSnapshot.currentMapId ? sheepSnapshot.currentMapId : 'map_douluo_world',
      ),
      'map_douluo_world',
    );
    const mapZoomHint = toNumber(
      deepGet(
        mapData,
        'current_zoom_hint',
        sheepSnapshot && Number.isFinite(Number(sheepSnapshot.currentZoomHint))
          ? Number(sheepSnapshot.currentZoomHint)
          : 0,
      ),
      0,
    );
    const primaryFaction = factions[0] || null;
    const topRelation = relations[0] || null;
    const questRecordCount = recordEntries.filter(
      ([, item]) => toText(item && item['状态'], '进行中') !== '已放弃',
    ).length;
    const warningText =
      toNumber(deepGet(sd, 'world.偏差值', 0), 0) >= 40
        ? `偏差 ${toNumber(deepGet(sd, 'world.偏差值', 0), 0)} / 高危`
        : deepGet(sd, 'world.兽潮已触发', false)
          ? '兽潮警报 / 已触发'
          : flagEntries.length
            ? `世界状态 ${flagEntries.length} 项`
            : '无';
    const auctionStatus = toText(deepGet(sd, 'world.拍卖.状态', '休市'), '休市');
    const auctionLocation = toText(deepGet(sd, 'world.拍卖.地点', '无'), '无');
    const 市场派生 = 构建市场派生模型(locationData, sd);
    const 本地供给 = 市场派生.本地供给;
    const 价格带 = 市场派生.价格带;
    const 最近成交影响 = 市场派生.最近成交影响;

    const chars = sd && sd.char ? sd.char : {};
    const charEntries = safeEntries(chars);
    const 快照数据 = {
      runtimeReady,
      rawRootData,
      rootData: sd,
      activeName: toText(activeName, contextMeta.name1 || contextMeta.name2 || '当前角色'),
      appearanceMeta: formatAppearanceMeta(deepGet(activeChar, '外貌', {})),
      appearanceText: formatAppearanceText(deepGet(activeChar, '外貌', {})),
      personalityText: toText(deepGet(activeChar, '性格', '未设定'), '未设定'),
      activeChar: activeChar || {},
      currentLoc,
      normalizedLoc: locationInfo.name,
      locationData,
      storeNames,
      dynamicLocationNames,
      timelineEntries,
      latestTimeline: timelineEntries[0] || null,
      势力: factions,
      relations,
      unlockedKnowledges,
      inventoryEntries,
      flagEntries,
      charEntries,
      orgEntries,
      titleEntries,
      recordEntries,
      conditionEntries,
      soulBoneEntries,
      artEntries,
      customSkillEntries,
      combatHistoryEntries,
      primarySpirit,
      secondaryTrack: secondarySpirit || (bloodline.valid ? bloodline : null),
      bloodline,
      mapNodeLabels: mapNodeLabels.slice(0, 4),
      pendingRequests,
      primaryFaction,
      topRelation,
      pendingSoulRing,
      关系分析: deepGet(activeChar, '社交.关系分析', {}),

      questRecordCount,
      当前任务名称,
      当前任务进度,
      图鉴聚焦名称,
      图鉴聚焦类型,
      图鉴聚焦规格,
      图鉴标准技能数,
      recentTitles,
      worldAlert: warningText,
      本地供给,
      价格带,
      最近成交影响,
      市场派生,
      bestiaryEntries,
      forestKilledAge,
      auctionStatus,
      auctionLocation,
      mapData,
      mapCurrentMapId,
      mapZoomHint,
      mapCurrentFocus,
      mapVisibleNodeEntries,
      mapVisibleDynamicEntries,
      mapAvailableChildMaps,
      mapTravelCandidates,
      publicIntel: 判断角色情报可见({ rootData: sd, activeName, activeChar }, activeChar),
      extraSkills,
    };
    return 快照数据;
  }

  function maybeAutoOpenPendingSoulRingPreview(snapshot, options = {}) {
    const pending = buildPendingSoulRingState(snapshot);
    if (!pending || pending.status !== '待选择') {
      if (!pending) lastAutoOpenedPendingSoulRingSignature = '';
      return;
    }
    if (!pending.signature || pending.signature === lastAutoOpenedPendingSoulRingSignature) return;
    lastAutoOpenedPendingSoulRingSignature = pending.signature;
    const shouldPreferFloating = options && options.force !== false;
    openModal(PENDING_SOUL_RING_PREVIEW_KEY, {
      preserveMapDispatchContext: true,
      displayMode: shouldPreferFloating ? 'floating' : undefined,
    });
  }

  async function handlePendingSoulRingGenerate(snapshot, candidateSoulName = '') {
    const pending = buildPendingSoulRingState(snapshot);
    if (!pending) throw new Error('当前没有待处理的魂环生成请求。');
    const wantedSoulName =
      toText(candidateSoulName, '').trim() || toText(deepGet(pending, 'candidates.0.soulName', ''), '').trim();
    if (!wantedSoulName) throw new Error('当前待选魂灵为空。');
    let skillPreviewKey = '';
    let skillLabel = '';
    await mutateStatDataByEditor(
      statData => {
        const charData = deepGet(statData, ['char', pending.charKey], null);
        if (!charData || typeof charData !== 'object') throw new Error('未找到对应角色。');
        const currentPending = deepGet(charData, ['状态', '待选魂环'], null);
        if (!currentPending || typeof currentPending !== 'object') throw new Error('当前待选魂环状态已失效。');
        const spiritSlot = toText(currentPending.武魂槽位, pending.spiritSlot).trim();
        const ringIndex = Math.max(1, toNumber(currentPending.待生成魂环位, pending.ringIndex));
        const spiritData = deepGet(charData, [spiritSlot], null);
        if (!spiritData || typeof spiritData !== 'object') throw new Error('未找到目标武魂槽位。');
        const soulData = deepGet(spiritData, [wantedSoulName], null);
        if (!soulData || typeof soulData !== 'object') throw new Error(`未找到候选魂灵【${wantedSoulName}】。`);
        const ringKey = `第${ringIndex}魂环`;
        if (
          soulData[ringKey] &&
          typeof soulData[ringKey] === 'object' &&
          (toNumber(soulData[ringKey].年限, 0) > 0 || 取魂环魂技条目_桥接(soulData[ringKey]).length > 0)
        ) {
          throw new Error(`第${ringIndex}魂环已存在。`);
        }
        const ringAge = Math.max(0, toNumber(soulData.年限, 0));
        const skillMap = buildDefaultRingSkillMapForUi(ringIndex, ringAge);
        const firstSkillName = Object.keys(skillMap)[0] || `第${ringIndex}魂技`;
        soulData[ringKey] = {
          年限: ringAge,
          颜色: getRingDisplayColorLabel('', ringAge),
          ...skillMap,
        };
        skillLabel = firstSkillName;
        skillPreviewKey = buildSkillDesignerPreviewKey({
          path: ['char', pending.charKey, spiritSlot, wantedSoulName, ringKey, firstSkillName],
          label: firstSkillName,
          category: '魂技',
          scope: '魂技',
        });
        if (!charData.状态 || typeof charData.状态 !== 'object') charData.状态 = {};
        delete charData.状态.待选魂环;
        if (!statData.sys || typeof statData.sys !== 'object') statData.sys = {};
        statData.sys.系统播报 = `[魂环生成] ${pending.charName} 选择由【${wantedSoulName}】为【${pending.spiritName}】衍生第 ${ringIndex} 魂环。`;
      },
      { force: true },
    );
    lastAutoOpenedPendingSoulRingSignature = '';
    await refreshLiveSnapshot({ force: true });
    const shouldJumpPreview = pending.spiritPreviewKey || '';
    if ((currentModalPreviewKey || currentUnifiedPreviewKey) === PENDING_SOUL_RING_PREVIEW_KEY) closeModal();
    if (skillPreviewKey) {
      打开技能设计确认({
        previewKey: skillPreviewKey,
        charName: pending.charName,
        sourceLabel: `${pending.spiritName}第${pending.ringIndex}魂环`,
        returnPreviewKey: shouldJumpPreview,
        submitAfterSave: true,
      });
    } else if (shouldJumpPreview) openModal(shouldJumpPreview, { preserveMapDispatchContext: true });
    if (window.MVU_Toast && typeof window.MVU_Toast.show === 'function') {
      window.MVU_Toast.show(skillLabel ? '已生成魂环，请确认魂技设计。' : '已生成对应魂环。', 'info');
    }
  }

  async function handlePendingSoulRingDefer(snapshot) {
    const pending = buildPendingSoulRingState(snapshot);
    if (!pending) throw new Error('当前没有待处理的魂环生成请求。');
    await mutateStatDataByEditor(
      statData => {
        const charData = deepGet(statData, ['char', pending.charKey], null);
        if (!charData || typeof charData !== 'object') throw new Error('未找到对应角色。');
        if (!charData.状态 || typeof charData.状态 !== 'object') charData.状态 = {};
        if (!charData.状态.待选魂环 || typeof charData.状态.待选魂环 !== 'object')
          throw new Error('待选魂环状态已失效。');
        charData.状态.待选魂环.状态 = '已暂缓';
        if (!statData.sys || typeof statData.sys !== 'object') statData.sys = {};
        statData.sys.系统播报 = `[魂环生成] ${pending.charName} 暂缓处理【${pending.spiritName}】的第 ${pending.ringIndex} 魂环。`;
      },
      { force: true },
    );
    await refreshLiveSnapshot({ force: true });
    if ((currentModalPreviewKey || currentUnifiedPreviewKey) === PENDING_SOUL_RING_PREVIEW_KEY) {
      closeModal();
    }
    if (window.MVU_Toast && typeof window.MVU_Toast.show === 'function') {
      window.MVU_Toast.show('已暂缓本次魂环生成。', 'info');
    }
  }

  function applyActiveCharacterSelection(nextName, options = {}) {
    cancelActiveInlineEdit();
    const targetName = toText(nextName, '').trim();
    const rootData = deepGet(liveSnapshot, 'rootData', null);
    const chars = deepGet(rootData, 'char', {});
    if (!targetName || !rootData || !chars || !chars[targetName]) return false;

    window.__MVU_MANUAL_CHAR_SET = true; // 标记这是用户手动切换的角色，不再自动被后续的玩家顶掉
    setPreferredActiveCharacterName(targetName);
    liveSnapshot = buildSnapshot(rootData);
    lastHeaderRenderSignature = buildHeaderRenderSignature(liveSnapshot);
    const nextDashboardSectionRenderSignatures = buildDashboardSectionRenderSignatures(liveSnapshot);
    lastDashboardRenderSignature = buildDashboardRenderSignature(liveSnapshot, nextDashboardSectionRenderSignatures);
    lastDashboardSectionRenderSignatures = null;
    renderHeader(liveSnapshot);
    renderLiveCards(liveSnapshot, nextDashboardSectionRenderSignatures);
    syncPrivateArchiveLongPressTargets(liveSnapshot);
    maybeAutoOpenPendingSoulRingPreview(liveSnapshot, { force: true });

    syncBattleUiForSnapshot(liveSnapshot, { force: true });

    const activeDetailPreviewKey = getEffectiveUnifiedPreviewKey() || currentModalPreviewKey;
    if ((detailModal.classList.contains('show') || isUnifiedInlinePreviewActive()) && activeDetailPreviewKey) {
      if (options.closeModal !== false) {
        if (isUnifiedInlinePreviewActive() && getEffectiveUnifiedPreviewKey())
          closeDetailSurface({ surface: 'unified' });
        else closeModal();
      } else {
        rerenderDetailSurface(activeDetailPreviewKey, {
          surface: getEffectiveUnifiedPreviewKey() ? 'unified' : 'modal',
        });
      }
    }

    return true;
  }

  function buildRenderSignature(value) {
    try {
      return JSON.stringify(value);
    } catch (error) {
      return `${Date.now()}|${Math.random()}`;
    }
  }

  function buildHeaderRenderSignature(snapshot) {
    const status = deepGet(snapshot, 'activeChar.状态', {});
    const battleDomain = toText(deepGet(snapshot, 'rootData.world.战斗.当前领域', ''), '');
    const bloodline =
      snapshot && snapshot.bloodline && snapshot.bloodline.valid
        ? {
            bloodline: snapshot.bloodline.bloodline,
            sealLv: snapshot.bloodline.sealLv,
            使用封印界面: !!snapshot.bloodline.使用封印界面,
            状态文本: 构建血脉状态文本_桥接(snapshot.bloodline),
          }
        : null;
    return buildRenderSignature({
      activeName: toText(snapshot && snapshot.activeName, ''),
      currentLoc: toText(snapshot && snapshot.currentLoc, ''),
      worldTimeText: toText(
        deepGet(snapshot, 'rootData.world.时间._calendar', deepGet(snapshot, 'rootData.world.时间.calendar', '')),
        '',
      ),
      action: toText(status && status.行动, ''),
      activeDomain: battleDomain,
      wound: getDisplayWoundLabel(deepGet(snapshot, 'activeChar.属性', {})),
      alive: deepGet(status, '存活', true) !== false,
      bloodline,
      armorStatus: toText(deepGet(snapshot, 'activeChar.装备.斗铠.装备状态', ''), ''),
      mechLv: toText(deepGet(snapshot, 'activeChar.装备.机甲.等级', ''), ''),
      worldAlert: toText(snapshot && snapshot.worldAlert, ''),
    });
  }

  function buildDashboardSectionRenderSignatures(snapshot) {
    return {
      archive: buildRenderSignature({
        activeName: toText(snapshot && snapshot.activeName, ''),
        activeChar: deepGet(snapshot, 'activeChar', {}),
        bloodline: snapshot && snapshot.bloodline ? snapshot.bloodline : null,
        primarySpirit: snapshot && snapshot.primarySpirit ? snapshot.primarySpirit : null,
        secondaryTrack: snapshot && snapshot.secondaryTrack ? snapshot.secondaryTrack : null,
        soulBoneEntries: Array.isArray(snapshot && snapshot.soulBoneEntries) ? snapshot.soulBoneEntries : [],
        inventoryEntries: Array.isArray(snapshot && snapshot.inventoryEntries) ? snapshot.inventoryEntries : [],
      }),
      map: buildRenderSignature({
        currentLoc: toText(snapshot && snapshot.currentLoc, ''),
        normalizedLoc: toText(snapshot && snapshot.normalizedLoc, ''),
        locationData: snapshot && snapshot.locationData ? snapshot.locationData : null,
        mapZoomHint: toNumber(snapshot && snapshot.mapZoomHint, 0),
        mapNodeLabels: Array.isArray(snapshot && snapshot.mapNodeLabels) ? snapshot.mapNodeLabels : [],
        mapVisibleNodeEntries: Array.isArray(snapshot && snapshot.mapVisibleNodeEntries)
          ? snapshot.mapVisibleNodeEntries
          : [],
        mapVisibleDynamicEntries: Array.isArray(snapshot && snapshot.mapVisibleDynamicEntries)
          ? snapshot.mapVisibleDynamicEntries
          : [],
        mapAvailableChildMaps:
          snapshot && snapshot.mapAvailableChildMaps && typeof snapshot.mapAvailableChildMaps === 'object'
            ? snapshot.mapAvailableChildMaps
            : {},
        本地人物: getShellLocalCharacterEntries(snapshot, 99).map(([名称, 角色]) => [
          名称,
          deepGet(角色, '状态.位置', ''),
          deepGet(角色, '状态.行动', ''),
          deepGet(角色, '社交.主身份', ''),
        ]),
        latestTimeline: snapshot && snapshot.latestTimeline ? snapshot.latestTimeline : null,
        timelineEntries: Array.isArray(snapshot && snapshot.timelineEntries) ? snapshot.timelineEntries : [],
      }),
      social: buildRenderSignature({
        social: deepGet(snapshot, 'activeChar.社交', {}),
        primaryFaction: snapshot && snapshot.primaryFaction ? snapshot.primaryFaction : null,
        topRelation: snapshot && snapshot.topRelation ? snapshot.topRelation : null,
        relations: Array.isArray(snapshot && snapshot.relations) ? snapshot.relations : [],
        unlockedKnowledges: Array.isArray(snapshot && snapshot.unlockedKnowledges) ? snapshot.unlockedKnowledges : [],
      }),
      world: buildRenderSignature({
        rootWorld: deepGet(snapshot, 'rootData.world', {}),
        worldAlert: toText(snapshot && snapshot.worldAlert, ''),
        factions: Array.isArray(snapshot && snapshot.势力) ? snapshot.势力 : [],
        locationData: snapshot && snapshot.locationData ? snapshot.locationData : null,
        latestTimeline: snapshot && snapshot.latestTimeline ? snapshot.latestTimeline : null,
      }),
      terminal: buildRenderSignature({
        rootSys: deepGet(snapshot, 'rootData.sys', {}),
        rootWorld: deepGet(snapshot, 'rootData.world', {}),
        activeChar: deepGet(snapshot, 'activeChar', {}),
        worldAlert: toText(snapshot && snapshot.worldAlert, ''),
        inventoryEntries: Array.isArray(snapshot && snapshot.inventoryEntries) ? snapshot.inventoryEntries : [],
        bestiaryEntries: Array.isArray(snapshot && snapshot.bestiaryEntries) ? snapshot.bestiaryEntries : [],
        recordEntries: Array.isArray(snapshot && snapshot.recordEntries) ? snapshot.recordEntries : [],
        timelineEntries: Array.isArray(snapshot && snapshot.timelineEntries) ? snapshot.timelineEntries : [],
        unlockedKnowledges: Array.isArray(snapshot && snapshot.unlockedKnowledges) ? snapshot.unlockedKnowledges : [],
      }),
    };
  }

  function buildDashboardRenderSignature(snapshot, sectionSignatures = null) {
    const sections = sectionSignatures || buildDashboardSectionRenderSignatures(snapshot);
    return [
      sections.archive || '',
      sections.map || '',
      sections.social || '',
      sections.world || '',
      sections.terminal || '',
    ].join('|');
  }

  function getLiveUiElements(selector) {
    if (!(liveUiRefCache instanceof Map)) liveUiRefCache = new Map();
    const cached = liveUiRefCache.get(selector);
    if (Array.isArray(cached) && cached.length && cached.every(el => el && el.isConnected)) {
      return cached;
    }
    const elements = Array.from(document.querySelectorAll(selector));
    if (elements.length) liveUiRefCache.set(selector, elements);
    else liveUiRefCache.delete(selector);
    return elements;
  }

  function setLiveNodeText(node, value) {
    if (!node) return;
    const nextValue = value == null ? '' : String(value);
    if (node.textContent === nextValue) return;
    node.textContent = nextValue;
  }

  function setLiveNodeHtml(node, value) {
    if (!node) return;
    const nextValue = value == null ? '' : String(value);
    if (node.innerHTML === nextValue) return;
    node.innerHTML = nextValue;
  }

  function setLiveText(selector, value) {
    getLiveUiElements(selector).forEach(node => setLiveNodeText(node, value));
  }

  function setLiveHtml(selector, value) {
    getLiveUiElements(selector).forEach(node => setLiveNodeHtml(node, value));
  }

  function 构建慢刷新骨架终端卡() {
    return `
        <div class="module-name">系统播报</div>
        <div class="terminal-log terminal-log--single-pane" data-terminal-tab-host="terminal-hero">
          <div class="terminal-tab-strip">
            <button type="button" class="terminal-tab terminal-skeleton-row" data-terminal-tab="播报">播报</button>
          </div>
          <div class="terminal-tab-panels">
            <div class="terminal-tab-panel active terminal-skeleton-row" data-terminal-tab-panel="播报">
              <div class="log-line roll log-line--single"><b>[播报]</b> 加载中...</div>
            </div>
          </div>
        </div>
        <div class="module-foot">
          <span class="foot-hint">数据刷新中</span>
          <span class="enter-chip">同步中</span>
        </div>
      `;
  }

  function 构建慢刷新骨架侧卡(标题 = '加载中') {
    return `
        <div class="simple-head"><div class="simple-title">${htmlEscape(toText(标题, '加载中'))}</div></div>
        <div class="simple-list">
          <div class="simple-row"><b>状态</b><span>加载中...</span></div>
          <div class="simple-row"><b>数据</b><span>正在同步</span></div>
        </div>
      `;
  }

  function 应用慢刷新骨架卡片() {
    setLiveHtml('[data-preview="系统播报与日志"].terminal-hero-card', 构建慢刷新骨架终端卡());
    setLiveHtml(
      '[data-preview="试炼与情报"].terminal-side-card, [data-preview="试炼与情报"].mvu-simple-card, [data-preview="试炼与情报"].simple-card',
      构建慢刷新骨架侧卡('试炼与情报'),
    );
  }

  function 设置慢刷新骨架状态(启用 = false, 选项 = {}) {
    const 需刷新详情 = Object.prototype.hasOwnProperty.call(选项 || {}, '刷新详情') ? !!选项.刷新详情 : true;
    if (启用) {
      if (!慢刷新骨架已启用) {
        慢刷新骨架已启用 = true;
        应用慢刷新骨架卡片();
      }
    } else if (慢刷新骨架已启用) {
      慢刷新骨架已启用 = false;
    }
    if (!需刷新详情) return;
    const 当前详情预览键 = toText(currentUnifiedPreviewKey || currentModalPreviewKey, '').trim();
    if (!当前详情预览键 || !慢刷新骨架预览键集合.has(当前详情预览键)) return;
    rerenderDetailSurface(当前详情预览键, {
      surface: currentUnifiedPreviewKey ? 'unified' : 'modal',
      force: true,
    });
  }

  function renderHeader(snapshot) {
    const worldTimeText = toText(
      deepGet(
        snapshot,
        'rootData.world.时间._calendar',
        deepGet(snapshot, 'rootData.world.时间.calendar', '斗罗历未同步'),
      ),
      '斗罗历未同步',
    );
    const headerComboHtml = `<span class="mvu-header-time">${htmlEscape(worldTimeText)}</span><span class="mvu-header-location">${htmlEscape(snapshot.currentLoc)}</span>`;
    setLiveHtml('.header-loc span', headerComboHtml);
    setLiveText('.char-name', snapshot.activeName);
    syncPrivateArchiveLongPressTargets(snapshot);

    const statusChips = getLiveUiElements('.header-status-row .header-status-chip');
    if (statusChips[0])
      setLiveNodeText(
        statusChips[0].querySelector('span'),
        toText(deepGet(snapshot, 'activeChar.状态.行动', '日常'), '日常'),
      );
    if (statusChips[1]) {
      const activeStatus = deepGet(snapshot, 'activeChar.状态', {});
      const injurySummary = buildInjurySummaryText(activeStatus, { limit: 1, empty: '' });
      setLiveNodeText(
        statusChips[1].querySelector('span'),
        `${getDisplayWoundLabel(deepGet(snapshot, 'activeChar.属性', {}))} / ${injurySummary || (deepGet(snapshot, 'activeChar.状态.存活', true) ? '状态稳定' : '已陨落')}`,
      );
    }
    if (statusChips[2]) {
      const shouldShowBloodline = !!(snapshot.bloodline && snapshot.bloodline.valid);
      if (statusChips[2].style.display !== (shouldShowBloodline ? '' : 'none')) {
        statusChips[2].style.display = shouldShowBloodline ? '' : 'none';
      }
      if (snapshot.bloodline && snapshot.bloodline.valid) {
        setLiveNodeText(statusChips[2].querySelector('span'), 构建血脉状态文本_桥接(snapshot.bloodline));
      }
    }
    if (statusChips[3])
      setLiveNodeText(
        statusChips[3].querySelector('span'),
        `斗铠${toText(deepGet(snapshot, 'activeChar.装备.斗铠.装备状态', '未装备'), '未装备')} / 机甲${toText(deepGet(snapshot, 'activeChar.装备.机甲.等级', '无'), '无')}`,
      );
    if (statusChips[4]) setLiveNodeText(statusChips[4].querySelector('span'), snapshot.worldAlert);
  }

  const PRIVATE_ARCHIVE_PREVIEW_KEY = '私密档案详细页';

  function isFemaleGenderText(value) {
    const normalized = String(value == null ? '' : value)
      .trim()
      .toLowerCase();
    if (!normalized) return false;
    if (normalized.includes('女')) return true;
    return normalized === 'female' || normalized === 'woman' || normalized === 'girl' || normalized === 'f';
  }

  function getActiveSnapshotCharacter(snapshot) {
    const activeChar = deepGet(snapshot, 'activeChar', null);
    if (activeChar && typeof activeChar === 'object') return activeChar;
    const activeCharKey = resolveSnapshotCharKey(snapshot, toText(snapshot && snapshot.activeName, ''));
    return activeCharKey ? deepGet(snapshot, ['rootData', 'char', activeCharKey], {}) : {};
  }

  function getPrivateArchiveAgeValue(value) {
    if (typeof value === 'number') return Number.isFinite(value) ? value : NaN;
    const rawText = String(value == null ? '' : value).trim();
    if (!rawText) return NaN;
    const directNumber = Number(rawText);
    if (Number.isFinite(directNumber)) return directNumber;
    const numericText = rawText.match(/-?\d+(?:\.\d+)?/);
    return numericText ? Number(numericText[0]) : NaN;
  }

