  function normalizeSoulSpiritQuality(value = '') {
    const text = toText(value, '').toUpperCase().replace('＋', '+').replace(/\s+/g, '');
    return SOUL_SPIRIT_QUALITY_VALUES.includes(text) ? text : '';
  }

  function createEmptySoulTowerDiscountSpiritRecord() {
    return {
      层数: 0,
      名称: '',
      标准物种: '',
      年限: 0,
      品质: '',
      已使用: false,
    };
  }

  function normalizeSoulTowerDiscountSpiritRecord(record = {}) {
    if (!record || typeof record !== 'object' || Array.isArray(record))
      return createEmptySoulTowerDiscountSpiritRecord();
    const next = createEmptySoulTowerDiscountSpiritRecord();
    next.层数 = Math.max(0, Math.floor(toNumber(record.层数, 0)));
    next.名称 = toText(record.名称, '');
    next.标准物种 = toText(record.标准物种, '');
    next.年限 = Math.max(0, Math.floor(toNumber(record.年限, 0)));
    next.品质 = normalizeSoulSpiritQuality(record.品质 || '');
    next.已使用 = record.已使用 === true;
    if (!(next.层数 > 0 && next.标准物种 && next.年限 > 0 && next.品质 && next.已使用 === false)) {
      return createEmptySoulTowerDiscountSpiritRecord();
    }
    if (!next.名称) next.名称 = `${next.标准物种}魂灵`;
    return next;
  }

  function hasActiveSoulTowerDiscountSpirit(record = {}) {
    return normalizeSoulTowerDiscountSpiritRecord(record).层数 > 0;
  }

  function buildSoulTowerDiscountSpiritDisplay(record = {}) {
    const normalized = normalizeSoulTowerDiscountSpiritRecord(record);
    if (!(normalized.层数 > 0)) return '暂无';
    return `第${normalized.层数}层 · ${normalized.标准物种} · ${formatAge(normalized.年限)} · ${normalized.品质}`;
  }

  function getSoulTowerAgeValueFromCharacter(charData = {}) {
    return getPrivateArchiveAgeValue(deepGet(charData, '属性.年龄', null));
  }

  function isSoulTowerEligibleCharacterData(charData = {}) {
    const ageValue = getSoulTowerAgeValueFromCharacter(charData);
    return Number.isFinite(ageValue) && ageValue > 0 && ageValue <= SOUL_TOWER_MAX_AGE;
  }

  function isTransmissionTowerEntryLocation(location = '') {
    const normalized = normalizeLocForMatch(location);
    if (!normalized.raw) return false;
    return normalized.segments.some(seg => /传灵塔/.test(seg));
  }

  function isSoulTowerHeadquartersLocation(location = '') {
    const normalized = normalizeLocForMatch(location);
    if (!normalized.raw) return false;
    if (/传灵塔总部/.test(normalized.raw)) return true;
    const hasSpiritPagoda = isTransmissionTowerEntryLocation(normalized.raw);
    const hasShrekCity = normalized.segments.some(seg => /史莱克城/.test(seg));
    return hasSpiritPagoda && hasShrekCity;
  }

  function 读取当前角色位置(snapshot) {
    return toText(
      deepGet(snapshot, 'activeChar.状态.位置', snapshot && snapshot.currentLoc),
      toText(snapshot && snapshot.currentLoc, ''),
    ).trim();
  }

  function 读取试炼状态文本(snapshot) {
    return toText(deepGet(snapshot, 'rootData.world.战斗.试炼状态', ''), '').trim();
  }

  function 是否试炼内地点(location = '') {
    return toText(location, '').trim().startsWith(试炼地点前缀);
  }

  function 构建升灵台试炼地点(档位 = '初级', 暴动期 = false) {
    const safeTier = ['初级', '中级', '高级'].includes(toText(档位, '初级')) ? toText(档位, '初级') : '初级';
    return `${试炼地点前缀}${暴动期 ? '暴动期' : ''}${safeTier}升灵台`;
  }

  function 构建魂灵塔试炼地点(层数 = 1) {
    const floor = Math.min(SOUL_TOWER_TOTAL_FLOORS, Math.max(1, Math.floor(toNumber(层数, 1))));
    return `${试炼地点前缀}魂灵塔-第${floor}层`;
  }

  function 解析试炼地点(location = '') {
    const safeLocation = toText(location, '').trim();
    if (!是否试炼内地点(safeLocation)) return null;
    const 塔匹配 = safeLocation.match(/^试炼-魂灵塔-第(\d+)层$/);
    if (塔匹配) {
      const floor = Math.min(SOUL_TOWER_TOTAL_FLOORS, Math.max(1, Math.floor(toNumber(塔匹配[1], 1))));
      return {
        试炼类型: '魂灵塔',
        门票名: '魂灵塔门票',
        档位: '魂灵塔',
        暴动期: false,
        入场地点: 魂灵塔退出地点,
        当前层: floor,
        试炼内地点: 构建魂灵塔试炼地点(floor),
      };
    }
    if (/升灵台/.test(safeLocation)) {
      const body = safeLocation.replace(/^试炼-/, '');
      const 暴动期 = /暴动期/.test(body);
      const 档位 = 解析升灵台档位(body);
      return {
        试炼类型: '升灵台',
        门票名: `${暴动期 ? '暴动期' : ''}${档位}升灵台门票`,
        档位,
        暴动期,
        入场地点: 升灵台退出地点,
        当前层: 0,
        试炼内地点: 构建升灵台试炼地点(档位, 暴动期),
      };
    }
    return null;
  }

  function isSoulTowerCombatType(detail = {}) {
    const battleType = toText(detail && (detail['战斗类型'] || detail.combatType || detail.type), '');
    return battleType === '魂灵塔冲塔';
  }

  function getSoulTowerGateMeta(floor = 0) {
    const safeFloor = Math.max(1, Math.floor(Number(floor) || 1));
    const rule =
      SOUL_TOWER_LAYER_RULES.find(item => safeFloor >= item.gateStart && safeFloor <= item.gateEnd) ||
      SOUL_TOWER_LAYER_RULES[SOUL_TOWER_LAYER_RULES.length - 1];
    const layerInGate = safeFloor - rule.gateStart + 1;
    const gateIndex = SOUL_TOWER_LAYER_RULES.findIndex(item => item.key === rule.key) + 1;
    const isGateBoss = safeFloor === rule.gateEnd;
    const nextGateBossFloor = rule.gateEnd;
    const layerProgress =
      rule.gateEnd > rule.gateStart ? (safeFloor - rule.gateStart) / (rule.gateEnd - rule.gateStart) : 1;
    return {
      floor: safeFloor,
      gateIndex,
      gateStart: rule.gateStart,
      gateEnd: rule.gateEnd,
      layerInGate,
      isGateBoss,
      gateLabel: rule.label,
      gateRangeLabel: `${rule.gateStart}-${rule.gateEnd}层`,
      nextGateBossFloor,
      rewardTier: rule.rewardTier,
      layerProgress,
      minAge: rule.minAge,
      maxAge: rule.maxAge,
      qualitySteps: rule.qualitySteps,
      isTopNine: safeFloor >= 100,
      totalFloors: SOUL_TOWER_TOTAL_FLOORS,
      key: rule.key,
    };
  }

  function getSoulTowerStageTextByHighestFloor(highestFloor = 0) {
    const safeHighestFloor = Math.max(0, Math.floor(Number(highestFloor) || 0));
    const nextFloor = Math.max(1, safeHighestFloor + 1);
    const meta = getSoulTowerGateMeta(nextFloor);
    return `${meta.gateLabel} · ${meta.gateRangeLabel}`;
  }

  function getSoulTowerNextBossFloorText(highestFloor = 0) {
    const safeHighestFloor = Math.max(0, Math.floor(Number(highestFloor) || 0));
    const nextFloor = Math.max(1, safeHighestFloor + 1);
    const meta = getSoulTowerGateMeta(nextFloor);
    if (safeHighestFloor >= SOUL_TOWER_TOTAL_FLOORS) return '已登顶';
    return `${meta.nextGateBossFloor}层`;
  }

  function getSoulTowerGuardianQualityForFloor(floor = 1) {
    const meta = getSoulTowerGateMeta(floor);
    const steps = Array.isArray(meta.qualitySteps) && meta.qualitySteps.length ? meta.qualitySteps : ['C'];
    if (steps.length === 1) return steps[0];
    const progress = Math.max(0, Math.min(1, Number(meta.layerProgress || 0)));
    const index = Math.min(steps.length - 1, Math.floor(progress * steps.length));
    return steps[index] || steps[steps.length - 1];
  }

  function buildSoulTowerGuardianAgeForFloor(floor = 1, rng = Math.random) {
    const meta = getSoulTowerGateMeta(floor);
    const minAge = Math.max(1, Math.floor(Number(meta.minAge || 1)));
    const maxAge = Math.max(minAge, Math.floor(Number(meta.maxAge || minAge)));
    if (meta.isGateBoss) return maxAge;
    const gateLength = Math.max(1, meta.gateEnd - meta.gateStart);
    const progress = Math.max(0, Math.min(1, Number(meta.layerProgress || 0)));
    const anchor = minAge + Math.round((maxAge - minAge) * progress);
    const bucket = Math.max(1, Math.floor((maxAge - minAge) / Math.max(2, gateLength + 1)));
    const variance = Math.max(0, Math.floor(bucket * 0.45));
    const offset = variance > 0 ? pickTemporaryBattleInt(-variance, variance, rng) : 0;
    return Math.max(minAge, Math.min(maxAge, anchor + offset));
  }

  function buildSoulTowerGuardianSeed(floor = 1, options = {}) {
    const safeFloor = Math.max(1, Math.floor(toNumber(floor, 1)));
    const rng = typeof options.rng === 'function' ? options.rng : Math.random;
    const speciesPool =
      Array.isArray(options.speciesPool) && options.speciesPool.length
        ? options.speciesPool
        : BATTLE_SOUL_BEAST_STANDARD_SPECIES;
    const species = toText(options.species, pickTemporaryBattleItem(speciesPool, rng) || '龙类') || '龙类';
    const age = Math.max(1, Math.floor(toNumber(options.age, buildSoulTowerGuardianAgeForFloor(safeFloor, rng))));
    const quality =
      normalizeSoulSpiritQuality(options.品质 || options.quality || getSoulTowerGuardianQualityForFloor(safeFloor)) ||
      'C';
    const name = toText(options.name, `${species}守塔魂兽`) || `${species}守塔魂兽`;
    return {
      name,
      名称: name,
      来源: '临时单位',
      单位性质: '魂兽',
      数量: 1,
      标准物种: species,
      具体物种: `${species}守塔魂兽`,
      物种品质: '普通',
      年限: age,
      品质: quality,
    };
  }

  function buildSoulTowerDiscountSpiritRecordFromSeed(floor = 1, seed = {}) {
    const safeFloor = Math.max(1, Math.floor(toNumber(floor, 1)));
    const species = toText(seed.标准物种, '');
    const age = Math.max(0, Math.floor(toNumber(seed.年限, 0)));
    const quality = normalizeSoulSpiritQuality(seed.品质 || '');
    if (!(species && age > 0 && quality)) return createEmptySoulTowerDiscountSpiritRecord();
    return {
      层数: safeFloor,
      名称: `${species}魂灵`,
      标准物种: species,
      年限: age,
      品质: quality,
      已使用: false,
    };
  }

  function buildSoulTowerTeamValidationResult(members = []) {
    const safeMembers = Array.isArray(members) ? members.filter(member => member && typeof member === 'object') : [];
    if (!safeMembers.length) return { ok: false, message: '魂灵塔队伍为空。' };
    if (safeMembers.length > SOUL_TOWER_TEAM_LIMIT) {
      return { ok: false, message: `魂灵塔队伍最多 ${SOUL_TOWER_TEAM_LIMIT} 人。` };
    }
    const invalidAgeMember = safeMembers.find(member => !(member.age > 0) || member.age > SOUL_TOWER_MAX_AGE);
    if (invalidAgeMember) {
      return {
        ok: false,
        message: `${toText(invalidAgeMember.name, '队员')} 已超过 ${SOUL_TOWER_MAX_AGE} 岁，不能参与魂灵塔。`,
      };
    }
    const ages = safeMembers.map(member => Number(member.age || 0)).filter(age => age > 0);
    const minAge = Math.min(...ages);
    const maxAge = Math.max(...ages);
    if (maxAge - minAge > SOUL_TOWER_MAX_AGE_GAP) {
      return { ok: false, message: `魂灵塔队伍成员年龄差不能超过 ${SOUL_TOWER_MAX_AGE_GAP} 岁。` };
    }
    return {
      ok: true,
      count: safeMembers.length,
      minAge,
      maxAge,
      totalFloors: SOUL_TOWER_TOTAL_FLOORS,
    };
  }

  function resolveSoulTowerStatCharKeyByName(statData, rawName = '') {
    const wanted = toText(rawName, '').trim();
    if (!wanted) return '';
    const charMap = statData && statData.char && typeof statData.char === 'object' ? statData.char : {};
    const direct = charMap[wanted];
    if (direct && typeof direct === 'object') return wanted;
    const foundEntry = Object.entries(charMap).find(([charKey, charData]) => {
      const displayName = toText(charData && charData.name, charKey);
      return displayName === wanted || charKey === wanted;
    });
    return foundEntry ? toText(foundEntry[0], '') : '';
  }

  function buildSoulTowerTeamMembersFromStatBattle(statData, charKey = '') {
    const safeCharKey = toText(charKey, '').trim();
    const battleData = deepGet(statData, 'world.战斗', null);
    if (!safeCharKey || !battleData || toText(battleData && battleData['战斗类型'], '') !== '魂灵塔冲塔') return null;
    const participantMap =
      battleData && battleData['参战者'] && typeof battleData['参战者'] === 'object' ? battleData['参战者'] : null;
    if (!participantMap) return null;
    const playerName = toText(deepGet(participantMap, 'team_player.0.name', ''), '');
    const selfNames = new Set(
      [safeCharKey, toText(deepGet(statData, ['char', safeCharKey, 'name'], ''), safeCharKey)].filter(Boolean),
    );
    if (playerName && !selfNames.has(playerName)) return null;
    const seeds = Array.isArray(participantMap.team_player) ? participantMap.team_player.filter(Boolean) : [];
    return seeds.map(seed => {
      const memberName = toText(seed && seed.name, '');
      const memberKey = resolveSoulTowerStatCharKeyByName(statData, memberName);
      const charData = memberKey ? deepGet(statData, ['char', memberKey], null) : null;
      return {
        key: memberKey,
        name: toText(charData && charData.name, memberName || memberKey || '队员'),
        age: getSoulTowerAgeValueFromCharacter(charData || {}),
      };
    });
  }

  function buildTrialBattleDispatchDetail(snapshot, dispatchDetail = {}, trialContext = null) {
    const sourceSnapshot = snapshot && snapshot.rootData ? snapshot : liveSnapshot || lastRenderableSnapshot;
    if (!sourceSnapshot || !sourceSnapshot.rootData) return null;
    const baseDetail = { ...cloneJsonValue(dispatchDetail, {}) };
    const 显式参战者 =
      baseDetail.参战者 && typeof baseDetail.参战者 === 'object' ? cloneJsonValue(baseDetail.参战者, {}) : null;
    const 显式己方队伍 = Array.isArray(显式参战者 && 显式参战者.team_player)
      ? cloneJsonValue(显式参战者.team_player, [])
      : [];
    const 状态上下文 = 解析试炼地点(读取试炼状态文本(sourceSnapshot));
    const safeContext = 规范化试炼状态上下文(trialContext || 状态上下文 || null);
    if (!safeContext) return null;
    const activeKey = resolveSnapshotCharKey(sourceSnapshot, toText(sourceSnapshot && sourceSnapshot.activeName, ''));
    if (!activeKey) return null;
    const activeName = toText(
      deepGet(sourceSnapshot, ['rootData', 'char', activeKey, 'name'], ''),
      toText(sourceSnapshot && sourceSnapshot.activeName, activeKey),
    );
    if (safeContext.试炼类型 === '升灵台') {
      const ascensionResult = 生成升灵台战斗参数(sourceSnapshot, safeContext);
      return {
        ...baseDetail,
        action: 'battle',
        currentLoc: safeContext.试炼内地点 || 读取当前角色位置(sourceSnapshot),
        target: safeContext.试炼内地点 || 读取当前角色位置(sourceSnapshot),
        战斗类型: '升灵台虚拟战斗',
        战斗意图: '升灵试炼',
        source: toText(baseDetail.source, 'trial_entry'),
        试炼状态: safeContext.试炼内地点 || 构建升灵台试炼地点(safeContext.档位, safeContext.暴动期),
        ascension_ticket: toText(baseDetail.ascension_ticket, safeContext.门票名),
        killed_age: Math.max(1, Math.floor(toNumber(baseDetail.killed_age, ascensionResult.killedAge))),
        party_size: Math.max(1, Math.floor(toNumber(baseDetail.party_size, 1))),
        升灵对手类型: toText(baseDetail.升灵对手类型, ascensionResult.对手类型),
        升灵档位百分位: Math.max(0, Math.min(1, toNumber(baseDetail.升灵档位百分位, ascensionResult.百分位))),
        参战者: {
          team_player: [{ name: activeName || activeKey }, ...显式己方队伍],
          team_enemy: [cloneJsonValue(ascensionResult.对手种子, {})],
        },
      };
    }
    if (safeContext.试炼类型 === '魂灵塔') {
      const 塔层基准值 = toNumber(
        baseDetail.floor,
        toNumber(
          deepGet(
            sourceSnapshot,
            'rootData.world.战斗.floor',
            safeContext.当前层 || getDefaultSoulTowerChallengeFloor(sourceSnapshot),
          ),
          safeContext.当前层 || getDefaultSoulTowerChallengeFloor(sourceSnapshot),
        ),
      );
      const requestedFloor = Math.min(SOUL_TOWER_TOTAL_FLOORS, Math.max(1, Math.floor(塔层基准值)));
      const guardianSeed = 构建魂灵塔守塔种子({ ...safeContext, 当前层: requestedFloor });
      return {
        ...baseDetail,
        action: 'battle',
        currentLoc: safeContext.试炼内地点 || 构建魂灵塔试炼地点(requestedFloor),
        target: safeContext.试炼内地点 || 构建魂灵塔试炼地点(requestedFloor),
        战斗类型: '魂灵塔冲塔',
        战斗意图: '魂灵塔试炼',
        source: toText(baseDetail.source, 'trial_entry'),
        试炼状态: safeContext.试炼内地点 || 构建魂灵塔试炼地点(requestedFloor),
        floor: requestedFloor,
        soulTowerTicket: toText(baseDetail.soulTowerTicket, safeContext.门票名),
        门票已扣除: true,
        参战者: {
          team_player: [{ name: activeName || activeKey }, ...显式己方队伍],
          team_enemy: [cloneJsonValue(guardianSeed, {})],
        },
      };
    }
    return null;
  }

  function getTrialEntranceText(snapshot) {
    const soulTowerEligible = isSoulTowerEligibleCharacterData(getActiveSnapshotCharacter(snapshot));
    const hasSoulTowerTicket = soulTowerEligible && listSoulTowerTicketNames(snapshot).length > 0;
    const hasAscensionTicket = listAscensionTicketNames(snapshot).length > 0;
    if (hasSoulTowerTicket) return '升灵台 / 魂灵塔 / 狩猎';
    if (hasAscensionTicket) return '升灵台 / 狩猎';
    return '当前无门票，仅常规狩猎';
  }

  function canOpenPrivateArchive(snapshot) {
    const activeChar = getActiveSnapshotCharacter(snapshot);
    const genderText = toText(deepGet(activeChar, '属性.性别', ''), '');
    if (!isFemaleGenderText(genderText)) return false;
    const ageValue = getPrivateArchiveAgeValue(deepGet(activeChar, '属性.年龄', null));
    return Number.isFinite(ageValue) && ageValue >= 6;
  }

  function getActiveNsfwPath(snapshot) {
    const activeCharKey = resolveSnapshotCharKey(snapshot, toText(snapshot && snapshot.activeName, ''));
    return activeCharKey ? ['char', activeCharKey, '私密档案'] : [];
  }

  function getActiveNsfwData(snapshot) {
    const activeNsfw = deepGet(snapshot, 'activeChar.私密档案', null);
    if (activeNsfw && typeof activeNsfw === 'object' && safeEntries(activeNsfw).length) return activeNsfw;
    const activeCharKey = resolveSnapshotCharKey(snapshot, toText(snapshot && snapshot.activeName, ''));
    const rootNsfw = activeCharKey ? deepGet(snapshot, ['rootData', 'char', activeCharKey, '私密档案'], null) : null;
    if (rootNsfw && typeof rootNsfw === 'object') return rootNsfw;
    return activeNsfw && typeof activeNsfw === 'object' ? activeNsfw : {};
  }

  function setPrivateArchiveLongPressTarget(node, enabled, options = {}) {
    if (!node) return;
    const useVisualClass = options.visualClass !== false;
    node.classList.toggle('nsfw-trigger-title', !!(enabled && useVisualClass));
    node.classList.remove('active-press');
    if (enabled) {
      node.setAttribute('data-longpress', PRIVATE_ARCHIVE_PREVIEW_KEY);
      node.setAttribute('data-longpress-delay', '600');
    } else {
      node.removeAttribute('data-longpress');
      node.removeAttribute('data-longpress-delay');
    }
  }

  function syncPrivateArchiveLongPressTargets(snapshot) {
    const enabled = canOpenPrivateArchive(snapshot);
    getLiveUiElements('.char-name').forEach(node => {
      setPrivateArchiveLongPressTarget(node, enabled);
    });
    getLiveUiElements('#mvu-unified-mount .mvu-unified-section-title').forEach(node => {
      if (toText(node.textContent, '').trim() === '详细档案') {
        setPrivateArchiveLongPressTarget(node, enabled);
      }
    });
  }

  function buildArchiveCoreCard(snapshot) {
    const stat = deepGet(snapshot, 'activeChar.属性', {});
    const status = deepGet(snapshot, 'activeChar.状态', {});
    const hpPair = getDisplayHpPair(stat);
    const woundLabel = getDisplayWoundLabel(stat);
    const nextLevelSoul = getNextLevelSoulRequirementWithCap(stat, deepGet(snapshot, 'activeChar', {}));
    const allowNsfwLongPress = canOpenPrivateArchive(snapshot);
    const mentalRealmText = 读取显示精神境界(stat);
    const 伤势显示 = woundLabel && woundLabel !== '无' ? woundLabel : '无伤';
    const 领域文本 = toText(deepGet(snapshot, 'rootData.world.战斗.当前领域', ''), '常态');
    const 领域显示 = 领域文本 && 领域文本 !== '无' ? 领域文本 : '常态';
    const nextSoulDisplayText = nextLevelSoul.isMax
      ? '下级魂力 已满级'
      : nextLevelSoul.blocked
        ? nextLevelSoul.blockedBy === 'ring'
          ? `下级魂力 受魂环限制`
          : `下级魂力 受魂核限制`
        : toNumber(nextLevelSoul.needed, 0) <= 0
          ? `下级魂力 已达${formatNumber(nextLevelSoul.nextLevel)}级门槛`
          : `下级魂力 ${formatNumber(nextLevelSoul.needed)}`;
    const nextSoulValueText = nextSoulDisplayText.replace(/^下级魂力\s*/, '');
    const 资源指标列表 = [
      {
        名称: '魂力',
        数值: `${格式化属性短数字(stat.魂力)}/${格式化属性短数字(stat.魂力上限)}`,
        值Html: 构建属性数值对Html('魂力', stat.魂力, stat.魂力上限),
        提示文本: `魂力：${格式化属性完整数字(stat.魂力)} / ${格式化属性完整数字(stat.魂力上限)}`,
        比例: ratioPercent(stat.魂力, stat.魂力上限),
        样式: 'cyan',
      },
      {
        名称: `精神力 · ${mentalRealmText}`,
        数值: `${格式化属性短数字(stat.精神力)}/${格式化属性短数字(stat.精神力上限)}`,
        值Html: 构建属性数值对Html('精神力', stat.精神力, stat.精神力上限),
        提示文本: `精神力：${格式化属性完整数字(stat.精神力)} / ${格式化属性完整数字(stat.精神力上限)}`,
        比例: ratioPercent(stat.精神力, stat.精神力上限),
        样式: 'white',
      },
      {
        名称: '生命',
        数值: `${格式化属性短数字(hpPair.hp)}/${格式化属性短数字(hpPair.hpMax)}`,
        值Html: 构建属性数值对Html('生命', hpPair.hp, hpPair.hpMax),
        提示文本: `生命：${格式化属性完整数字(hpPair.hp)} / ${格式化属性完整数字(hpPair.hpMax)}`,
        比例: ratioPercent(hpPair.hp, hpPair.hpMax),
        样式: 'red',
      },
      {
        名称: '体力',
        数值: `${格式化属性短数字(stat.体力)}/${格式化属性短数字(stat.体力上限)}`,
        值Html: 构建属性数值对Html('体力', stat.体力, stat.体力上限),
        提示文本: `体力：${格式化属性完整数字(stat.体力)} / ${格式化属性完整数字(stat.体力上限)}`,
        比例: ratioPercent(stat.体力, stat.体力上限),
        样式: 'red',
      },
    ];
    return `
        <div class="panel-head panel-head--archive archive-core-head">
          <div class="panel-title-row">
            <div class="panel-title${allowNsfwLongPress ? ' nsfw-trigger-title' : ''}"${allowNsfwLongPress ? ` data-longpress="${PRIVATE_ARCHIVE_PREVIEW_KEY}" data-longpress-delay="600"` : ''}>详细档案</div>
          </div>
        </div>
        <div class="archive-core-grid">
          <div class="archive-core-tile">
            <b>年龄 / 性别</b>
            <strong>${htmlEscape(`${toText(stat.年龄, '0')}岁 / ${toText(stat.性别, '未知')}`)}</strong>
          </div>
          <div class="archive-core-tile">
            <b>修为等级</b>
            <strong class="cyan">${htmlEscape(formatCultivationLevelBadge(stat.等级, '0'))}</strong>
          </div>
          <div class="archive-core-tile">
            <b>身体状态</b>
            <strong>${htmlEscape(`${伤势显示} / ${领域显示}`)}</strong>
          </div>
          <div class="archive-core-tile">
            <b>下级所需魂力</b>
            <strong class="cyan">${htmlEscape(nextSoulValueText)}</strong>
          </div>
          ${资源指标列表
            .map(
              指标 => `
            <div class="archive-core-tile archive-core-tile--resource is-${htmlEscape(指标.样式)}">
              <b>${htmlEscape(指标.名称)}</b>
              <strong${指标.提示文本 ? ` title="${escapeHtmlAttr(指标.提示文本)}"` : ''}>${指标.值Html || htmlEscape(指标.数值)}</strong>
              <i><span style="width:${指标.比例}%;"></span></i>
            </div>
          `,
            )
            .join('')}
        </div>
        `;
  }

  function 构建副职业工坊上限摘要(职业名 = '', 职业数据 = {}) {
    if (!职业数据 || typeof 职业数据 !== 'object') return '暂无工坊上限';
    const 派生 = 派生副职业显示数据(职业名, 职业数据);
    return `支持融锻数 ${派生.支持融锻数} / 基础成功率 ${派生.基础成功率}%`;
  }

  function 读取职业显示等级(职业数据 = {}) {
    if (!职业数据 || typeof 职业数据 !== 'object') return 0;
    return 派生副职业显示数据('', 职业数据).等级;
  }

  function 读取副职业派生接口() {
    const 根列表 = [];
    try { 根列表.push(__mvuBridgeRoot); } catch (错误) {}
    try { 根列表.push(window); } catch (错误) {}
    try { if (window.parent && window.parent !== window) 根列表.push(window.parent); } catch (错误) {}
    try { if (window.top && window.top !== window) 根列表.push(window.top); } catch (错误) {}
    const 接口 = 根列表
      .map(根 => {
        try { return 根.__LWCS_PROFESSION_DERIVATION__; } catch (错误) { return null; }
      })
      .find(候选接口 => 候选接口 && typeof 候选接口.派生运行时 === 'function');
    if (!接口) throw new Error('副职业派生接口未加载');
    return 接口;
  }

  function 派生副职业显示数据(职业名 = '', 职业数据 = {}) {
    return 读取副职业派生接口().派生运行时(职业名, 职业数据);
  }

  function 读取属性天赋梯队(属性 = {}) {
    return toText(属性?.天赋梯队 ?? 属性?.talent_tier, '未定');
  }

  function buildArmoryCard(snapshot) {
    const armor = deepGet(snapshot, 'activeChar.装备.斗铠', {});
    const mech = deepGet(snapshot, 'activeChar.装备.机甲', {});
    const weapon = deepGet(snapshot, 'activeChar.装备.武器', {});
    const jobs = safeEntries(deepGet(snapshot, 'activeChar.职业', {}));
    const jobSummary = jobs.length ? `${jobs[0][0]} Lv.${读取职业显示等级(jobs[0][1])}` : '未展开';
    const jobCoreTechSummary = jobs.length
      ? 派生副职业显示数据(jobs[0][0], jobs[0][1]).核心技艺
      : '暂无核心技术';
    const jobLimitSummary = jobs.length ? 构建副职业工坊上限摘要(jobs[0][0], jobs[0][1]) : '暂无工坊上限';
    const 斗铠名称 = toText(armor.名称 || armor['名称'], '');
    const armorSummary = toNumber(armor.等级, 0) > 0 || 斗铠名称 ? 斗铠名称 || `${armor.等级}字斗铠` : '无';
    const mechSummary =
      toText(mech.等级, '无') !== '无'
        ? `${toText(mech.名称 || mech['名称'], `${toText(mech.等级, '无')}机甲`)}·${toText(mech.型号, '均衡')}`
        : '无';
    const boneCount = snapshot.soulBoneEntries ? snapshot.soulBoneEntries.length : 0;
    const 武器摘要 = toText(weapon.名称, '') || toText(weapon.类型, '') || '无';
    return `
        <div class="module-name">武装工坊</div>
        <div class="module-grid armory-grid">
          <div class="mini-box"><b>当前斗铠</b><span>${htmlEscape(armorSummary)}</span></div>
          <div class="mini-box"><b>当前机甲</b><span>${htmlEscape(mechSummary)}</span></div>
          <div class="mini-box"><b>武器</b><span>${htmlEscape(shortenText(武器摘要, 28))}</span></div>
          <div class="mini-box"><b>装载魂骨</b><span>${htmlEscape(boneCount ? `${boneCount} 块` : '0 块')}</span></div>
        </div>
        <div class="module-foot">
          <span class="foot-hint">${htmlEscape(jobSummary)} · ${htmlEscape(jobCoreTechSummary)}</span>
          <span class="enter-chip">${htmlEscape(jobLimitSummary)}</span>
        </div>
      `;
  }

  function buildVaultCard(snapshot) {
    const wealth = deepGet(snapshot, 'activeChar.财富', {});
    const activeCharKey =
      resolveSnapshotCharKey(snapshot, toText(snapshot.activeName, '')) || toText(snapshot.activeName, '当前角色');
    return `
        <div class="module-name">储物仓库</div>
        <div class="module-grid vault-grid">
          <div class="mini-box"><b>物品种类</b><span>${htmlEscape(String(snapshot.inventoryEntries.length || 0))}</span></div>
          <div class="mini-box"><b>联邦币</b><span>${htmlEscape(formatNumber(wealth.联邦币))}</span></div>
          <div class="mini-box"><b>星罗币</b><span>${htmlEscape(formatNumber(wealth.星罗币))}</span></div>
          <div class="mini-box"><b>唐门积分</b><span>${htmlEscape(formatNumber(wealth.唐门积分))}</span></div>
        </div>
        <div class="module-foot">
          <span class="foot-hint">记录物资总计 ${htmlEscape(String(snapshot.inventoryEntries.length || 0))} 件</span>
          <span class="enter-chip gold-chip">学院/战功：${htmlEscape(formatNumber(wealth.学院积分))} / ${htmlEscape(formatNumber(wealth.战功))}</span>
        </div>
      `;
  }

  function buildUnifiedSocialCard(snapshot) {
    const social = deepGet(snapshot, 'activeChar.社交', {});
    const primaryFactionName = snapshot.primaryFaction ? snapshot.primaryFaction[0] : '无';
    const primaryFactionRole = snapshot.primaryFaction
      ? toText(deepGet(snapshot.primaryFaction[1], '身份', '无'), '无')
      : '未加入';
    const topRelationText = snapshot.topRelation
      ? `${toText(snapshot.topRelation[0], '未知人物')} / ${toText(deepGet(snapshot.topRelation[1], '关系', '陌生'), '陌生')} / ${toNumber(deepGet(snapshot.topRelation[1], '好感度', 0), 0)}`
      : '暂无高亮关系';
    const latestIntelText = getLatestUnlockedIntelText(snapshot, 32, '暂无情报');
    const 名望等级 = toText(social.名望等级, toText(social.名望等级, '籍籍无名'));
    const 主身份 = toText(social.主身份, '社会档案');
    return `
        <div class="mvu-social-entry-grid">
          ${构建社交入口块('名望', 名望等级, 主身份, '社会档案详细页', 'gold', `声望 ${formatNumber(social.声望)}`)}
          ${构建社交入口块('势力', primaryFactionName, primaryFactionRole, '所属势力详细页', 'live', `${(snapshot.势力 || []).length || 0} 项`)}
          ${构建社交入口块('关系', topRelationText, '人物关系', '人物关系详细页', '', `${snapshot.relations.length} 条`)}
          ${构建社交入口块('情报', latestIntelText, snapshot.publicIntel ? '公开情报' : '情报库', '情报库详细页', '', `${snapshot.unlockedKnowledges.length} 条`)}
        </div>
      `;
  }

  function buildUnifiedSpiritCard(config, options = {}) {
    const primary = !!(options && options.primary);
    if (!config) {
      return `
          <div class="mvu-unified-card-head">
            <div class="mvu-unified-card-title">${primary ? '主武魂' : '第2武魂'}</div>
          </div>
          <div class="mvu-unified-empty-note mvu-unified-empty-note--compact">${primary ? '当前未加载武魂信息。' : '未启用第2武魂或血脉'}</div>
        `;
    }
    const content =
      config.kind === 'bloodline' ? renderArchiveBloodlineEntry(config) : renderArchiveSpiritEntry(config, primary);
    return `<div class="mvu-unified-spirit-card">${content}</div>`;
  }

  function 构建统一副轨摘要卡(snapshot) {
    const 第二轨 = snapshot && snapshot.secondaryTrack ? snapshot.secondaryTrack : null;
    if (第二轨) return buildUnifiedSpiritCard(第二轨, { primary: false });
    const 融合资料 = getFusionArchiveMeta(snapshot || {});
    const 魂骨数量 = Array.isArray(snapshot && snapshot.soulBoneEntries) ? snapshot.soulBoneEntries.length : 0;
    return `
        <div class="mvu-spirit-empty-compact">
          <b>第2武魂 / 血脉</b>
          <span>未启用第2武魂。</span>
          <em>融合技 ${htmlEscape(String(融合资料.fusionEntries.length || 0))} 项 · 魂骨 ${htmlEscape(String(魂骨数量 || 0))} 块</em>
        </div>
      `;
  }

  function normalizeUnifiedSurfaceKey(surface) {
    const value = toText(surface, '').trim().toLowerCase();
    if (value === 'panel') return 'panel';
    return '';
  }

  function collectShellBadgeItems(items = [], max = 4) {
    const result = [];
    (Array.isArray(items) ? items : []).forEach(item => {
      if (result.length >= max) return;
      const entry =
        item && typeof item === 'object'
          ? { text: toText(item.text, '').trim(), tone: toText(item.tone, '').trim() }
          : { text: toText(item, '').trim(), tone: '' };
      if (!entry.text) return;
      if (result.some(candidate => candidate.text === entry.text)) return;
      result.push(entry);
    });
    return result;
  }

  function collectShellMetricItems(items = [], max = 4) {
    return (Array.isArray(items) ? items : [])
      .map(item => ({
        label: toText(item && item.label, '').trim(),
        value: toText(item && item.value, '').trim(),
        值Html: item && item.值Html ? String(item.值Html) : '',
        提示文本: toText(item && item.提示文本, '').trim(),
        tone: toText(item && item.tone, '').trim(),
      }))
      .filter(item => item.label && (item.value || item.值Html))
      .slice(0, max);
  }

  function collectShellLineItems(items = [], max = 3) {
    return (Array.isArray(items) ? items : [])
      .map(item => ({
        label: toText(item && item.label, '').trim(),
        value: toText(item && item.value, '').trim(),
      }))
      .filter(item => item.label && item.value)
      .slice(0, max);
  }

  function formatShellPair(当前源, 上限源) {
    return `${格式化属性短数字(当前源)} / ${格式化属性短数字(上限源)}`;
  }

  function 构建属性指标项(标签, 当前值, 上限值, 样式 = '') {
    return {
      label: 标签,
      value: formatShellPair(当前值, 上限值),
      值Html: 构建属性数值对Html(标签, 当前值, 上限值),
      提示文本: `${标签}：${格式化属性完整数字(当前值)} / ${格式化属性完整数字(上限值)}`,
      tone: 样式,
    };
  }

  function buildShellSummaryCard(options = {}) {
    const kicker = toText(options.kicker, '').trim();
    const title = toText(options.title, '空').trim() || '空';
    const value = toText(options.value, '').trim();
    const meta = toText(options.meta, '').trim();
    const rawNote = toText(options.note, '').trim();
    const tone = toText(options.tone, '').trim();
    const requestedSize = toText(options.size, '').trim();
    const size = requestedSize || 'compact';
    const longPressPreview = toText(options.longPressPreview, '').trim();
    const longPressDelay = Math.max(250, toNumber(options.longPressDelay, 600));
    const badgeLimit =
      options.badgeLimit != null
        ? Math.max(0, toNumber(options.badgeLimit, size === 'hero' ? 2 : 1))
        : size === 'hero'
          ? 2
          : 1;
    const metricLimit =
      options.metricLimit != null
        ? Math.max(0, toNumber(options.metricLimit, size === 'hero' ? 3 : 1))
        : size === 'hero'
          ? 3
          : 1;
    const rowLimit =
      options.rowLimit != null
        ? Math.max(0, toNumber(options.rowLimit, size === 'hero' ? 2 : 1))
        : size === 'hero'
          ? 2
          : 1;
    const badges = collectShellBadgeItems(options.badges || [], badgeLimit);
    const metrics = collectShellMetricItems(options.metrics || [], metricLimit);
    const rows = collectShellLineItems(options.rows || [], rowLimit);
    const note = size === 'hero' || !rows.length ? rawNote : '';
    const className = [
      'mvu-shell-summary',
      tone ? `mvu-shell-summary--${tone}` : '',
      size ? `mvu-shell-summary--${size}` : '',
      value ? 'has-value' : '',
      longPressPreview ? 'nsfw-trigger-title' : '',
    ]
      .filter(Boolean)
      .join(' ');
    const longPressAttrs = longPressPreview
      ? ` data-longpress="${escapeHtmlAttr(longPressPreview)}" data-longpress-delay="${escapeHtmlAttr(String(longPressDelay))}"`
      : '';

    return `
        <div class="${className}"${longPressAttrs}>
          <div class="mvu-shell-card-top">
            <div class="mvu-shell-card-copy">
              <div class="mvu-shell-title">${htmlEscape(title)}</div>
              ${meta ? `<div class="mvu-shell-meta">${htmlEscape(meta)}</div>` : ''}
            </div>
            ${value ? `<div class="mvu-shell-value">${htmlEscape(value)}</div>` : ''}
          </div>
          ${
            badges.length
              ? `
            <div class="mvu-shell-chip-row">
              ${badges.map(item => `<span class="mvu-shell-chip${item.tone ? ` is-${htmlEscape(item.tone)}` : ''}">${htmlEscape(item.text)}</span>`).join('')}
            </div>
          `
              : ''
          }
          ${
            metrics.length
              ? `
            <div class="mvu-shell-metric-grid">
              ${metrics
                .map(
                  item => `
                <div class="mvu-shell-metric${item.tone ? ` is-${htmlEscape(item.tone)}` : ''}"${item.提示文本 ? ` title="${escapeHtmlAttr(item.提示文本)}"` : ''}>
                  <span class="mvu-shell-metric-label">${htmlEscape(item.label)}</span>
                  <strong class="mvu-shell-metric-value">${item.值Html || htmlEscape(item.value)}</strong>
                </div>
              `,
                )
                .join('')}
            </div>
          `
              : ''
          }
          ${
            rows.length
              ? `
            <div class="mvu-shell-line-list">
              ${rows
                .map(
                  item => `
                <div class="mvu-shell-line">
                  <span class="mvu-shell-line-label">${htmlEscape(item.label)}</span>
                  <span class="mvu-shell-line-value">${htmlEscape(item.value)}</span>
                </div>
              `,
                )
                .join('')}
            </div>
          `
              : ''
          }
          ${note ? `<div class="mvu-shell-card-note">${htmlEscape(note)}</div>` : ''}
        </div>
      `;
  }

  function buildShellEmptyCard(title, note, options = {}) {
    return buildShellSummaryCard({
      kicker: options.kicker || '',
      title,
      value: note || '空',
      tone: options.tone || 'muted',
    });
  }

  function buildShellAppPeek(options = {}) {
    const value = toText(options.value, '暂无信息').trim() || '暂无信息';
    const meta = toText(options.meta, '').trim();
    const note = toText(options.note, '').trim();
    const tone = toText(options.tone, '').trim();
    return `
        <div class="mvu-shell-app-peek${tone ? ` is-${htmlEscape(tone)}` : ''}">
          <div class="mvu-shell-app-peek-value">${htmlEscape(value)}</div>
          ${meta ? `<div class="mvu-shell-app-peek-meta">${htmlEscape(meta)}</div>` : ''}
          ${note ? `<div class="mvu-shell-app-peek-note">${htmlEscape(note)}</div>` : ''}
        </div>
      `;
  }

  function isShellPlaceholderText(value) {
    const text = toText(value, '').trim();
    if (!text) return true;
    const normalized = text.replace(/\s+/g, '');
    return /^(无|暂无|暂无记录|暂无收录|暂无待办|暂无委托|暂无待读|暂无时间线|暂无事件|暂无播报|暂无新线索|暂无警报|暂无变化|暂无见闻|待命中|未同步|时间未同步|未设置|未记录|未收录|--)$/.test(
      normalized,
    );
  }

  function resolveShellText(value, fallback = '') {
    const text = toText(value, '').trim();
    if (!isShellPlaceholderText(text)) return text;
    const fallbackText = toText(fallback, '').trim();
    return isShellPlaceholderText(fallbackText) ? '' : fallbackText;
  }

  function normalizeUserFacingTrackLabel(value, fallback = '') {
    const text = toText(value, fallback).trim() || toText(fallback, '').trim();
    if (!text) return '';
    return text
      .replace(/血脉副轨/g, '血脉')
      .replace(/武魂副轨/g, '第2武魂')
      .replace(/副轨/g, '第2武魂');
  }

  function summarizeShellIdentityText(value, options = {}) {
    const limit = Math.max(4, toNumber(options.limit, 12));
    const preferFirst = options.preferFirst !== false;
    const rawText = resolveShellText(value, '').trim();
    if (!rawText) return '';
    const cleaned = rawText
      .replace(/（[^）]*）/g, '')
      .replace(/\([^)]*\)/g, '')
      .replace(/[；;，,。].*$/, '')
      .replace(/\s+/g, ' ')
      .trim();
    if (!cleaned) return '';
    const pieces = cleaned
      .split(/[｜|/／、]/)
      .map(item => toText(item, '').trim())
      .filter(Boolean);
    const resolved = preferFirst && pieces.length ? pieces[0] : cleaned;
    return shortenText(resolved || cleaned, limit);
  }

  function isRenderableShellRing(ring) {
    if (!ring || typeof ring !== 'object') return false;
    const title = resolveShellText(ring.title, '');
    const desc = resolveShellText(ring.desc, '');
    const skills = Array.isArray(ring.skills)
      ? ring.skills.filter(skill => resolveShellText(skill && skill.name, '')).length
      : 0;
    return !!title || !!desc || skills > 0;
  }

  function isRenderableShellSoul(soul) {
    if (!soul || typeof soul !== 'object') return false;
    const spiritName = resolveShellText(soul.spiritName || soul.desc || soul.name, '');
    const description = resolveShellText(soul.description, '');
    const state = toText(soul.state, '').trim();
    const ringCount = Array.isArray(soul.魂环) ? soul.魂环.filter(isRenderableShellRing).length : 0;
    if (ringCount > 0) return true;
    if (spiritName && !/^(未设置|魂灵槽位)$/.test(spiritName)) return true;
    if (description && !/^(尚未接入魂灵。|未设置)$/.test(description)) return true;
    return !!state && !/^(未知|未激活|未设置)$/.test(state);
  }

  function buildShellSpiritSummaryCard(config, options = {}) {
    const primary = !!(options && options.primary);
    if (!config) {
      return buildShellEmptyCard(
        primary ? '主武魂' : normalizeUserFacingTrackLabel('', '第2武魂'),
        primary ? '未接入' : '未启用',
      );
    }

    if (config.kind === 'bloodline') {
      const 血脉状态文本 = 构建血脉状态文本_桥接(config);
      const 主动数量 = Array.isArray(config.bloodSkills) ? config.bloodSkills.length : 0;
      const 被动数量 = Array.isArray(config.bloodPassives) ? config.bloodPassives.length : 0;
      const 血环数量 = Array.isArray(config.魂环) ? config.魂环.length : 0;
      return buildShellSummaryCard({
        kicker: '血脉',
        title: shortenText(toText(config.bloodline, '未觉醒'), 20),
        value: config.使用封印界面 ? `封印 ${toText(config.sealLv, '0')} 层` : `主动 ${主动数量} / 被动 ${被动数量}`,
        meta: config.使用封印界面
          ? `核心 ${shortenText(toText(config.core, '未凝核'), 16)}`
          : shortenText(toText(config.desc, 血脉状态文本), 22),
        badges: config.使用封印界面
          ? [
              config.lifeFire ? { text: '命火已燃', tone: 'gold' } : { text: '命火未燃' },
              ...(config.魂环 || []).slice(0, 2).map(item => shortenText(toText(item && item.title, ''), 16)),
            ]
          : (config.魂环 || []).slice(0, 2).map(item => shortenText(toText(item && item.title, ''), 16)),
        metrics: [
          ...(config.使用封印界面 || 血环数量 ? [{ label: '血环', value: String(血环数量 || 0), tone: 'gold' }] : []),
          { label: '技能', value: String(主动数量 || 0) },
          { label: '特性', value: String(被动数量 || 0) },
        ],
        rows: [
          { label: '状态', value: config.使用封印界面 ? (config.lifeFire ? '已点燃' : '等待命火') : 血脉状态文本 },
          { label: '概览', value: shortenText(toText(config.desc, '未记录'), 28) },
        ],
        tone: 'gold',
      });
    }

    const renderableSouls = Array.isArray(config.souls) ? config.souls.filter(isRenderableShellSoul) : [];
    const primarySoul = renderableSouls[0] || null;
    const callableElements = Array.isArray(config.spiritCallableElements) ? config.spiritCallableElements : [];
    const soulCount = renderableSouls.length || Math.max(0, toNumber(config.soulCount, 0));
    const ringCount = Array.isArray(config.魂环) ? config.魂环.filter(isRenderableShellRing).length : 0;
    const hasSpiritProgress = !!primarySoul || soulCount > 0 || ringCount > 0;
    if (!hasSpiritProgress) {
      return buildShellSummaryCard({
        kicker: primary ? '主武魂' : normalizeUserFacingTrackLabel(config.badge, '第2武魂'),
        title: shortenText(toText(config.spiritName || config.name, primary ? '主武魂' : '第2武魂'), 20),
        value: '待接魂环',
        meta: shortenText(toText(config.spiritType, '未定'), 18),
        rows: [{ label: '状态', value: '未接魂环' }],
        tone: primary ? 'live' : 'cyan',
      });
    }
    const renderableRings = (config.魂环 || []).filter(isRenderableShellRing);
    return buildShellSummaryCard({
      kicker: primary ? '主武魂' : normalizeUserFacingTrackLabel(config.badge, '第2武魂'),
      title: shortenText(
        toText(
          config.spiritName || config.name,
          primary ? '主武魂' : normalizeUserFacingTrackLabel(config.badge, '第2武魂'),
        ),
        20,
      ),
      value: `${soulCount} 枚魂灵`,
      meta: `${shortenText(toText(config.spiritType, '未定'), 12)} · ${shortenText(toText(config.spiritElement, '未定'), 12)}`,
      badges: [
        primarySoul ? shortenText(toText(primarySoul.spiritName || primarySoul.desc, ''), 16) : '',
        ...renderableRings.slice(0, 2).map(item => shortenText(toText(item && item.title, ''), 16)),
        ...callableElements.slice(0, 1).map(item => shortenText(toText(item, ''), 14)),
      ],
      metrics: [
        { label: '契合', value: primarySoul ? toText(primarySoul.comp, '--') : '--', tone: 'live' },
        { label: '年限', value: primarySoul ? shortenText(toText(primarySoul.age, '--'), 12) : '--' },
        { label: '魂环', value: String(ringCount || 0) },
        {
          label: '元素',
          value: String(callableElements.length || 0),
        },
      ],
      rows: [
        {
          label: '主魂灵',
          value: primarySoul ? shortenText(toText(primarySoul.spiritName || primarySoul.desc, '未接入'), 24) : '未接入',
        },
        { label: '状态', value: primarySoul ? toText(primarySoul.state, '未知') : '等待唤醒' },
      ],
      tone: primary ? 'live' : 'cyan',
    });
  }

  function buildShellHomeArchiveCard(snapshot) {
    if (!snapshot) {
      return buildShellAppPeek({
        value: toText(snapshot && snapshot.activeName, '当前聊天'),
        meta: '待同步',
        note: '当前聊天',
        tone: 'gold',
      });
    }
    const stat = deepGet(snapshot, 'activeChar.属性', {});
    const status = deepGet(snapshot, 'activeChar.状态', {});
    const placeText = buildShellLocationLabel(snapshot, { fullLimit: 18, trailLimit: 8 });
    return buildShellAppPeek({
      value: toText(snapshot.activeName, '当前角色'),
      meta: `${formatCultivationLevelBadge(stat.等级, '0')} · ${placeText}`,
      note: toText(status.行动, '日常'),
      tone: 'live',
    });
  }

  function buildShellLocationLabel(snapshot, options = {}) {
    const normalizedLoc = toText(snapshot && snapshot.normalizedLoc, '').trim();
    const currentLoc = toText(snapshot && snapshot.currentLoc, '').trim();
    const fullLimit = Math.max(8, toNumber(options.fullLimit, 18));
    const trailLimit = Math.max(6, toNumber(options.trailLimit, 8));
    if (!normalizedLoc && !currentLoc) return '未知地点';
    if (
      !normalizedLoc ||
      normalizedLoc === currentLoc ||
      currentLoc.startsWith(`${normalizedLoc}-`) ||
      currentLoc.startsWith(`${normalizedLoc}·`)
    ) {
      return shortenText(currentLoc || normalizedLoc, fullLimit);
    }
    return `${shortenText(normalizedLoc, trailLimit)} · ${shortenText(currentLoc || normalizedLoc, trailLimit)}`;
  }

  function 获取首页当前位置摘要(snapshot, options = {}) {
    const 完整限制 = Math.max(12, toNumber(options.完整限制, 34));
    const 地图限制 = Math.max(8, toNumber(options.地图限制, 16));
    const 原始位置 = toText(
      deepGet(snapshot, 'activeChar.状态.位置', snapshot && snapshot.currentLoc),
      snapshot && snapshot.currentLoc ? snapshot.currentLoc : '未知地点',
    )
      .replace(/^斗罗大陆-/, '')
      .replace(/^斗灵大陆-/, '');
    const 标准位置 = toText(snapshot && snapshot.normalizedLoc, '')
      .replace(/^斗罗大陆-/, '')
      .replace(/^斗灵大陆-/, '');
    const 展示位置 =
      标准位置 && 原始位置 && 原始位置 !== 标准位置
        ? `${shortenText(标准位置, 12)} / ${shortenText(原始位置, 完整限制)}`
        : shortenText(原始位置 || 标准位置 || '未知地点', 完整限制);
    const 地图名称 = shortenText(getMapDisplayName(snapshot), 地图限制);
    return {
      展示位置,
      完整位置: 原始位置 || 标准位置 || '未知地点',
      地图名称,
    };
  }

  function 构建首页当前位置页脚(snapshot, options = {}) {
    const 摘要 = 获取首页当前位置摘要(snapshot, options);
    const 右侧文本 = toText(options && options.右侧文本, '').trim();
    const 右侧样式 = toText(options && options.右侧样式, '').trim();
    return `
        <div class="module-foot module-foot--location">
          <button type="button" class="mvu-home-location-link clickable" data-preview="当前节点详情" title="${escapeHtmlAttr(`当前位置 / ${摘要.完整位置}`)}">
            <b>当前位置</b>
            <span>${htmlEscape(摘要.展示位置)}</span>
          </button>
          ${右侧文本 ? `<span class="enter-chip mvu-home-location-chip ${htmlEscape(右侧样式)}">${htmlEscape(右侧文本)}</span>` : `<span class="enter-chip mvu-home-location-chip">${htmlEscape(摘要.地图名称)}</span>`}
        </div>
      `;
  }

  function 构建首页状态页脚({ 文本 = '', 样式 = '' } = {}) {
    const 状态文本 = toText(文本, '').trim();
    if (!状态文本) return '';
    const 状态样式 = toText(样式, '').trim();
    return `
        <div class="module-foot module-foot--location">
          <span class="enter-chip mvu-home-location-chip ${htmlEscape(状态样式)}">${htmlEscape(状态文本)}</span>
        </div>
      `;
  }

  function buildShellHomeMapCard(snapshot) {
    if (!snapshot) {
      return buildShellAppPeek({
        value: '地图待同步',
        meta: '待同步',
        note: '当前聊天',
      });
    }
    const 本地人物数量 = getShellLocalCharacterEntries(snapshot, 99).length;
    return buildShellAppPeek({
      value: shortenText(toText(snapshot.normalizedLoc || snapshot.currentLoc, '未命名节点'), 14),
      meta: `${本地人物数量} 名在场 · ${toText(snapshot && snapshot.价格带, '平稳')}`,
      note: shortenText(getMapDisplayName(snapshot), 18),
      tone: 'live',
    });
  }

  function buildShellHomeWorldCard(snapshot) {
    if (!snapshot) {
      return buildShellAppPeek({
        value: '世界待同步',
        meta: '待同步',
        note: '当前聊天',
      });
    }
    const rawWorldTime = toText(
      deepGet(
        snapshot,
        'rootData.world.时间._calendar',
        deepGet(snapshot, 'rootData.world.时间.calendar', '时间未同步'),
      ),
      '时间未同步',
    );
    const worldTime = resolveShellText(rawWorldTime, '等待同步');
    const deviation = toNumber(deepGet(snapshot, 'rootData.world.偏差值', 0), 0);
    const 偏差倍率 = toNumber(deepGet(snapshot, 'rootData.world.偏差倍率', 1), 1);
    const 偏差状态 = deviation >= 40 ? '高危' : deviation >= 10 ? '波动' : '平稳';
    const worldAlertText = resolveShellText(snapshot.worldAlert, '');
    const 近期安排摘要 = buildRecentPlanSummary(snapshot, { worldLimit: 1, recordLimit: 1 });
    const timelineNote = 近期安排摘要.worldPlans[0] ? toText(近期安排摘要.worldPlans[0].desc, '') : '';
    const headline = worldAlertText || timelineNote || (rawWorldTime !== '时间未同步' ? '世界时钟' : '世界平稳');
    return buildShellAppPeek({
      value: shortenText(toText(headline, '世界平稳'), 14),
      meta: shortenText(worldTime || '等待同步', 18),
      note: shortenText(worldAlertText || timelineNote || `偏差 ${偏差状态} x${偏差倍率}`, 18),
      tone: worldAlertText ? (deviation >= 40 ? 'warn' : 'gold') : deviation >= 10 ? 'gold' : 'live',
    });
  }

  function buildShellHomeOrgCard(snapshot) {
    if (!snapshot) {
      return buildShellAppPeek({
        value: '势力待同步',
        meta: '待同步',
        note: '当前聊天',
        tone: 'gold',
      });
    }
    const primaryFactionEntry = getPrimaryFactionEntry(snapshot);
    const primaryFaction = snapshot.势力[0] || null;
    const factionName = primaryFaction
      ? primaryFaction[0]
      : primaryFactionEntry.name || toText(deepGet(snapshot, 'locationData.掌控势力', '未加入'), '未加入');
    const roleText = primaryFaction
      ? toText(deepGet(primaryFaction[1], '身份', '未加入'), '未加入')
      : toText(deepGet(primaryFactionEntry.data, '身份', '未加入'), '未加入');
    return buildShellAppPeek({
      value: shortenText(toText(factionName, '未加入'), 14),
      meta: `身份 ${shortenText(roleText, 10)}`,
      note: `${(snapshot.orgEntries || []).length || 0} 个势力焦点`,
      tone: 'gold',
    });
  }

  function buildShellHomeTerminalCard(snapshot) {
    if (!snapshot) {
      return buildShellAppPeek({
        value: '终端待同步',
        meta: '待同步',
        note: '当前聊天',
      });
    }
    const latestRequest = resolveShellText(
      (snapshot.pendingRequests || [])[0],
      resolveShellText(deepGet(snapshot, 'rootData.sys.系统播报', ''), '待命中'),
    );
    const intelCount = (snapshot.unlockedKnowledges || []).length || 0;
    return buildShellAppPeek({
      value: intelCount
        ? `${intelCount} 条情报`
        : snapshot.questRecordCount
          ? `${snapshot.questRecordCount} 项任务`
          : '系统在线',
      meta: `${snapshot.questRecordCount || 0} 项任务 · ${(snapshot.bestiaryEntries || []).length || 0} 条图鉴`,
      note: shortenText(latestRequest || '待命中', 18),
      tone: intelCount ? 'gold' : snapshot.questRecordCount ? 'gold' : 'live',
    });
  }

  function buildShellArchiveCoreCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '角色首页',
        title: toText(snapshot && snapshot.activeName, '当前聊天'),
        value: '待同步',
        meta: '当前聊天',
        metrics: [
          { label: '状态', value: '待同步' },
          { label: '地点', value: '--' },
          { label: '阵营', value: '--' },
          { label: '关系', value: '--' },
        ],
        rows: [
          { label: '页面', value: '档案' },
          { label: '数据', value: '未接入' },
        ],
        tone: 'hero',
        size: 'hero',
      });
    }
    const stat = deepGet(snapshot, 'activeChar.属性', {});
    const social = deepGet(snapshot, 'activeChar.社交', {});
    const status = deepGet(snapshot, 'activeChar.状态', {});
    const primaryFactionName = snapshot.primaryFaction ? snapshot.primaryFaction[0] : '未加入';
    const primaryFactionRole = snapshot.primaryFaction
      ? toText(deepGet(snapshot.primaryFaction[1], '身份', '未加入'), '未加入')
      : '未加入';
    const titleText =
      Array.isArray(snapshot.recentTitles) && snapshot.recentTitles.length ? snapshot.recentTitles[0] : '';
    const nextLevelSoul = getNextLevelSoulRequirementWithCap(stat, deepGet(snapshot, 'activeChar', {}));
    const hasSoulPowerMeter = toNumber(stat.魂力上限, 0) > 0;
    const hasVitalityMeter = toNumber(stat.体力上限, 0) > 0;
    const hasMentalMeter = toNumber(stat.精神力上限, 0) > 0;
    const ageMetric = toNumber(stat.年龄, 0);
    const 性别文本 = toText(stat.性别, '未知');
    const talentMetric = shortenText(读取属性天赋梯队(stat), 8);
    const factionJoined = primaryFactionName !== '未加入';
    const nextLevelNeeded = Math.max(0, toNumber(nextLevelSoul && nextLevelSoul.needed, 0));
    const hpPair = getDisplayHpPair(stat);
    const woundText = getDisplayWoundLabel(stat);
    const injurySummary = buildInjurySummaryText(status, { limit: 2, empty: '无' });
    const 体征摘要 =
      injurySummary && injurySummary !== '无' ? injurySummary : woundText && woundText !== '无' ? woundText : '无伤';
    const identitySummary =
      summarizeShellIdentityText(social.主身份, { limit: 12 }) || shortenText(toText(social.主身份, ''), 14);
    const factionSummary = factionJoined
      ? `${shortenText(primaryFactionName, 8)} / ${shortenText(primaryFactionRole, 8)}`
      : identitySummary || '独行';
    const fameLevelText = shortenText(toText(social.名望等级, toText(social.名望等级, '籍籍无名')), 8);
    const allowPrivateArchiveLongPress = canOpenPrivateArchive(snapshot);
    return buildShellSummaryCard({
      kicker: '角色首页',
      title: toText(snapshot.activeName, '当前角色'),
      value: formatCultivationLevelBadge(stat.等级, '0'),
      meta: factionSummary || identitySummary || '档案',
      badges: [
        titleText ? { text: shortenText(titleText, 10), tone: 'gold' } : '',
        factionJoined ? { text: shortenText(primaryFactionName, 10), tone: 'live' } : '',
        fameLevelText && fameLevelText !== '籍籍无名' ? { text: fameLevelText, tone: 'gold' } : '',
      ],
      metrics: [
        hpPair.hpMax > 0
          ? 构建属性指标项('HP', hpPair.hp, hpPair.hpMax, 'warn')
          : { label: '年龄', value: ageMetric > 0 ? String(ageMetric) : '--' },
        hasVitalityMeter
          ? 构建属性指标项('体力', stat.体力, stat.体力上限, 'gold')
          : { label: '天赋', value: talentMetric || '--', tone: 'gold' },
        hasSoulPowerMeter
          ? 构建属性指标项('魂力', stat.魂力, stat.魂力上限, 'live')
          : { label: '天赋', value: talentMetric || '--', tone: 'gold' },
        hasMentalMeter
          ? 构建属性指标项('精神', stat.精神力, stat.精神力上限)
          : { label: '年龄', value: ageMetric > 0 ? String(ageMetric) : '--' },
      ],
      rows: [
        { label: '身体', value: 体征摘要 || '--' },
        { label: factionJoined ? '阵营' : '身份', value: factionSummary },
        { label: '名望', value: social.声望 ? `${fameLevelText} · ${formatNumber(social.声望)}` : fameLevelText },
        { label: '年龄', value: `${ageMetric > 0 ? ageMetric : '--'}岁 / ${性别文本}` },
      ],
      tone: 'hero',
      size: 'hero',
      metricLimit: 4,
      rowLimit: 3,
      longPressPreview: allowPrivateArchiveLongPress ? PRIVATE_ARCHIVE_PREVIEW_KEY : '',
      longPressDelay: 600,
    });
  }

  function buildShellArmoryCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '武装',
        title: '装配摘要',
        value: '待同步',
        meta: '当前聊天',
        rows: [
          { label: '斗铠', value: '--' },
          { label: '机甲', value: '--' },
          { label: '主武器', value: '--' },
        ],
      });
    }
    const armor = deepGet(snapshot, 'activeChar.装备.斗铠', {});
    const mech = deepGet(snapshot, 'activeChar.装备.机甲', {});
    const weapon = deepGet(snapshot, 'activeChar.装备.武器', {});
    const jobs = safeEntries(deepGet(snapshot, 'activeChar.职业', {}));
    const jobSummary = jobs.length ? `${jobs[0][0]} Lv.${读取职业显示等级(jobs[0][1])}` : '未开启';
    const weaponName = toText(weapon.名称, '').trim();
    const hasArmor = toNumber(armor.等级, 0) > 0;
    const hasWeapon = !!weaponName && !/^(无|未记录)$/.test(weaponName);
    const hasMech = !!toText(mech.等级, '').trim();
    const hasLoadout = hasArmor || hasWeapon || hasMech || (snapshot.soulBoneEntries || []).length;
    const armorSummary = toNumber(armor.等级, 0) > 0 ? toText(armor.名称, `${armor.等级}字斗铠`) : '无';
    const mechSummary = toText(mech.等级, '')
      ? `${toText(mech.名称 || mech['名称'], `${toText(mech.等级, '')}机甲`)} · ${toText(mech.型号, '均衡')}`
      : '无';
    if (!hasLoadout) {
      return buildShellSummaryCard({
        title: jobs.length ? '工坊' : '武装',
        value: jobs.length ? shortenText(jobSummary, 16) : '0',
        meta: jobs.length ? '副职已记录' : '无武装',
        rows: [{ label: jobs.length ? '副职' : '斗铠', value: jobs.length ? shortenText(jobSummary, 16) : '无' }],
      });
    }
    return buildShellSummaryCard({
      kicker: '武装',
      title: '武装',
      value: toNumber(armor.等级, 0) > 0 ? shortenText(toText(armor.名称, `${armor.等级}字斗铠`), 12) : '无',
      meta: shortenText(armorSummary, 24),
      metrics: [
        { label: '机甲', value: toText(mech.等级, '--') || '--' },
        { label: '魂骨', value: String((snapshot.soulBoneEntries || []).length || 0), tone: 'gold' },
      ],
      rows: [
        { label: '主武器', value: shortenText(toText(weapon.名称, '未记录'), 14) },
        { label: '工坊', value: shortenText(jobSummary, 14) },
        { label: '机甲', value: shortenText(mechSummary, 14) },
      ],
    });
  }

  function buildShellVaultCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '仓库',
        title: '资源概览',
        value: '待同步',
        meta: '当前聊天',
        rows: [
          { label: '联邦', value: '--' },
          { label: '星罗', value: '--' },
        ],
      });
    }
    const wealth = deepGet(snapshot, 'activeChar.财富', {});
    const inventoryCount = (snapshot.inventoryEntries || []).length || 0;
    const fedCoin = toNumber(wealth.联邦币, 0);
    const starCoin = toNumber(wealth.星罗币, 0);
    const tangPt = toNumber(wealth.唐门积分, 0);
    const bloodPt = toNumber(wealth.战功, 0);
    const hasStoredResources = inventoryCount > 0 || fedCoin > 0 || starCoin > 0 || tangPt > 0 || bloodPt > 0;
    if (!hasStoredResources) {
      return buildShellSummaryCard({
        title: '仓库',
        value: '0',
        meta: '无物资',
        rows: [{ label: '货币', value: '0' }],
      });
    }
    return buildShellSummaryCard({
      kicker: '仓库',
      title: '仓库',
      value: `${formatNumber(inventoryCount)} 物资`,
      meta: `流动资金 ${formatNumber(fedCoin)} / 星罗 ${formatNumber(starCoin)}`,
      metrics: [
        { label: '联邦', value: formatNumber(fedCoin), tone: 'live' },
        { label: '星罗', value: formatNumber(starCoin) },
        { label: '积分', value: formatNumber(tangPt), tone: 'gold' },
      ],
      rows: [
        { label: '血神', value: formatNumber(bloodPt) },
        { label: '物资', value: `${formatNumber(inventoryCount)} 种` },
      ],
    });
  }

  function 构建社交入口块(标题, 主值, 副值, 预览键, 色调 = '', 数量文本 = '') {
    const 标题文本 = toText(标题, '');
    const 主值文本 = toText(主值, '暂无');
    const 副值文本 = toText(副值, '');
    const 数量显示 = toText(数量文本, '').trim();
    const 标题属性 = [标题文本, 主值文本, 副值文本, 数量显示].filter(Boolean).join(' / ');
    return `
        <div class="mvu-social-entry clickable ${色调 ? `is-${色调}` : ''}" role="button" tabindex="0" data-preview="${escapeHtmlAttr(预览键)}" data-detail-mode="embed" title="${escapeHtmlAttr(标题属性)}">
          <b class="mvu-social-entry-label">${htmlEscape(标题文本)}</b>
          <strong class="mvu-social-entry-main">${htmlEscape(主值文本)}</strong>
          <span class="mvu-social-entry-sub">${htmlEscape(副值文本)}</span>
          ${数量显示 ? `<em class="mvu-social-entry-count">${htmlEscape(数量显示)}</em>` : ''}
        </div>
      `;
  }

  function buildShellSocialCard(snapshot) {
    if (!snapshot) {
      return `
          <div class="mvu-social-entry-grid">
            ${构建社交入口块('名望', '待同步', '社会档案', '社会档案详细页')}
            ${构建社交入口块('势力', '待同步', '所属势力', '所属势力详细页')}
            ${构建社交入口块('关系', '待同步', '人物关系', '人物关系详细页')}
            ${构建社交入口块('情报', '待同步', '情报库', '情报库详细页')}
          </div>
        `;
    }
    const social = deepGet(snapshot, 'activeChar.社交', {});
    const primaryFactionName = snapshot.primaryFaction ? snapshot.primaryFaction[0] : '未加入';
    const primaryFactionRole = snapshot.primaryFaction
      ? toText(deepGet(snapshot.primaryFaction[1], '身份', '未加入'), '未加入')
      : '未加入';
    const topRelationText = snapshot.topRelation
      ? `${shortenText(snapshot.topRelation[0], 8)} / ${toText(deepGet(snapshot.topRelation[1], '关系', '陌生'), '陌生')} / ${toNumber(deepGet(snapshot.topRelation[1], '好感度', 0), 0)}`
      : '暂无高亮关系';
    const latestIntelText = getLatestUnlockedIntelText(snapshot, 12, '暂无');
    const fameLevel = toText(social.名望等级, toText(social.名望等级, '籍籍无名'));
    const reputationText = formatNumber(social.声望);
    const mainIdentity = toText(social.主身份, '') || summarizeShellIdentityText(social.主身份, { limit: 12 });
    const factionSummary = primaryFactionName === '未加入' ? mainIdentity || '未结盟' : primaryFactionName;
    const intelCount = (snapshot.unlockedKnowledges || []).length || 0;
    return `
        <div class="mvu-social-entry-grid">
          ${构建社交入口块('名望', fameLevel, mainIdentity || '社会档案', '社会档案详细页', 'gold', `声望 ${reputationText}`)}
          ${构建社交入口块('势力', factionSummary, primaryFactionRole, '所属势力详细页', 'live', `${(snapshot.势力 || []).length || 0} 项`)}
          ${构建社交入口块('关系', topRelationText, '人物关系', '人物关系详细页', '', `${(snapshot.relations || []).length || 0} 条`)}
          ${构建社交入口块('情报', latestIntelText, snapshot.publicIntel ? '公开情报' : '情报库', '情报库详细页', '', `${intelCount} 条`)}
        </div>
      `;
  }

  function getShellLocalCharacterEntries(snapshot, limit = 6, 选项 = {}) {
    if (!snapshot) return [];
    const activeCharKey = resolveSnapshotCharKey(snapshot, toText(snapshot.activeName, ''));
    const activeDisplayName = toText(
      deepGet(snapshot, 'activeChar.name', deepGet(snapshot, 'activeChar.base.name', snapshot.activeName)),
      snapshot.activeName,
    );
    const currentLoc = toText(deepGet(snapshot, 'activeChar.状态.位置', snapshot.currentLoc), snapshot.currentLoc);
    const normalizedLoc = toText(snapshot.normalizedLoc, currentLoc);
    const 目标地点 = toText(选项 && 选项.目标地点, '').trim();
    const 标准地点 = toText(选项 && 选项.标准地点, '').trim();
    const 指定地点列表 = (目标地点 ? [目标地点] : [标准地点])
      .map(item => toText(item, '').trim())
      .filter((item, index, list) => item && list.indexOf(item) === index);
    const 地图快照 =
      window.__sheepMapSnapshot && typeof window.__sheepMapSnapshot === 'object' ? window.__sheepMapSnapshot : null;
    if (指定地点列表.length && 地图快照 && 地图快照.charactersByLoc instanceof Map) {
      const 已收录人物 = new Set();
      const 角色表 = deepGet(snapshot, 'rootData.char', {});
      return 指定地点列表
        .flatMap(地点 => 地图快照.charactersByLoc.get(地点) || [])
        .filter(人物条目 => {
          const 人物名 = toText(人物条目 && 人物条目.name, '');
          if (!人物名 || 已收录人物.has(人物名)) return false;
          已收录人物.add(人物名);
          return true;
        })
        .map(人物条目 => {
          const 人物名 = toText(人物条目 && 人物条目.name, '');
          return [
            toText(人物条目 && 人物条目.id, 人物名),
            (人物条目 && 人物条目.raw) || 角色表[人物名] || {},
            人物条目,
          ];
        })
        .slice(0, Math.max(1, toNumber(limit, 6)));
    }
    const 默认地点列表 = [currentLoc, normalizedLoc]
      .map(item => toText(item, '').trim())
      .filter((item, index, list) => item && list.indexOf(item) === index);
    const 匹配地点列表 = 指定地点列表.length ? 指定地点列表 : 默认地点列表;
    return safeEntries(deepGet(snapshot, 'rootData.char', {}))
      .filter(([name, char]) => {
        const displayName = toText(deepGet(char, 'name', deepGet(char, 'base.name', name)), name);
        if ((activeCharKey && name === activeCharKey) || (activeDisplayName && displayName === activeDisplayName))
          return false;
        const npcLoc = toText(deepGet(char, '状态.位置', ''), '');
        if (!npcLoc) return false;
        return 匹配地点列表.some(地点 => isLocationCompatible(地点, npcLoc));
      })
      .slice(0, Math.max(1, toNumber(limit, 6)));
  }

  let 星图焦点态 = null;

  function buildShellMapCurrentCard(snapshot) {
    const currentMapDisplayName = getMapDisplayName(snapshot);
    const localFaction = toText(deepGet(snapshot, 'locationData.掌控势力', '未知'), '未知');
    const nodeStores = safeEntries(deepGet(snapshot, 'locationData.商店', {}));
    return buildShellSummaryCard({
      kicker: '地点',
      title: shortenText(toText(snapshot.normalizedLoc, snapshot.currentLoc), 22),
      value: shortenText(currentMapDisplayName, 16),
      meta: snapshot.normalizedLoc !== snapshot.currentLoc ? shortenText(snapshot.currentLoc, 22) : '',
      rows: [
        { label: '掌控', value: shortenText(localFaction, 22) },
        { label: '店铺', value: nodeStores.length ? `${nodeStores.length} 处` : '0' },
        { label: '供给', value: toText(snapshot && snapshot.本地供给, '无供给') },
        { label: '价格', value: toText(snapshot && snapshot.价格带, '无') },
        { label: '成交', value: toText(snapshot && snapshot.最近成交影响, '平稳') },
      ],
    });
  }

  function buildShellLocalRosterRows(localEntries, limit = 4, 选项 = {}) {
    const entries = (Array.isArray(localEntries) ? localEntries : []).slice(0, Math.max(1, toNumber(limit, 4)));
    const 启用操作 = !!(选项 && 选项.启用操作);
    const 当前地点 = toText(选项 && 选项.当前地点, '');
    if (!entries.length) {
      return '<div class="mvu-shell-roster-empty">暂无本地角色</div>';
    }
    return entries
      .map(([name, char, 地图人物条目]) => {
        const displayName = toText(deepGet(char, 'name', deepGet(char, 'base.name', name)), name);
        const identity =
          summarizeShellIdentityText(deepGet(char, '社交.主身份', ''), { limit: 14 }) ||
          shortenText(toText(deepGet(char, '社交.主身份', '未知身份'), '未知身份'), 14);
        const action = resolveShellText(deepGet(char, '状态.行动', ''), '日常') || '日常';
        const 可委托 = 获取角色工坊委托能力摘要(char).length > 0;
        const 允许人物操作 = 启用操作 && (!地图人物条目 || 地图人物条目.可交互 === true);
        const 摘要状态 =
          地图人物条目 && 地图人物条目.可交互 === false
            ? toText(地图人物条目.meta, `位于：${toText(地图人物条目.所在子节点, '子节点')}`)
            : action;
        const 操作按钮 = 允许人物操作
          ? `
            <div class="mvu-shell-roster-actions">
              <button type="button" class="mvu-shell-roster-action clickable" data-preview="角色档案：${escapeHtmlAttr(displayName)}">档案</button>
              <button type="button" class="mvu-shell-roster-action map-dispatch-action-btn live" data-action="talk" data-target="${escapeHtmlAttr(当前地点)}" data-current-loc="${escapeHtmlAttr(当前地点)}" data-npc-target="${escapeHtmlAttr(displayName)}">对话</button>
              <button type="button" class="mvu-shell-roster-action map-dispatch-action-btn" data-action="intel" data-target="${escapeHtmlAttr(当前地点)}" data-current-loc="${escapeHtmlAttr(当前地点)}" data-npc-target="${escapeHtmlAttr(displayName)}">请教</button>
              <button type="button" class="mvu-shell-roster-action map-dispatch-action-btn warn" data-action="battle" data-target="${escapeHtmlAttr(当前地点)}" data-current-loc="${escapeHtmlAttr(当前地点)}" data-npc-target="${escapeHtmlAttr(displayName)}">切磋</button>
              <button type="button" class="mvu-shell-roster-action map-dispatch-action-btn" data-action="trade" data-target="${escapeHtmlAttr(当前地点)}" data-current-loc="${escapeHtmlAttr(当前地点)}" data-npc-target="${escapeHtmlAttr(displayName)}">交易</button>
              ${可委托 ? `<button type="button" class="mvu-shell-roster-action map-dispatch-action-btn warn" data-action="commission" data-target="${escapeHtmlAttr(当前地点)}" data-current-loc="${escapeHtmlAttr(当前地点)}" data-npc-target="${escapeHtmlAttr(displayName)}" data-executor-type="private">委托</button>` : ''}
            </div>
          `
          : '';
        return `
          <div class="mvu-shell-roster-row${启用操作 ? ' mvu-shell-roster-row--interactive' : ''}">
            <button type="button" class="mvu-shell-roster-name clickable" data-preview="角色档案：${escapeHtmlAttr(displayName)}">${htmlEscape(shortenText(displayName, 12))}</button>
            <div class="mvu-shell-roster-meta">${htmlEscape(shortenText(identity, 18))}</div>
            <div class="mvu-shell-roster-state">${htmlEscape(shortenText(摘要状态, 22))}</div>
            ${操作按钮}
          </div>
        `;
      })
      .join('');
  }

  function buildShellMapLocalCharactersCard(snapshot) {
    const localEntries = getShellLocalCharacterEntries(snapshot, 4);
    const currentLoc = toText(deepGet(snapshot, 'activeChar.状态.位置', snapshot.currentLoc), snapshot.currentLoc);
    return `
        <div class="mvu-shell-roster-card">
          <div class="mvu-shell-roster-head">
            <div>
              <span>本地角色</span>
              <strong>${htmlEscape(shortenText(currentLoc, 22))}</strong>
            </div>
            <b>${htmlEscape(localEntries.length ? `${localEntries.length} 名` : '0')}</b>
          </div>
          <div class="mvu-shell-roster-list">
            ${buildShellLocalRosterRows(localEntries, 4, { 当前地点: currentLoc })}
          </div>
        </div>
      `;
  }

  function buildShellMapRouteCard(snapshot) {
    const routeCount = snapshot.mapTravelCandidates.length || snapshot.mapNodeLabels.length || 0;
    return buildShellSummaryCard({
      kicker: '跑图',
      title: '路线',
      value: `${routeCount} 条`,
      meta: `${shortenText(getMapDisplayName(snapshot), 18)} · ${safeEntries(snapshot.mapAvailableChildMaps).length} 个子图`,
      rows: [
        { label: '当前地图', value: shortenText(getMapDisplayName(snapshot), 22) },
        {
          label: '子图',
          value: safeEntries(snapshot.mapAvailableChildMaps).length
            ? `${safeEntries(snapshot.mapAvailableChildMaps).length} 个入口`
            : '暂无子图',
        },
        { label: '入口', value: routeCount ? `${routeCount} 条可用路线` : '暂无路线' },
      ],
    });
  }

  function buildShellMapDynamicCard(snapshot) {
    if (!snapshot || !snapshot.mapVisibleDynamicEntries.length) {
      return buildShellSummaryCard({
        title: '动态',
        value: '0',
        meta: '无地图动态',
        rows: [],
      });
    }
    return buildShellSummaryCard({
      kicker: '动态',
      title: '动态',
      value: `${snapshot.mapVisibleDynamicEntries.length || 0} 处`,
      meta: '地图节点',
      rows: [{ label: '动态地点', value: `${snapshot.mapVisibleDynamicEntries.length || 0} 处` }],
    });
  }

  function 处理星图焦点变更(event) {
    const 详情 = event && event.detail && typeof event.detail === 'object' ? event.detail : {};
    const 焦点名称 = toText(详情.焦点名称, '').trim();
    if (!焦点名称) return;
    星图焦点态 = {
      焦点名称,
      地图名称: toText(详情.地图名称, ''),
      类型: toText(详情.类型, ''),
      功能: toText(详情.功能, ''),
      可用: toText(详情.可用, ''),
      状态: toText(详情.状态, ''),
      地形: toText(详情.地形, ''),
      说明: toText(详情.说明, ''),
      自由坐标: !!详情.自由坐标,
      是否当前位置: !!详情.是否当前位置,
    };
    const 快照 = liveSnapshot || lastRenderableSnapshot;
    if (!快照) return;
    const 地图节点面板 = 读取地图模块星图节点面板(星图焦点态);
    setUnifiedCardMarkup(
      'map-current',
      地图节点面板 ? 地图节点面板.primaryHtml : '',
      {
        preview: 地图节点面板 ? toText(地图节点面板.primaryPreview, '') : '',
        surface: 'panel',
      },
    );
    setUnifiedCardMarkup('map-locals', 地图节点面板 ? 地图节点面板.secondaryHtml : '', {
      preview: 地图节点面板 ? toText(地图节点面板.secondaryPreview, '') : '',
      surface: 'panel',
    });
  }

  window.addEventListener('sheep-map-focus-change', 处理星图焦点变更);

  function buildShellWorldHeroCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '世界',
        title: '时空中枢',
        value: '待同步',
        meta: '当前聊天',
        metrics: [
          { label: '偏差', value: '--' },
          { label: '事件', value: '--' },
          { label: '阶段', value: '--' },
          { label: '森怨', value: '--' },
        ],
        note: '等待同步',
        tone: 'hero',
        size: 'hero',
      });
    }
    const rawWorldTime = toText(
      deepGet(
        snapshot,
        'rootData.world.时间._calendar',
        deepGet(snapshot, 'rootData.world.时间.calendar', '时间未同步'),
      ),
      '时间未同步',
    );
    const worldTime = resolveShellText(rawWorldTime, '等待同步');
    const deviation = toNumber(deepGet(snapshot, 'rootData.world.偏差值', 0), 0);
    const 偏差倍率 = toNumber(deepGet(snapshot, 'rootData.world.偏差倍率', 1), 1);
    const 偏差状态 = deviation >= 40 ? '高危' : deviation >= 10 ? '波动' : '平稳';
    const forestRatio = Math.max(
      0,
      Math.min(100, Number(((toNumber(snapshot.forestKilledAge, 0) / 1000000) * 100).toFixed(1))),
    );
    const 核心阶段 = 推断世界核心阶段(snapshot);
    return buildShellSummaryCard({
      kicker: '世界',
      title: '世界',
      value: 偏差状态,
      meta: shortenText(worldTime || '等待同步', 24),
      metrics: [
        { label: '时间', value: shortenText(worldTime || '等待同步', 12) },
        { label: '偏差', value: String(deviation), tone: deviation >= 40 ? 'warn' : deviation >= 10 ? 'gold' : 'live' },
        { label: '阶段', value: shortenText(核心阶段, 12) },
        {
          label: '森怨',
          value: `${forestRatio}%`,
          tone: forestRatio >= 70 ? 'warn' : forestRatio >= 30 ? 'gold' : 'live',
        },
      ],
      note: shortenText(`安全等级 ${偏差状态} / x${偏差倍率} / ${核心阶段}`, 34),
      tone: 'hero',
      size: 'hero',
    });
  }

  function 构建世界编年史条目(snapshot) {
    const 近期安排摘要 = buildRecentPlanSummary(snapshot, { worldLimit: 6, recordLimit: 4 });
    const 近期见闻摘要 = buildRecentNewsSummary(snapshot, { seqLimit: 6, intelLimit: 4 });
    const 生态警报文本 = resolveShellText(snapshot.worldAlert, '');
    const 拍卖状态 = resolveShellText(snapshot.auctionStatus, '休市');
    const 拍卖地点 = resolveShellText(snapshot.auctionLocation, '');
    const 存在拍卖活动 = 拍卖状态 !== '休市' || !!拍卖地点;
    const 拍卖刷新tick = toNumber(deepGet(snapshot, 'rootData.world.拍卖.下次刷新tick', 0), 0);
    const 拍品条目 = safeEntries(deepGet(snapshot, 'rootData.world.拍卖.拍品', {}));
    const 万年魂灵开放 = 判断传灵塔万年魂灵开放_桥接(deepGet(snapshot, 'rootData', {}));
    const 森林击杀年限 = toNumber(snapshot.forestKilledAge, 0);
    const 森林比例 = Math.max(0, Math.min(100, Number(((森林击杀年限 / 1000000) * 100).toFixed(1))));
    const 森林阶段 =
      森林比例 >= 100 ? '兽潮临界' : 森林比例 >= 70 ? '高度紧张' : 森林比例 >= 30 ? '持续升温' : '相对安全';
    const 警报描述 = [
      存在拍卖活动 ? `拍卖：${拍卖地点 ? `${拍卖状态} / ${拍卖地点}` : 拍卖状态}` : '拍卖：休市',
      拍卖刷新tick > 0 ? `刷新：${formatTickToCalendarDateText(拍卖刷新tick)}` : '',
      拍品条目.length
        ? `拍品：${拍品条目
            .slice(0, 3)
            .map(([名称]) => 名称)
            .join('、')}`
        : '',
      生态警报文本 ? `生态：${生态警报文本}` : '生态：平稳',
      万年魂灵开放 ? '传灵塔：万年魂灵开放' : '',
    ]
      .filter(Boolean)
      .join(' ｜ ');
    const 编年史条目 = [
      {
        title: htmlEscape('拍卖 / 警报'),
        desc: '',
        descLines: [
          存在拍卖活动 ? `拍卖：${拍卖地点 ? `${拍卖状态} / ${拍卖地点}` : 拍卖状态}` : '拍卖：休市',
          拍卖刷新tick > 0 ? `刷新：${formatTickToCalendarDateText(拍卖刷新tick)}` : '',
          拍品条目.length
            ? `拍品：${拍品条目
                .slice(0, 3)
                .map(([名称]) => 名称)
                .join('、')}`
            : '',
          生态警报文本 ? `生态：${生态警报文本}` : '生态：平稳',
          万年魂灵开放 ? '传灵塔：万年魂灵开放' : '',
        ],
        descTitle: 警报描述,
        className: 'hologram-chronicle-card--alert',
        preview: '拍卖与警报',
      },
      {
        title: htmlEscape('魂兽森林'),
        desc: '',
        descLines: [
          森林阶段,
          `累计击杀年限：${formatNumber(森林击杀年限)} / 1000000`,
          `仇恨进度：${森林比例}%`,
        ],
        className: 森林比例 >= 70 ? 'hologram-chronicle-card--alert' : 'hologram-chronicle-card--state',
        preview: '森林仇恨值',
      },
    ];
    const 安排条目 = (近期安排摘要.worldPlans || []).concat(近期安排摘要.personalPlans || []);
    const 见闻条目 = (近期见闻摘要.globalNews || []).concat(近期见闻摘要.personalNews || []);
    return 编年史条目.concat(
      (安排条目.length ? 安排条目 : 近期安排摘要.cards || []).map((条目, 序号) => ({
        title: htmlEscape(toText(条目 && 条目.title, '近期安排')),
        desc: '',
        descLines: [
          toText(条目 && 条目.时间摘要, '').trim(),
          toText(条目 && 条目.地点, '').trim() && !/^(无|未知|待定)$/.test(toText(条目 && 条目.地点, '').trim())
            ? `地点：${toText(条目 && 条目.地点, '').trim()}`
            : '',
          toText(条目 && 条目.状态, '').trim() ? `状态：${toText(条目 && 条目.状态, '').trim()}` : '',
          toText(条目 && 条目.事件, '').trim() || toText(条目 && 条目.desc, '暂无安排'),
          toText(条目 && 条目.后续, '').trim() ? `后续：${toText(条目 && 条目.后续, '').trim()}` : '',
        ],
        descTitle: toText(条目 && 条目.desc, ''),
        className: 'hologram-chronicle-card--plan',
        preview: `近期安排：${序号}`,
      })),
      (见闻条目.length ? 见闻条目 : 近期见闻摘要.cards || []).map((条目, 序号) => ({
        title: htmlEscape(toText(条目 && 条目.title, '近期见闻')),
        desc: '',
        descLines: [
          toNumber(条目 && 条目.触发tick, 0) > 0 ? `时间：${formatTickToCalendarDateText(toNumber(条目 && 条目.触发tick, 0))}` : '',
          toText(条目 && 条目.状态, '').trim() ? `状态：${toText(条目 && 条目.状态, '').trim()}` : '',
          toText(条目 && 条目.事件, '').trim() || toText(条目 && 条目.desc, '暂无见闻'),
          toText(条目 && 条目.影响, '').trim() ? `影响：${toText(条目 && 条目.影响, '').trim()}` : '',
          toText(条目 && 条目.后续, '').trim() ? `后续：${toText(条目 && 条目.后续, '').trim()}` : '',
        ],
        descTitle: toText(条目 && 条目.desc, ''),
        className: 'hologram-chronicle-card--news',
        preview: `近期见闻：${序号}`,
      })),
    );
  }

  function 构建世界编年史卡(snapshot) {
    const 编年史条目 = 构建世界编年史条目(snapshot || {});
    return `
        <div class="simple-head"><div class="simple-title">全息编年史</div></div>
        <div class="hologram-chronicle-track">${makeTimelineStack(编年史条目)}</div>
      `;
  }

  function 构建近期安排条目详情(snapshot, 序号) {
    const 近期安排摘要 = buildRecentPlanSummary(snapshot, { worldLimit: 6, recordLimit: 4 });
    const 条目列表 = (近期安排摘要.worldPlans || []).concat(近期安排摘要.personalPlans || []);
    const 条目 = 条目列表[序号] || 条目列表[0] || { title: '近期安排', desc: '暂无可展示的近期安排。' };
    const 触发tick = toNumber(条目 && 条目.触发tick, 0);
    const 进度值 = 条目 && 条目.进度 !== undefined ? `${toNumber(条目.进度, 0)}%` : '';
    const 信息项 = [
      { label: '来源', value: htmlEscape(toText(条目 && 条目.title, '近期安排').split('/')[0].trim() || '近期安排') },
      条目 && 条目.事件名 ? { label: '事件', value: htmlEscape(toText(条目.事件名, '')) } : null,
      触发tick > 0 ? { label: '触发时间', value: htmlEscape(formatTickToCalendarDateText(触发tick)) } : null,
      条目 && 条目.时间摘要 ? { label: '距离', value: htmlEscape(toText(条目.时间摘要, '')) } : null,
      条目 && 条目.地点 && !/^(无|未知|待定)$/.test(toText(条目.地点, '').trim())
        ? { label: '地点', value: htmlEscape(toText(条目.地点, '')) }
        : null,
      条目 && 条目.状态 ? { label: '状态', value: htmlEscape(toText(条目.状态, '')) } : null,
      进度值 ? { label: '进度', value: htmlEscape(进度值) } : null,
      条目 && 条目.后续 ? { label: '后续', value: htmlEscape(toText(条目.后续, '')) } : null,
    ].filter(Boolean);
    return {
      title: toText(条目 && 条目.title, '近期安排'),
      summary: '',
      body: `
          <div class="archive-modal-grid mvu-detail-grid--single">
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">安排详情</div></div>
              ${makeTimelineStack([
                {
                  title: htmlEscape(toText(条目 && 条目.title, '近期安排')),
                  desc: '',
                  descLines: [
                    toText(条目 && 条目.事件, '').trim() || toText(条目 && 条目.desc, '暂无安排'),
                    条目 && 条目.后续 ? `后续：${toText(条目.后续, '')}` : '',
                  ],
                },
              ])}
            </div>
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">节点信息</div></div>
              ${makeTileGrid(信息项.length ? 信息项 : [{ label: '状态', value: '暂无记录' }], 'two')}
            </div>
          </div>
        `,
    };
  }

  function 构建近期见闻条目详情(snapshot, 序号) {
    const 近期见闻摘要 = buildRecentNewsSummary(snapshot, { seqLimit: 6, intelLimit: 4 });
    const 条目列表 = (近期见闻摘要.globalNews || []).concat(近期见闻摘要.personalNews || []);
    const 条目 = 条目列表[序号] || 条目列表[0] || { title: '近期见闻', desc: '暂无新的全局或个人见闻。' };
    const 触发tick = toNumber(条目 && 条目.触发tick, 0);
    const 信息项 = [
      { label: '来源', value: htmlEscape(toText(条目 && 条目.title, '近期见闻').split('/')[0].trim() || '近期见闻') },
      条目 && 条目.事件名 ? { label: '事件', value: htmlEscape(toText(条目.事件名, '')) } : null,
      触发tick > 0 ? { label: '发生时间', value: htmlEscape(formatTickToCalendarDateText(触发tick)) } : null,
      条目 && 条目.状态 ? { label: '状态', value: htmlEscape(toText(条目.状态, '')) } : null,
      条目 && 条目.影响 ? { label: '影响', value: htmlEscape(toText(条目.影响, '')) } : null,
      条目 && 条目.后续 ? { label: '后续', value: htmlEscape(toText(条目.后续, '')) } : null,
    ].filter(Boolean);
    return {
      title: toText(条目 && 条目.title, '近期见闻'),
      summary: '',
      body: `
          <div class="archive-modal-grid mvu-detail-grid--single">
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">见闻详情</div></div>
              ${makeTimelineStack([
                {
                  title: htmlEscape(toText(条目 && 条目.title, '近期见闻')),
                  desc: '',
                  descLines: [
                    toText(条目 && 条目.事件, '').trim() || toText(条目 && 条目.desc, '暂无见闻'),
                    条目 && 条目.影响 ? `影响：${toText(条目.影响, '')}` : '',
                    条目 && 条目.后续 ? `后续：${toText(条目.后续, '')}` : '',
                  ],
                },
              ])}
            </div>
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">节点信息</div></div>
              ${makeTileGrid(信息项.length ? 信息项 : [{ label: '状态', value: '暂无记录' }], 'two')}
            </div>
          </div>
        `,
    };
  }

  function 构建全息编年史详情(snapshot) {
    const 近期安排摘要 = buildRecentPlanSummary(snapshot, { worldLimit: 12, recordLimit: 8 });
    const 近期见闻摘要 = buildRecentNewsSummary(snapshot, { seqLimit: 12, intelLimit: 8 });
    const 拍卖状态 = resolveShellText(deepGet(snapshot, 'rootData.world.拍卖.状态', ''), '休市');
    const 拍卖地点 = resolveShellText(deepGet(snapshot, 'rootData.world.拍卖.地点', ''), '');
    const 拍卖刷新tick = toNumber(deepGet(snapshot, 'rootData.world.拍卖.下次刷新tick', 0), 0);
    const 拍品条目 = safeEntries(deepGet(snapshot, 'rootData.world.拍卖.拍品', {}));
    const 生态警报文本 = resolveShellText(snapshot.worldAlert, '平稳');
    const 安排条目 = (近期安排摘要.worldPlans || []).concat(近期安排摘要.personalPlans || []);
    const 见闻条目 = (近期见闻摘要.globalNews || []).concat(近期见闻摘要.personalNews || []);
    const 编年史条目 = 构建世界编年史条目(snapshot || {});
    return {
      title: '全息编年史',
      summary: '',
      body: `
          <div class="archive-modal-grid mvu-detail-grid--single">
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">统一时间轴</div></div>
              <div class="mvu-detail-scroll-list">${makeTimelineStack(编年史条目)}</div>
            </div>
            <div class="archive-card full">
              <div class="archive-card-head"><div class="archive-card-title">拍卖与生态</div></div>
              ${makeTileGrid(
                [
                  { label: '拍卖状态', value: htmlEscape(拍卖状态) },
                  { label: '拍卖地点', value: htmlEscape(拍卖地点 || '无') },
                  {
                    label: '刷新时间',
                    value: htmlEscape(拍卖刷新tick > 0 ? formatTickToCalendarDateText(拍卖刷新tick) : '未记录'),
                  },
                  { label: '拍品数量', value: htmlEscape(`${拍品条目.length} 件`) },
                  { label: '生态警报', value: htmlEscape(生态警报文本) },
                ],
                'two',
              )}
            </div>
            ${
              拍品条目.length
                ? `
              <div class="archive-card full mvu-detail-scroll-card">
                <div class="archive-card-head"><div class="archive-card-title">拍品清单</div></div>
                <div class="mvu-detail-scroll-list">${makeTimelineStack(
                  拍品条目.slice(0, 8).map(([名称, 数据]) => ({
                    title: htmlEscape(名称),
                    desc: htmlEscape(
                      [
                        toText(deepGet(数据, '类型', ''), '').trim(),
                        toText(deepGet(数据, '品阶', deepGet(数据, '阶位', '')), '').trim(),
                        toText(deepGet(数据, '描述', ''), '').trim(),
                      ]
                        .filter(Boolean)
                        .join(' ｜ ') || '暂无拍品说明',
                    ),
                  })),
                )}</div>
              </div>
            `
                : ''
            }
          </div>
        `,
    };
  }

  function buildShellOrgHeroCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '势力',
        title: '阵营待同步',
        value: '待同步',
        meta: '当前聊天',
        rows: [
          { label: '阵营', value: '--' },
          { label: '身份', value: '--' },
        ],
      });
    }
    const primaryFactionEntry = getPrimaryFactionEntry(snapshot);
    const factionStats = getPrimaryFactionPowerStats(snapshot);
    const localFaction = toText(
      deepGet(snapshot, 'locationData.掌控势力', primaryFactionEntry.name || '未知'),
      primaryFactionEntry.name || '未知',
    );
    return buildShellSummaryCard({
      kicker: '势力',
      title: shortenText(primaryFactionEntry.name || '势力矩阵', 14),
      value: `${(snapshot.orgEntries || []).length || 0} 个焦点`,
      meta: `本地 ${shortenText(localFaction, 12)}`,
      badges: [
        snapshot.势力[0] ? { text: shortenText(snapshot.势力[0][0], 10), tone: 'gold' } : '',
        buildFactionRelationSummary(primaryFactionEntry.data || {}, 2),
      ],
      metrics: [
        { label: '极限', value: String(factionStats.limit || 0), tone: 'gold' },
        { label: '超级', value: String(factionStats.super || 0) },
        { label: '封号', value: String(factionStats.title || 0), tone: 'live' },
        { label: '焦点', value: String((snapshot.orgEntries || []).length || 0) },
      ],
      note: shortenText(buildFactionRelationSummary(primaryFactionEntry.data || {}, 3) || '暂无势力关系', 34),
      tone: 'hero',
      size: 'hero',
    });
  }

  function buildShellOrgFactionCard(snapshot) {
    const primaryFaction = snapshot.势力[0] || null;
    const primaryFactionEntry = getPrimaryFactionEntry(snapshot);
    const factionName = primaryFaction ? primaryFaction[0] : primaryFactionEntry.name;
    const factionData = primaryFaction ? primaryFaction[1] : primaryFactionEntry.data;
    return buildShellSummaryCard({
      kicker: '我的阵营权限',
      title: shortenText(toText(factionName, '未加入'), 14),
      value: shortenText(toText(deepGet(factionData, '身份', '未加入'), '未加入'), 10),
      meta: shortenText(toText(deepGet(factionData, '状态', '正常'), '正常'), 18),
      rows: [
        { label: '影响力', value: formatNumber(deepGet(factionData, '影响力', 0)) },
        {
          label: '关系',
          value: shortenText(buildFactionRelationSummary(primaryFactionEntry.data || {}, 2) || '暂无', 16),
        },
      ],
    });
  }

  function buildShellOrgNodeCard(snapshot) {
    return buildShellSummaryCard({
      kicker: '本地据点',
      title: buildShellLocationLabel(snapshot, { fullLimit: 14, trailLimit: 7 }),
      value: shortenText(toText(deepGet(snapshot, 'locationData.掌控势力', '未知'), '未知'), 12),
      meta: `${shortenText(toText(deepGet(snapshot, 'locationData.经济状况', '未知'), '未知'), 8)} · ${shortenText(toText(deepGet(snapshot, 'locationData.守护军团', '未知'), '未知'), 8)}`,
      rows: [
        { label: '店铺', value: String((snapshot.storeNames || []).length || 0) },
        { label: '动态点', value: String((snapshot.dynamicLocationNames || []).length || 0) },
      ],
    });
  }

  function buildShellTerminalHeroCard(snapshot) {
    if (!snapshot) {
      return buildShellSummaryCard({
        kicker: '终端',
        title: '系统待同步',
        value: '待同步',
        meta: '当前聊天',
        rows: [
          { label: '情报', value: '--' },
          { label: '任务', value: '--' },
          { label: '收录', value: '--' },
        ],
      });
    }
    const sys = deepGet(snapshot, 'rootData.sys', {});
    const recentNews = buildRecentNewsSummary(snapshot, { seqLimit: 2, intelLimit: 2 });
    const worldAlertText = resolveShellText(snapshot.worldAlert, '');
    const intelCount = (snapshot.unlockedKnowledges || []).length || 0;
    return buildShellSummaryCard({
      kicker: '终端',
      title: '终端',
      value: intelCount
        ? `${intelCount} 情报`
        : snapshot.questRecordCount
          ? `${snapshot.questRecordCount} 任务`
          : '在线',
      meta: shortenText(resolveShellText(sys.系统播报, '待命中') || '待命中', 26),
      badges: [
        worldAlertText ? { text: shortenText(worldAlertText, 10), tone: 'warn' } : '',
        intelCount ? { text: `已录 ${intelCount}`, tone: 'gold' } : snapshot.questRecordCount ? '任务待跟进' : '待命中',
      ],
      metrics: [
        { label: '情报', value: String(intelCount), tone: 'gold' },
        { label: '任务', value: String(snapshot.questRecordCount || 0), tone: 'live' },
        { label: '收录', value: String((snapshot.bestiaryEntries || []).length || 0) },
      ],
      note: shortenText(resolveShellText((snapshot.pendingRequests || [])[0], '待命中'), 34),
      tone: 'hero',
      size: 'hero',
    });
  }

  function buildShellTerminalIntelCard(snapshot) {
    if (!(snapshot.unlockedKnowledges || []).length && !(snapshot.pendingRequests || []).length) {
      return buildShellSummaryCard({
        title: '情报',
        value: '0',
        meta: '公开情报',
        note: '暂无公开情报',
      });
    }
    const latestIntelText = getLatestUnlockedIntelText(snapshot, 12, '暂无情报');
    const pendingRequestText = resolveShellText((snapshot.pendingRequests || [])[0], '');
    return buildShellSummaryCard({
      kicker: '情报',
      title: '情报',
      value: (snapshot.unlockedKnowledges || []).length
        ? `${(snapshot.unlockedKnowledges || []).length} 已录`
        : '待命中',
      meta: '公开情报',
      note: shortenText(pendingRequestText || latestIntelText || '暂无公开情报', 24),
    });
  }

  function buildShellTerminalNewsCard(snapshot) {
    const newsSummary = buildRecentNewsSummary(snapshot, { seqLimit: 1, intelLimit: 1 });
    if (!(newsSummary.cards || []).length) {
      return buildShellSummaryCard({
        title: '见闻',
        value: '0',
        meta: '无见闻',
      });
    }
    const globalNews = resolveShellText(((newsSummary.globalNews || [])[0] || {}).desc, '');
    const personalNews = resolveShellText(((newsSummary.personalNews || [])[0] || {}).desc, '');
    const summaryText = resolveShellText(newsSummary.summary, '等待新见闻');
    return buildShellSummaryCard({
      kicker: '播报',
      title: '播报',
      value: `${(newsSummary.cards || []).length || 0} 条`,
      meta: shortenText(globalNews || personalNews || summaryText || '等待新见闻', 20),
      note: globalNews && personalNews ? shortenText(personalNews, 24) : '',
    });
  }

  function buildShellTerminalBestiaryCard(snapshot) {
    const bestiaryNames = (snapshot.bestiaryEntries || []).map(([name]) => name).filter(Boolean);
    if (!bestiaryNames.length) {
      return buildShellSummaryCard({
        title: '图鉴',
        value: '0',
        meta: '暂无收录',
        note: '等待标准模板',
      });
    }
    return buildShellSummaryCard({
      kicker: '收录',
      title: '收录',
      value: bestiaryNames.length ? `${bestiaryNames.length} 种` : '待收录',
      meta: shortenText(
        `${toText(snapshot && snapshot.图鉴聚焦名称, bestiaryNames[0] || '暂无')} · ${toText(snapshot && snapshot.图鉴聚焦类型, '怪物')}`,
        20,
      ),
      note: shortenText(
        `${toText(snapshot && snapshot.图鉴聚焦规格, '--')} · 技能 ${toText(snapshot && snapshot.图鉴标准技能数, 0)} 项`,
        24,
      ),
    });
  }

  function buildShellTerminalQuestCard(snapshot) {
    const questBoardEntries = safeEntries(deepGet(snapshot, 'rootData.world.委托板', {})).filter(
      ([, item]) => item && typeof item === 'object',
    );
    const pendingRequestText = resolveShellText((snapshot.pendingRequests || [])[0], '');
    if (!snapshot.questRecordCount && !questBoardEntries.length && !pendingRequestText) {
      return buildShellSummaryCard({
        title: '任务',
        value: '0',
        meta: `进度 ${toText(snapshot && snapshot.当前任务进度, '--')}`,
        note: toText(snapshot && snapshot.当前任务名称, '暂无任务'),
      });
    }
    return buildShellSummaryCard({
      kicker: '任务',
      title: '任务',
      value: snapshot.questRecordCount ? `${snapshot.questRecordCount} 项` : '待命中',
      meta: `进度 ${toText(snapshot && snapshot.当前任务进度, '--')}`,
      note: shortenText(toText(snapshot && snapshot.当前任务名称, '') || pendingRequestText, 24),
    });
  }

  function buildShellCurrentAreaView(snapshot) {
    const currentMapDisplayName = getMapDisplayName(snapshot);
    const currentLoc = toText(deepGet(snapshot, 'activeChar.状态.位置', snapshot.currentLoc), snapshot.currentLoc);
    const localFaction = toText(deepGet(snapshot, 'locationData.掌控势力', '未知'), '未知');
    const nodeStores = safeEntries(deepGet(snapshot, 'locationData.商店', {}));
    const localEntries = getShellLocalCharacterEntries(snapshot, 8);
    const localCards = buildShellLocalRosterRows(localEntries, 8);
    return {
      title: '当前地区',
      body: `
          <div class="mvu-shell-lite-root" data-shell-light-view="area">
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">本地角色</div>
              <div class="mvu-shell-roster-list">${localCards}</div>
            </section>
            <section class="mvu-shell-lite-card mvu-shell-lite-card--hero">
              <div class="mvu-shell-lite-head">
                <span>${htmlEscape(shortenText(currentMapDisplayName, 18))}</span>
                <strong>${htmlEscape(shortenText(currentLoc, 28))}</strong>
              </div>
              <div class="mvu-shell-lite-grid">
                <div class="mvu-shell-lite-stat"><span>掌控</span><b>${htmlEscape(shortenText(localFaction, 14))}</b></div>
                <div class="mvu-shell-lite-stat"><span>角色</span><b>${htmlEscape(String(localEntries.length))}</b></div>
                <div class="mvu-shell-lite-stat"><span>商店</span><b>${htmlEscape(String(nodeStores.length))}</b></div>
              </div>
            </section>
          </div>
        `,
    };
  }

  function buildShellQuestOverviewView(snapshot) {
    const questRecords = (snapshot.recordEntries || []).filter(
      ([, item]) =>
        item &&
        typeof item === 'object' &&
        (Object.prototype.hasOwnProperty.call(item, '状态') ||
          Object.prototype.hasOwnProperty.call(item, '当前进度') ||
          Object.prototype.hasOwnProperty.call(item, '奖励币') ||
          Object.prototype.hasOwnProperty.call(item, '奖励声望')),
    );
    const questBoardEntries = safeEntries(deepGet(snapshot, 'rootData.world.委托板', {})).filter(
      ([, item]) => item && typeof item === 'object',
    );
    const renderQuest = ([name, item]) => {
      const status = toText(item && item['状态'], '进行中');
      const current = Math.max(0, Math.min(100, toNumber(item && item['当前进度'], 0)));
      const desc = toText(item && item['描述'], '暂无说明');
      return `
          <div class="mvu-shell-lite-item">
            <b>${htmlEscape(shortenText(name, 18))}</b>
            <span>${htmlEscape(status)} · ${htmlEscape(`${current}%`)}</span>
            <div class="mvu-shell-lite-track"><i style="width:${ratioPercent(current, 100)}%;"></i></div>
            <em>${htmlEscape(shortenText(desc, 28))}</em>
          </div>
        `;
    };
    const renderBoard = ([id, item]) => {
      const title = toText(item && item['标题'], id);
      const status = toText(item && item['状态'], '待接取');
      const publisher = toText(item && item['发布者'], '系统');
      return `
          <div class="mvu-shell-lite-item">
            <b>${htmlEscape(shortenText(title, 18))}</b>
            <span>${htmlEscape(status)} · ${htmlEscape(shortenText(publisher, 12))}</span>
          </div>
        `;
    };
    const questList = questRecords.length
      ? questRecords.slice(0, 5).map(renderQuest).join('')
      : '<div class="mvu-shell-lite-empty">暂无任务</div>';
    const boardList = questBoardEntries.length
      ? questBoardEntries.slice(0, 4).map(renderBoard).join('')
      : '<div class="mvu-shell-lite-empty">暂无委托</div>';
    return {
      title: '任务',
      body: `
          <div class="mvu-shell-lite-root" data-shell-light-view="quest">
            <section class="mvu-shell-lite-card mvu-shell-lite-card--hero">
              <div class="mvu-shell-lite-head">
                <span>任务</span>
                <strong>${htmlEscape(questRecords[0] ? questRecords[0][0] : '暂无进行中任务')}</strong>
              </div>
              <div class="mvu-shell-lite-grid">
                <div class="mvu-shell-lite-stat"><span>任务</span><b>${htmlEscape(String(questRecords.length))}</b></div>
                <div class="mvu-shell-lite-stat"><span>委托</span><b>${htmlEscape(String(questBoardEntries.length))}</b></div>
                <div class="mvu-shell-lite-stat"><span>待办</span><b>${htmlEscape(String((snapshot.pendingRequests || []).length || 0))}</b></div>
              </div>
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">我的任务</div>
              <div class="mvu-shell-lite-list">${questList}</div>
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">委托板</div>
              <div class="mvu-shell-lite-list">${boardList}</div>
            </section>
          </div>
        `,
    };
  }

  function buildShellLiteStats(items = [], options = {}) {
    const className = toText(options.className, '').trim();
    const list = (Array.isArray(items) ? items : [])
      .map(item => ({
        label: toText(item && item.label, '').trim(),
        value: toText(item && item.value, '').trim(),
        值Html: item && item.值Html ? String(item.值Html) : '',
        提示文本: toText(item && item.提示文本, '').trim(),
      }))
      .filter(item => item.label || item.value || item.值Html);
    if (!list.length) return '';
    return `
        <div class="mvu-shell-lite-grid ${htmlEscape(className)}">
          ${list
            .map(
              item => `
            <div class="mvu-shell-lite-stat">
              <span>${htmlEscape(item.label)}</span>
              <b${item.提示文本 ? ` title="${escapeHtmlAttr(item.提示文本)}"` : ''}>${item.值Html || htmlEscape(item.value)}</b>
            </div>
          `,
            )
            .join('')}
        </div>
      `;
  }

  function buildShellLiteTags(items = []) {
    const list = (Array.isArray(items) ? items : [])
      .map(item => toText(item, '').trim())
      .filter(Boolean)
      .slice(0, 5);
    if (!list.length) return '';
    return `<div class="mvu-shell-lite-tags">${list.map(item => `<span>${htmlEscape(shortenText(item, 16))}</span>`).join('')}</div>`;
  }

  function buildShellLiteItemList(items = [], fallback = '暂无记录') {
    const list = (Array.isArray(items) ? items : []).filter(item => item && (item.title || item.meta || item.note));
    if (!list.length) return `<div class="mvu-shell-lite-empty">${htmlEscape(fallback)}</div>`;
    return list
      .map(
        item => {
          const 悬浮Html = item && item.悬浮Html ? toText(item.悬浮Html, '') : '';
          return `
        <div class="mvu-shell-lite-item${悬浮Html ? ' mvu-shell-lite-item--has-hover' : ''}"${悬浮Html ? ' tabindex="0"' : ''}>
          <b>${htmlEscape(shortenText(item.title || '未命名', 22))}</b>
          ${item.meta ? `<span>${htmlEscape(shortenText(item.meta, 30))}</span>` : ''}
          ${item.note ? `<em>${htmlEscape(shortenText(item.note, 34))}</em>` : ''}
          ${悬浮Html}
        </div>
      `;
        },
      )
      .join('');
  }

  function buildShellLifeView(snapshot) {
    const stat = deepGet(snapshot, 'activeChar.属性', {});
    const status = deepGet(snapshot, 'activeChar.状态', {});
    const social = deepGet(snapshot, 'activeChar.社交', {});
    const hpPair = getDisplayHpPair(stat);
    const woundLabel = getDisplayWoundLabel(stat);
    const placeText = buildShellLocationLabel(snapshot, { fullLimit: 24, trailLimit: 10 });
    return {
      title: '详细档案',
      body: `
          <div class="mvu-shell-lite-root" data-shell-light-view="life">
            <section class="mvu-shell-lite-card mvu-shell-lite-card--hero">
              <div class="mvu-shell-lite-head">
                <span>${htmlEscape(placeText || '当前位置')}</span>
                <strong>${htmlEscape(toText(snapshot && snapshot.activeName, '当前角色'))}</strong>
              </div>
              ${buildShellLiteStats(
                [
                  { label: '年龄 / 性别', value: `${toText(stat.年龄, '--')} / ${toText(stat.性别, '未知')}` },
                  { label: '修为等级', value: formatCultivationLevelBadge(stat.等级, '0') },
                  构建属性指标项('HP', hpPair.hp, hpPair.hpMax),
                  构建属性指标项('体力', stat.体力, stat.体力上限),
                  构建属性指标项('魂力', stat.魂力, stat.魂力上限),
                  构建属性指标项('精神', stat.精神力, stat.精神力上限),
                  { label: '状态', value: shortenText(toText(status.行动, '日常'), 16) },
                  { label: '伤势', value: woundLabel },
                ],
                { className: 'mvu-shell-lite-grid--two' },
              )}
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">属性</div>
              ${buildShellLiteStats(
                [
                  {
                    label: '力量',
                    value: 格式化属性短数字(stat.力量),
                    值Html: 构建属性数值Html('力量', stat.力量),
                    提示文本: `力量：${格式化属性完整数字(stat.力量)}`,
                  },
                  {
                    label: '防御',
                    value: 格式化属性短数字(stat.防御),
                    值Html: 构建属性数值Html('防御', stat.防御),
                    提示文本: `防御：${格式化属性完整数字(stat.防御)}`,
                  },
                  {
                    label: '敏捷',
                    value: 格式化属性短数字(stat.敏捷),
                    值Html: 构建属性数值Html('敏捷', stat.敏捷),
                    提示文本: `敏捷：${格式化属性完整数字(stat.敏捷)}`,
                  },
                  { label: '精神境界', value: 读取显示精神境界(stat) },
                ],
                { className: 'mvu-shell-lite-grid--two' },
              )}
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">摘要</div>
              <div class="mvu-shell-lite-list">${buildShellLiteItemList(
                [
                  {
                    title: '身份',
                    meta: summarizeShellIdentityText(social.主身份, { limit: 22 }) || toText(social.主身份, '未记录'),
                  },
                  {
                    title: '阵营',
                    meta: snapshot.primaryFaction
                      ? `${snapshot.primaryFaction[0]} / ${toText(deepGet(snapshot.primaryFaction[1], '身份', '成员'), '成员')}`
                      : '未加入',
                  },
                  {
                    title: '名望',
                    meta: `${toText(social.名望等级, toText(social.名望等级, '籍籍无名'))} · ${formatNumber(social.声望)}`,
                  },
                ],
                '暂无摘要',
              )}</div>
            </section>
          </div>
        `,
    };
  }

  function buildShellArmoryView(snapshot) {
    const armor = deepGet(snapshot, 'activeChar.装备.斗铠', {});
    const mech = deepGet(snapshot, 'activeChar.装备.机甲', {});
    const weapon = deepGet(snapshot, 'activeChar.装备.武器', {});
    const jobs = safeEntries(deepGet(snapshot, 'activeChar.职业', {}));
    const soulBoneEntries = Array.isArray(snapshot && snapshot.soulBoneEntries) ? snapshot.soulBoneEntries : [];
    const armorText = toNumber(armor.等级, 0) > 0 ? toText(armor.名称, `${armor.等级}字斗铠`) : '无';
    const mechText =
      toText(mech.等级, '') && toText(mech.等级, '无') !== '无'
        ? `${toText(mech.名称 || mech['名称'], `${toText(mech.等级, '无')}机甲`)} · ${toText(mech.型号, '均衡')}`
        : '无';
    const weaponText = toText(weapon.名称 || weapon['名称'], '无');
    const jobItems = jobs.slice(0, 4).map(([name, info]) => {
      const 副职业 = 派生副职业显示数据(name, info);
      return {
        title: name,
        meta: `Lv.${副职业.等级} · ${toText(副职业.称号, '未定级')}`,
        note: `${副职业.核心技艺} / ${副职业.支持融锻数}`,
      };
    });
    return {
      title: '武装',
      body: `
          <div class="mvu-shell-lite-root" data-shell-light-view="armory">
            <section class="mvu-shell-lite-card mvu-shell-lite-card--hero">
              <div class="mvu-shell-lite-head">
                <span>${htmlEscape(shortenText(weaponText, 18))}</span>
                <strong>${htmlEscape(shortenText(armorText, 24))}</strong>
              </div>
              ${buildShellLiteStats([
                { label: '机甲', value: shortenText(mechText, 10) },
                { label: '魂骨', value: String(soulBoneEntries.length || 0) },
              ])}
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">副职</div>
              <div class="mvu-shell-lite-list">${buildShellLiteItemList(jobItems, '暂无副职')}</div>
            </section>
          </div>
        `,
    };
  }

  function buildShellSpiritView(snapshot, previewKey) {
    const config =
      previewKey === '第2武魂详细页' ? snapshot && snapshot.secondaryTrack : snapshot && snapshot.primarySpirit;
    if (!config) {
      return {
        title: '武魂',
        body: `<div class="mvu-shell-lite-root"><section class="mvu-shell-lite-card"><div class="mvu-shell-lite-empty">暂无武魂</div></section></div>`,
      };
    }
    const souls = Array.isArray(config.souls) ? config.souls : [];
    const rings = Array.isArray(config.魂环) ? config.魂环 : [];
    const skillItems = rings
      .flatMap(ring =>
        (Array.isArray(ring.skills) ? ring.skills : []).map(skill => ({
          title: toText(skill && skill.name, '魂技'),
          meta: shortenText(toText(ring && ring.title, '魂环'), 24),
          note: shortenText(toText(skill && skill.effectSummary, toText(skill && skill.effectDesc, '')), 30),
          悬浮Html: 构建技能悬浮卡片(skill, toText(ring && ring.title, '魂环')),
        })),
      )
      .slice(0, 5);
    return {
      title: '武魂',
      body: `
          <div class="mvu-shell-lite-root" data-shell-light-view="spirit">
            <section class="mvu-shell-lite-card mvu-shell-lite-card--hero">
              <div class="mvu-shell-lite-head">
                <span>${htmlEscape(shortenText(toText(config.spiritType, config.badge), 16))}</span>
                <strong>${htmlEscape(shortenText(toText(config.spiritName || config.name, '武魂'), 22))}</strong>
              </div>
              ${buildShellLiteStats([
                { label: '魂灵', value: String(souls.length || 0) },
                { label: '魂环', value: String(rings.length || 0) },
                { label: '属性', value: shortenText(toText(config.spiritElement, '无'), 8) },
              ])}
            </section>
            <section class="mvu-shell-lite-card">
              <div class="mvu-shell-lite-section-title">魂技</div>
              <div class="mvu-shell-lite-list">${buildShellLiteItemList(skillItems, '暂无魂技')}</div>
            </section>
          </div>
        `,
    };
  }

