  function getBattleInlineHost() {
    const host = document.getElementById('mvu-battle-inline-host');
    return host instanceof Element && host.isConnected ? host : null;
  }

  const 召唤夹具名称列表 = Object.freeze([
    '召唤:生成入表',
    '召唤:受击治疗护盾状态',
    '召唤:群体护卫协同自主',
    '召唤:收回死亡精神',
    '召唤:目标池与单体收回',
    '召唤:分身目标隔离',
    '召唤:批量编号重复召唤',
    '召唤:UI预览',
  ]);

  function 构建召唤夹具战斗数据() {
    const 生成单位 = 名称 => ({
      name: 名称,
      type: '强攻系',
      lv: 45,
      hp: 1200,
      hp_max: 1200,
      HP: 1200,
      HP上限: 1200,
      体力: 900,
      体力上限: 900,
      sp: 800,
      sp_max: 800,
      men: 600,
      men_max: 600,
      str: 180,
      def: 120,
      agi: 110,
      状态效果: {},
      持续效果: {},
    });
    const 宿主 = 生成单位('召唤夹具宿主');
    const 敌人 = 生成单位('召唤夹具敌人');
    宿主.状态效果['召唤:预览召唤物'] = {
      类型: 'buff',
      层数: 1,
      duration: 3,
      战斗效果: {},
      召唤物: {
        召唤单位类型: '魂兽',
        召唤物名称: '预览召唤物',
        召唤数量: 1,
        行动模式: '自主行动',
        强度: 1,
      },
    };
    return {
      进行中: true,
      回合: 1,
      战斗类型: '召唤夹具',
      阶段: '宣告阶段',
      参战者: { team_player: [宿主], team_enemy: [敌人] },
    };
  }

  async function 挂载临时召唤夹具战斗UI() {
    const 模块加载结果 = await 确保模块依赖已加载('战斗模块', 'summon_fixture');
    if (!模块加载结果 || 模块加载结果.ok === false || typeof window.mountBattleUI !== 'function') {
      throw new Error('战斗模块未就绪');
    }
    const 原战斗UI = window.BattleUI;
    const 容器 = document.createElement('div');
    容器.setAttribute('data-lwcs-summon-fixture-host', '1');
    容器.style.cssText = 'position:fixed;left:-9999px;top:0;width:720px;z-index:-1;pointer-events:none;';
    容器.innerHTML = buildBattleInlineHostMarkup();
    document.body.appendChild(容器);
    const 战斗数据 = 构建召唤夹具战斗数据();
    const 组件 = window.mountBattleUI(容器, {}, { combatData: 战斗数据 });
    await new Promise(resolve => window.setTimeout(resolve, 40));
    return {
      容器,
      组件,
      战斗数据,
      清理() {
        try {
          if (组件 && typeof 组件.destroy === 'function') 组件.destroy();
        } catch (错误) {}
        容器.remove();
        if (原战斗UI !== undefined) window.BattleUI = 原战斗UI;
        else delete window.BattleUI;
      },
    };
  }

  function 归一化召唤夹具名称(名称 = '') {
    return String(名称 || '').replace(/^召唤[:：]/, '').trim();
  }

  function 包装召唤夹具结果(名称, 执行函数) {
    const 日志 = [];
    try {
      const 结果 = 执行函数(日志);
      return { ok: true, name: 名称, logs: 日志, result: 结果 || null };
    } catch (错误) {
      return { ok: false, name: 名称, logs: 日志, failedAt: String(错误?.message || 错误 || '未知失败') };
    }
  }

  async function 运行召唤聚合夹具(名称 = '') {
    const 夹具名 = 归一化召唤夹具名称(名称);
    if (夹具名 === 'UI预览') {
      const 临时 = await 挂载临时召唤夹具战斗UI();
      try {
        return 包装召唤夹具结果('召唤:UI预览', 日志 => {
          const 队列 = 临时.容器.querySelector('#ui-summon-queue');
          const 卡片 = 临时.容器.querySelector('.summon-card');
          const 按钮 = 临时.容器.querySelector('.summon-recall-btn');
          if (!队列 || 队列.hidden) throw new Error('UI队列未显示');
          if (!卡片) throw new Error('召唤卡片未渲染');
          if (!按钮) throw new Error('单体收回按钮缺失');
          按钮.click();
          const 动作 = window.BattleUI?.state?.selectedAction || {};
          if (动作.action_type !== '收回召唤' || !String(动作.target_name || '').trim()) throw new Error('收回动作未携带召唤键');
          日志.push('UI队列、卡片和单体收回动作已验证');
          return { summonQueue: true, recallTarget: 动作.target_name };
        });
      } finally {
        临时.清理();
      }
    }
    const 临时 = await 挂载临时召唤夹具战斗UI();
    try {
      if (typeof window.__LWCS_RUN_SUMMON_FIXTURE_BATCH__ !== 'function') {
        throw new Error('召唤夹具运行器未挂载');
      }
      const 运行结果 = window.__LWCS_RUN_SUMMON_FIXTURE_BATCH__(夹具名);
      return 包装召唤夹具结果(名称 || '召唤:批量', 日志 => {
        (运行结果?.results || []).forEach(item => 日志.push(`${item?.name || '召唤夹具'}:${item?.ok ? 'ok' : item?.failedAt || 'fail'}`));
        if (!运行结果 || 运行结果.ok !== true) throw new Error(`召唤夹具返回失败:${日志.join(';') || '无明细'}`);
        return 运行结果;
      });
    } finally {
      临时.清理();
    }
  }

  function 注册召唤夹具聚合入口() {
    if (window.__LWCS_SUMMON_FIXTURE_AGGREGATED__) return;
    const 原列表函数 = typeof window.__LWCS_LIST_SKILL_FIXTURES__ === 'function'
      ? window.__LWCS_LIST_SKILL_FIXTURES__.bind(window)
      : null;
    const 原运行函数 = typeof window.__LWCS_RUN_SKILL_FIXTURE_BATCH__ === 'function'
      ? window.__LWCS_RUN_SKILL_FIXTURE_BATCH__.bind(window)
      : null;
    window.__LWCS_LIST_SKILL_FIXTURES__ = () => {
      const 原列表 = 原列表函数 ? 原列表函数() : [];
      return Array.from(new Set([...(Array.isArray(原列表) ? 原列表 : []), ...召唤夹具名称列表]));
    };
    window.__LWCS_RUN_SKILL_FIXTURE_BATCH__ = async (名称 = '') => {
      const 文本 = String(名称 || '').trim();
      if (!文本) {
        const 结果列表 = [];
        if (原运行函数) 结果列表.push(await 原运行函数(''));
        for (const 召唤夹具名 of 召唤夹具名称列表) {
          结果列表.push(await 运行召唤聚合夹具(召唤夹具名));
        }
        return { ok: 结果列表.every(item => item?.ok !== false), results: 结果列表 };
      }
      if (/^召唤[:：]/.test(文本)) return 运行召唤聚合夹具(文本);
      return 原运行函数 ? 原运行函数(文本) : { ok: false, name: 文本, failedAt: '未找到夹具' };
    };
    window.__LWCS_SUMMON_FIXTURE_AGGREGATED__ = true;
  }

  注册召唤夹具聚合入口();

  function waitForBattleInlineHost(attempts = 12) {
    return new Promise(resolve => {
      const check = remaining => {
        const host = getBattleInlineHost();
        if (host || remaining <= 0) {
          resolve(host || null);
          return;
        }
        if (typeof window.requestAnimationFrame === 'function') {
          window.requestAnimationFrame(() => check(remaining - 1));
        } else {
          window.setTimeout(() => check(remaining - 1), 16);
        }
      };
      check(attempts);
    });
  }

  function isCombatActiveForBattleInline(snapshot) {
    const combatData = deepGet(snapshot, 'rootData.world.战斗', {});
    return !!(
      combatData &&
      typeof combatData === 'object' &&
      combatData.进行中 &&
      isSnapshotPlayerControlled(snapshot)
    );
  }

  function getBattleInlineSummary(snapshot) {
    const combatData = deepGet(snapshot, 'rootData.world.战斗', {});
    const player = toText(
      combatData && combatData.参战者 && combatData.参战者.team_player?.[0] && combatData.参战者.team_player[0].name,
      '己方',
    );
    const enemy = toText(
      combatData && combatData.参战者 && combatData.参战者.team_enemy?.[0] && combatData.参战者.team_enemy[0].name,
      '对手',
    );
    const round = toNumber(combatData && combatData.回合, 0);
    return {
      title: '战斗',
      meta: `${player} / ${enemy}`,
      roundText: `回合 ${round}`,
    };
  }

  function openBattleInlineFromReturnEntry() {
    battleInlineDismissed = false;
    removeBattleReturnEntries();
    openBattleInlineSurface().then(() => refreshLiveSnapshot({ force: true, reopenBattle: true }));
  }

  function removeBattleReturnEntries() {
    document.querySelectorAll('[data-mvu-battle-return="1"]').forEach(node => node.remove());
  }

  function ensureBattleReturnEntry(container, className, html) {
    if (!(container instanceof Element)) return;
    let entry = container.querySelector('[data-mvu-battle-return="1"]');
    if (!entry) {
      entry = document.createElement('button');
      entry.type = 'button';
      entry.setAttribute('data-mvu-battle-return', '1');
      container.appendChild(entry);
    }
    entry.className = className;
    entry.innerHTML = html;
    entry.onclick = event => {
      event.preventDefault();
      event.stopPropagation();
      openBattleInlineFromReturnEntry();
    };
  }

  function syncBattleReturnEntries(snapshot, isActive) {
    if (!isActive) {
      removeBattleReturnEntries();
      return;
    }
    const summary = getBattleInlineSummary(snapshot);
    const unifiedActionGrid = document.querySelector('#mvu-unified-mount .mvu-unified-action-grid');
    ensureBattleReturnEntry(
      unifiedActionGrid,
      'mvu-unified-action-btn mvu-unified-grid-btn mvu-battle-return-entry',
      `<span>${htmlEscape(summary.title)}</span><small>${htmlEscape(summary.meta)}</small>`,
    );
    const unifiedTabRow = document.querySelector('#mvu-unified-mount .mvu-unified-tab-row');
    ensureBattleReturnEntry(unifiedTabRow, 'mvu-tab-btn mvu-battle-return-tab', htmlEscape(summary.title));
  }

  function scheduleBattleReturnEntrySync(snapshot, isActive) {
    const token = ++battleReturnEntrySyncToken;
    const run = () => {
      if (token !== battleReturnEntrySyncToken) return;
      const latestSnapshot = liveSnapshot || lastRenderableSnapshot || snapshot;
      syncBattleReturnEntries(latestSnapshot, isActive && isCombatActiveForBattleInline(latestSnapshot));
    };
    if (typeof window.requestAnimationFrame === 'function') {
      window.requestAnimationFrame(run);
    }
    [80, 240, 520].forEach(delay => window.setTimeout(run, delay));
  }

  function openBattleInlineSurface() {
    const 当前宿主 = getBattleInlineHost();
    const 统一宿主 = getUnifiedInlineHost();
    if (
      当前宿主 &&
      统一宿主 &&
      toText(统一宿主.dataset.unifiedPreview, '').trim() === BATTLE_INLINE_PREVIEW_KEY
    ) {
      return Promise.resolve(当前宿主);
    }
    if (typeof window.__MVU_OPEN_UNIFIED_PREVIEW__ !== 'function') {
      return Promise.resolve(null);
    }
    window.__MVU_OPEN_UNIFIED_PREVIEW__(BATTLE_INLINE_PREVIEW_KEY, {
      preserveMapDispatchContext: true,
      replace: true,
    });
    return waitForBattleInlineHost();
  }

  const COMBAT_PARTICIPANT_STAT_KEYS = [
    '年龄',
    '等级',
    '天赋梯队',
    '邪魂师',
    'HP',
    'HP上限',
    '魂力',
    '魂力上限',
    '精神力',
    '精神力上限',
    '力量',
    '防御',
    '敏捷',
    '体力',
    '体力上限',
  ];

  function buildCombatParticipantFromSnapshotChar(snapshot, charKey, faction = '敌对') {
    const chars = deepGet(snapshot, 'rootData.char', {});
    const sourceChar = chars && typeof chars === 'object' ? chars[charKey] : null;
    if (!sourceChar || typeof sourceChar !== 'object') return null;
    const participant = cloneJsonValue(sourceChar, {});
    const stat = participant.属性 && typeof participant.属性 === 'object' ? participant.属性 : {};
    const status = participant.状态 && typeof participant.状态 === 'object' ? participant.状态 : {};
    participant.name = toText(participant.name || deepGet(participant, 'base.name', ''), charKey);
    participant.势力 = faction;
    participant.状态 = status;
    COMBAT_PARTICIPANT_STAT_KEYS.forEach(key => {
      if (stat[key] !== undefined) participant[key] = stat[key];
    });
    participant.等级 = toNumber(participant.等级, toNumber(stat.等级, 1));
    participant.系别 = toText(participant.系别, 取角色主武魂系别_桥接(participant, '未知系'));
    participant.HP上限 = Math.max(1, toNumber(participant.HP上限, toNumber(stat.HP上限, toNumber(stat.体力上限, 1))));
    participant.HP = Math.max(0, toNumber(participant.HP, toNumber(stat.HP, toNumber(stat.体力, participant.HP上限))));
    participant.体力上限 = Math.max(1, toNumber(participant.体力上限, toNumber(stat.体力上限, 1)));
    participant.体力 = Math.max(0, toNumber(participant.体力, toNumber(stat.体力, participant.体力上限)));
    participant.魂力上限 = Math.max(1, toNumber(participant.魂力上限, toNumber(stat.魂力上限, 1)));
    participant.魂力 = Math.max(0, toNumber(participant.魂力, toNumber(stat.魂力, participant.魂力上限)));
    participant.精神力上限 = Math.max(1, toNumber(participant.精神力上限, toNumber(stat.精神力上限, 1)));
    participant.精神力 = Math.max(0, toNumber(participant.精神力, toNumber(stat.精神力, participant.精神力上限)));
    participant.力量 = Math.max(0, toNumber(participant.力量, toNumber(stat.力量, 1)));
    participant.防御 = Math.max(0, toNumber(participant.防御, toNumber(stat.防御, 1)));
    participant.敏捷 = Math.max(0, toNumber(participant.敏捷, toNumber(stat.敏捷, 1)));
    participant.状态效果 = cloneJsonValue(participant.状态效果 || stat.状态效果 || {}, {});
    delete participant.持续效果;
    delete participant.蓄力技能;
    participant.存活 = status.存活 !== false;
    participant.状态.死亡tick = participant.存活 ? -1 : Math.max(-1, toNumber(status.死亡tick, -1));
    participant.状态.死亡类型 = participant.存活 ? '无' : toText(status.死亡类型, '意外');
    return participant;
  }

  function 读取角色间好感度(snapshot, leftKey = '', rightKey = '') {
    const chars = deepGet(snapshot, 'rootData.char', {});
    const left = chars && typeof chars === 'object' ? chars[leftKey] : null;
    const right = chars && typeof chars === 'object' ? chars[rightKey] : null;
    const rightNames = [rightKey, toText(right && right.name, ''), toText(deepGet(right, 'base.name', ''), '')].filter(
      Boolean,
    );
    const leftNames = [leftKey, toText(left && left.name, ''), toText(deepGet(left, 'base.name', ''), '')].filter(
      Boolean,
    );
    for (const name of rightNames) {
      const value = Number(deepGet(left, ['社交', '关系', name, '好感度'], NaN));
      if (Number.isFinite(value)) return value;
    }
    for (const name of leftNames) {
      const value = Number(deepGet(right, ['社交', '关系', name, '好感度'], NaN));
      if (Number.isFinite(value)) return value;
    }
    return 0;
  }

  function 允许已有参战者压制等级(snapshot, charKey = '') {
    const activeRaw =
      toText(snapshot && snapshot.activeName, '') || toText(deepGet(snapshot, 'rootData.sys.玩家名', ''), '');
    const activeKey = resolveSnapshotCharKey(snapshot, activeRaw);
    if (!activeKey || !charKey) return false;
    if (activeKey === charKey) return true;
    return 读取角色间好感度(snapshot, activeKey, charKey) >= 20;
  }

  function 应用已有参战者种子实力封顶(snapshot, charKey, 参战者, 种子 = {}) {
    if (!参战者 || typeof 参战者 !== 'object' || !种子 || typeof 种子 !== 'object') return 参战者;
    if (String(种子.单位性质 || '').trim() !== '人类') return 参战者;
    if (!允许已有参战者压制等级(snapshot, charKey)) return 参战者;
    const 限制等级 = Math.floor(Number(种子.等级));
    if (!Number.isFinite(限制等级) || 限制等级 <= 0) return 参战者;
    const 属性 = 参战者.属性 && typeof 参战者.属性 === 'object' ? 参战者.属性 : {};
    const 实际等级 = Math.floor(toNumber(参战者.等级, toNumber(属性.等级, 限制等级)));
    if (实际等级 <= 限制等级) return 参战者;
    const 限制基准 = getTemporaryBattleBaseStats(限制等级);
    参战者.实力压制 = {
      刻意压制等级: true,
      原始等级: 实际等级,
      压制等级: 限制等级,
      说明: `${toText(参战者.name || 参战者.名称, '参战者')}刻意将战斗实力压制到${限制等级}级`,
    };
    const 字段映射 = [
      ['HP上限', 'vit_max'],
      ['体力上限', 'vit_max'],
      ['魂力上限', 'sp_max'],
      ['精神力上限', 'men_max'],
      ['力量', 'str'],
      ['防御', 'def'],
      ['敏捷', 'agi'],
    ];
    参战者.等级 = 限制等级;
    属性.等级 = 限制等级;
    字段映射.forEach(([字段名, 基准名]) => {
      const 限制值 = Math.max(1, Math.floor(Number(限制基准[基准名] || 1)));
      const 当前值 = toNumber(参战者[字段名], toNumber(属性[字段名], 限制值));
      const 下限值 = Math.min(当前值, 限制值);
      参战者[字段名] = 下限值;
      属性[字段名] = 下限值;
    });
    [
      ['HP', 'HP上限'],
      ['体力', '体力上限'],
      ['魂力', '魂力上限'],
      ['精神力', '精神力上限'],
    ].forEach(([当前字段, 上限字段]) => {
      const 上限值 = Math.max(0, toNumber(参战者[上限字段], toNumber(属性[上限字段], 0)));
      const 当前值 = Math.max(0, toNumber(参战者[当前字段], toNumber(属性[当前字段], 上限值)));
      const 下限值 = Math.min(当前值, 上限值);
      参战者[当前字段] = 下限值;
      属性[当前字段] = 下限值;
    });
    参战者.属性 = 属性;
    return 参战者;
  }

  function normalizeBattleSeedParticipant(seed, fallbackName = '') {
    if (Array.isArray(seed)) {
      const firstValid = seed.find(item => item !== undefined && item !== null && item !== '');
      return firstValid === undefined ? null : normalizeBattleSeedParticipant(firstValid, fallbackName);
    }
    if (typeof seed === 'string' || typeof seed === 'number') {
      const normalizedName = toText(seed, fallbackName);
      return normalizedName ? { name: normalizedName } : null;
    }
    if (!seed || typeof seed !== 'object' || Array.isArray(seed)) return null;
    const normalized = cloneJsonValue(seed, {});
    const normalizedName = toText(normalized.name, fallbackName);
    if (!normalizedName) return null;
    normalized.name = normalizedName;
    return normalized;
  }

